{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track meals, calories, and nutrition with daily goals and weekly charts",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  category: FoodCategory;
};

export type Meal = {
  id: string;
  timestamp: string;
  name: string;
  items: FoodItem[];
  totalCalories: number;
};

export type DailyGoal = {
  calories: number;
  updatedAt: string;
};

export type MealsData = {
  meals: Meal[];
};

export type GoalData = {
  goal: DailyGoal;
};

export type DailySummary = {
  date: string;
  totalCalories: number;
  mealCount: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goalCalories: number;
  goalProgress: number;
};

export type WeeklyData = {
  days: {
    date: string;
    label: string;
    totalCalories: number;
  }[];
  goalCalories: number;
};

{
  "meals": []
}

import type { MealsData, GoalData } from './types';

const MEALS_PATH = 'data/meals.json';
const GOALS_PATH = 'data/goals.json';

export const loadMeals = async (): Promise<MealsData> => {
  try {
    return await Bun.file(MEALS_PATH).json() as MealsData;
  } catch {
    const empty: MealsData = { meals: [] };
    await Bun.write(MEALS_PATH, JSON.stringify(empty, null, 2));
    return empty;
  }
};

export const saveMeals = async (data: MealsData): Promise<void> => {
  await Bun.write(MEALS_PATH, JSON.stringify(data, null, 2));
};

export const loadGoal = async (): Promise<GoalData> => {
  try {
    return await Bun.file(GOALS_PATH).json() as GoalData;
  } catch {
    const defaultGoal: GoalData = {
      goal: { calories: 2000, updatedAt: new Date().toISOString() },
    };
    await Bun.write(GOALS_PATH, JSON.stringify(defaultGoal, null, 2));
    return defaultGoal;
  }
};

export const saveGoal = async (data: GoalData): Promise<void> => {
  await Bun.write(GOALS_PATH, JSON.stringify(data, null, 2));
};

import type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData } from './types';
import { loadMeals, saveMeals, loadGoal } from './storage';

const generateId = (): string => crypto.randomUUID();

const getDateString = (iso: string): string => iso.slice(0, 10);

const today = (): string => new Date().toISOString().slice(0, 10);

export const addMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const data = await loadMeals();
  const meal: Meal = {
    id: generateId(),
    timestamp: timestamp ?? new Date().toISOString(),
    name,
    items,
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
  };
  data.meals.push(meal);
  await saveMeals(data);
  return meal;
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const data = await loadMeals();
  const index = data.meals.findIndex((m) => m.id === id);
  if (index === -1) return false;
  data.meals.splice(index, 1);
  await saveMeals(data);
  return true;
};

export const getMealsForDate = async (date?: string): Promise<Meal[]> => {
  const targetDate = date ?? today();
  const data = await loadMeals();
  return data.meals
    .filter((m) => getDateString(m.timestamp) === targetDate)
    .sort((a, b) => a.timestamp.localeCompare(b.timestamp));
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? today();
  const meals = await getMealsForDate(targetDate);
  const goalData = await loadGoal();

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  let totalCalories = 0;
  for (const meal of meals) {
    totalCalories += meal.totalCalories;
    for (const item of meal.items) {
      categoryBreakdown[item.category] += item.calories;
    }
  }

  const goalCalories = goalData.goal.calories;
  const goalProgress = goalCalories > 0 ? Math.round((totalCalories / goalCalories) * 100) : 0;

  return {
    date: targetDate,
    totalCalories,
    mealCount: meals.length,
    categoryBreakdown,
    goalCalories,
    goalProgress,
  };
};

export const getWeeklyData = async (): Promise<WeeklyData> => {
  const data = await loadMeals();
  const goalData = await loadGoal();
  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const dayLabel = d.toLocaleDateString('en-US', { weekday: 'short' });

    const dayCalories = data.meals
      .filter((m) => getDateString(m.timestamp) === dateStr)
      .reduce((sum, m) => sum + m.totalCalories, 0);

    days.push({ date: dateStr, label: dayLabel, totalCalories: dayCalories });
  }

  return { days, goalCalories: goalData.goal.calories };
};

import type { DailyGoal } from './types';
import { loadGoal, saveGoal } from './storage';

export const getGoal = async (): Promise<DailyGoal> => {
  const data = await loadGoal();
  return data.goal;
};

export const setGoal = async (calories: number): Promise<DailyGoal> => {
  const goal: DailyGoal = {
    calories: Math.max(0, Math.round(calories)),
    updatedAt: new Date().toISOString(),
  };
  await saveGoal({ goal });
  return goal;
};

