export const renderDailySummary = (summary: DailySummary, meals: Meal[]) => {
  const progressPct = Math.min(summary.goalProgress, 100);
  const progressColor = summary.goalProgress > 100 ? '#F44336' : '#4CAF50';

  return h('div', { style: styles.container },
    h('div', { style: styles.flex },
      h('h1', { style: styles.header }, 'Diet Tracker'),
      h('div', { style: styles.nav },
        h('button', {
          style: styles.buttonSecondary,
          'p-trigger': 'navigate:weekly',
        }, 'Weekly Chart'),
        h('button', {
          style: styles.buttonSecondary,
          'p-trigger': 'navigate:settings',
        }, 'Goal'),
      ),
    ),

    // Daily stats card
    h('div', { style: styles.card },
      h('div', { style: styles.sectionTitle }, `Today \u2014 ${summary.date}`),
      h('div', { style: styles.statsRow },
        h('div', {},
          h('div', { style: styles.statValue }, String(summary.totalCalories)),
          h('div', { style: styles.statLabel }, `of ${summary.goalCalories} kcal goal`),
        ),
        h('div', {},
          h('div', { style: styles.statValue }, String(summary.mealCount)),
          h('div', { style: styles.statLabel }, 'meals logged'),
        ),
      ),
      h('div', { style: { marginTop: '12px' } },
        h('div', { style: { ...styles.flex, marginBottom: '4px' } },
          h('span', { style: { fontSize: '12px', color: '#666' } }, 'Progress'),
          h('span', { style: { fontSize: '12px', fontWeight: '600' } }, `${summary.goalProgress}%`),
        ),
        h('div', { style: styles.progressBarOuter },
          h('div', {
            style: {
              width: `${progressPct}%`,
              height: '100%',
              backgroundColor: progressColor,
              borderRadius: '6px',
              transition: 'width 0.3s ease',
            },
          }),
        ),
      ),
    ),

    // Category breakdown
    h('div', { style: styles.card },
      h('div', { style: styles.sectionTitle }, 'Category Breakdown'),
      h('div', { style: { display: 'flex', gap: '12px', flexWrap: 'wrap' } },
        ...(['protein', 'carbs', 'fat', 'fiber'] as FoodCategory[]).map((cat) =>
          h('div', { style: { display: 'flex', alignItems: 'center', gap: '6px' } },
            h('div', {
              style: {
