                height: '10px',
                borderRadius: '50%',
                backgroundColor: CATEGORY_COLORS[cat],
              },
            }),
            h('span', { style: { fontSize: '13px' } },
              `${CATEGORY_LABELS[cat]}: ${summary.categoryBreakdown[cat]} kcal`,
            ),
          ),
        ),
