        : h(Fragment, {},
            ...meals.map((meal) =>
              h('div', { style: styles.mealItem },
                h('div', { style: styles.flex },
                  h('div', {},
                    h('div', { style: styles.mealName }, meal.name),
                    h('div', { style: styles.mealTime },
                      new Date(meal.timestamp).toLocaleTimeString('en-US', {
                        hour: '2-digit',
                        minute: '2-digit',
