export const renderWeeklyChart = (weeklyData: WeeklyData) => {
  const maxCal = Math.max(
    weeklyData.goalCalories,
    ...weeklyData.days.map((d) => d.totalCalories),
    1,
  );
  const chartHeight = 150;

  return h('div', { style: styles.container },
    h('div', { style: styles.flex },
      h('h1', { style: styles.header }, 'Weekly Overview'),
      h('button', {
        style: styles.buttonSecondary,
        'p-trigger': 'navigate:daily',
      }, 'Back'),
    ),

    h('div', { style: styles.card },
      h('div', { style: styles.sectionTitle }, 'Calorie Intake \u2014 Last 7 Days'),

      // Chart with goal line
      h('div', { style: { position: 'relative', paddingTop: '8px' } },
        // Goal reference line
        h('div', {
          style: {
            position: 'absolute',
            top: `${8 + chartHeight - (weeklyData.goalCalories / maxCal) * chartHeight}px`,
            left: '0',
            right: '0',
            borderTop: '2px dashed #FF9800',
            zIndex: '1',
          },
        }),
        h('div', {
          style: {
            position: 'absolute',
            top: `${2 + chartHeight - (weeklyData.goalCalories / maxCal) * chartHeight}px`,
            right: '0',
            fontSize: '10px',
            color: '#FF9800',
            fontWeight: '600',
          },
        }, `Goal: ${weeklyData.goalCalories}`),

        // Bars
        h('div', { style: styles.chartContainer },
          ...weeklyData.days.map((day) => {
            const barHeight = maxCal > 0
              ? Math.max((day.totalCalories / maxCal) * chartHeight, day.totalCalories > 0 ? 4 : 0)
              : 0;
            const overGoal = day.totalCalories > weeklyData.goalCalories;

            return h('div', { style: styles.chartBar },
              h('div', { style: styles.chartValue },
                day.totalCalories > 0 ? String(day.totalCalories) : '',
              ),
              h('div', {
                style: {
                  width: '100%',
                  maxWidth: '40px',
                  height: `${barHeight}px`,
                  backgroundColor: overGoal ? '#F44336' : '#4CAF50',
                  borderRadius: '4px 4px 0 0',
                  transition: 'height 0.3s ease',
                },
              }),
              h('div', { style: styles.chartLabel }, day.label),
            );
          }),
        ),
      ),

      // Legend
      h('div', {
        style: { display: 'flex', gap: '16px', marginTop: '12px', fontSize: '12px', color: '#666' },
      },
        h('div', { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
          h('div', { style: { width: '12px', height: '12px', backgroundColor: '#4CAF50', borderRadius: '2px' } }),
          h('span', {}, 'Under goal'),
        ),
        h('div', { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
          h('div', { style: { width: '12px', height: '12px', backgroundColor: '#F44336', borderRadius: '2px' } }),
          h('span', {}, 'Over goal'),
        ),
        h('div', { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
          h('div', { style: { width: '12px', height: '2px', borderTop: '2px dashed #FF9800' } }),
          h('span', {}, 'Daily goal'),
        ),
      ),
    ),

    // Weekly total
    h('div', { style: styles.card },
      h('div', { style: styles.statsRow },
        h('div', {},
          h('div', { style: styles.statValue },
            String(weeklyData.days.reduce((s, d) => s + d.totalCalories, 0)),
          ),
          h('div', { style: styles.statLabel }, 'Total this week (kcal)'),
        ),
        h('div', {},
          h('div', { style: styles.statValue },
            String(Math.round(
              weeklyData.days.reduce((s, d) => s + d.totalCalories, 0) / 7,
            )),
          ),
          h('div', { style: styles.statLabel }, 'Daily average (kcal)'),
        ),
      ),
    ),
  );
};

export const renderAddMealForm = () =>
