export const renderFoodItemRow = (index: number) =>
  h('div', {
    style: {
      display: 'grid',
      gridTemplateColumns: '1fr 80px 100px',
      gap: '8px',
      marginBottom: '8px',
      alignItems: 'end',
    },
  },
    h('div', {},
      h('label', { style: styles.label }, 'Food'),
      h('input', {
        style: styles.input,
        type: 'text',
        name: `item-name-${index}`,
        placeholder: 'e.g., Chicken breast',
        required: 'true',
      }),
    ),
    h('div', {},
      h('label', { style: styles.label }, 'Calories'),
      h('input', {
        style: styles.input,
        type: 'number',
        name: `item-cal-${index}`,
        placeholder: '0',
        min: '0',
        required: 'true',
      }),
    ),
    h('div', {},
      h('label', { style: styles.label }, 'Category'),
      h('select', { style: styles.select, name: `item-cat-${index}` },
        h('option', { value: 'protein' }, 'Protein'),
        h('option', { value: 'carbs' }, 'Carbs'),
        h('option', { value: 'fat' }, 'Fat'),
        h('option', { value: 'fiber' }, 'Fiber'),
      ),
    ),
  );

export const renderGoalSettings = (currentGoal: number) =>
  h('div', { style: styles.container },
    h('div', { style: styles.flex },
      h('h1', { style: styles.header }, 'Daily Goal'),
      h('button', {
        style: styles.buttonSecondary,
        'p-trigger': 'navigate:daily',
      }, 'Back'),
    ),

    h('div', { style: styles.card },
      h('div', { style: { textAlign: 'center', marginBottom: '16px' } },
        h('div', { style: styles.statValue }, String(currentGoal)),
        h('div', { style: styles.statLabel }, 'Current daily goal (kcal)'),
      ),
      h('form', { 'p-trigger': 'submit-goal' },
        h('div', { style: styles.formGroup },
          h('label', { style: styles.label }, 'New Daily Calorie Goal'),
          h('input', {
            style: styles.input,
            type: 'number',
            name: 'goalCalories',
            placeholder: '2000',
            min: '0',
            max: '10000',
            required: 'true',
            value: String(currentGoal),
            'p-target': 'goalInput',
          }),
        ),
        h('button', { type: 'submit', style: styles.button }, 'Update Goal'),
      ),
    ),
  );

import { createSSR } from 'plaited';
import type { FoodItem, FoodCategory } from './types';
import { addMeal, deleteMeal, getMealsForDate, getDailySummary, getWeeklyData } from './meals';
import { getGoal, setGoal } from './goals';
import {
  renderDailySummary,
  renderWeeklyChart,
  renderAddMealForm,
  renderGoalSettings,
} from './views';

type Route = 'daily' | 'weekly' | 'add-meal' | 'settings';

const ssr = createSSR();

const renderPage = async (route: Route): Promise<string> => {
  switch (route) {
    case 'daily': {
      const [summary, meals] = await Promise.all([
        getDailySummary(),
        getMealsForDate(),
      ]);
      return ssr(renderDailySummary(summary, meals));
    }
    case 'weekly': {
      const weeklyData = await getWeeklyData();
      return ssr(renderWeeklyChart(weeklyData));
    }
    case 'add-meal': {
      return ssr(renderAddMealForm());
    }
    case 'settings': {
      const goal = await getGoal();
      return ssr(renderGoalSettings(goal.calories));
    }
  }
};

// --- Action handlers ---

const handleAddMeal = async (body: Record<string, string>): Promise<void> => {
  const mealName = body.mealName ?? 'Unnamed Meal';
  const items: FoodItem[] = [];

  for (let i = 0; i < 20; i++) {
    const name = body[`item-name-${i}`];
    const cal = body[`item-cal-${i}`];
    const cat = body[`item-cat-${i}`];
    if (!name || !cal) break;
    items.push({
      name,
      calories: parseInt(cal, 10) || 0,
      category: (cat as FoodCategory) || 'carbs',
    });
  }

  if (items.length > 0) {
    await addMeal(mealName, items);
  }
};

const handleDeleteMeal = async (id: string): Promise<void> => {
  await deleteMeal(id);
};

const handleSetGoal = async (body: Record<string, string>): Promise<void> => {
  const calories = parseInt(body.goalCalories, 10);
  if (!isNaN(calories) && calories >= 0) {
    await setGoal(calories);
  }
};

// --- HTTP server ---

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? '';
  if (contentType.includes('application/json')) {
    return req.json();
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text();
    const params = new URLSearchParams(text);
    const result: Record<string, string> = {};
    params.forEach((v, k) => { result[k] = v; });
    return result;
  }
  return {};
};

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const method = req.method;

    // API routes
    if (method === 'POST' && url.pathname === '/api/meals') {
      const body = await parseBody(req);
      await handleAddMeal(body);
      return Response.redirect('/', 303);
    }

    if (method === 'POST' && url.pathname === '/api/goal') {
      const body = await parseBody(req);
      await handleSetGoal(body);
      return Response.redirect('/settings', 303);
    }

    if (method === 'POST' && url.pathname.startsWith('/api/meals/delete/')) {
      const id = url.pathname.split('/').pop() ?? '';
      await handleDeleteMeal(id);
      return Response.redirect('/', 303);
    }

    // JSON API for programmatic access
    if (method === 'GET' && url.pathname === '/api/summary') {
      const date = url.searchParams.get('date') ?? undefined;
      const summary = await getDailySummary(date);
      return Response.json(summary);
    }

    if (method === 'GET' && url.pathname === '/api/weekly') {
      const data = await getWeeklyData();
      return Response.json(data);
    }

    if (method === 'GET' && url.pathname === '/api/goal') {
      const goal = await getGoal();
      return Response.json(goal);
    }

    // Page routes
    const routeMap: Record<string, Route> = {
      '/': 'daily',
      '/weekly': 'weekly',
      '/add-meal': 'add-meal',
      '/settings': 'settings',
    };

    const route = routeMap[url.pathname];
    if (route) {
      const html = await renderPage(route);
      return new Response(
        `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Diet Tracker</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #fafafa; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`,
        { headers: { 'Content-Type': 'text/html; charset=utf-8' } },
      );
    }

    return new Response('Not Found', { status: 404 });
  },
});

