export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other';

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other'];

export type Expense = {
  id: string;
  amount: number;
  category: Category;
  date: string; // ISO date string YYYY-MM-DD
  notes: string;
  createdAt: string; // ISO timestamp
};

export type ExpenseFilter = {
  startDate?: string;
  endDate?: string;
  category?: Category;
};

export type CategorySummary = {
  category: Category;
  total: number;
  count: number;
  percentage: number;
};

export type MonthlySummary = {
  month: string; // YYYY-MM
  total: number;
  categories: CategorySummary[];
};

import type { Expense, ExpenseFilter, Category } from './types';

const DATA_PATH = 'data/expenses.json';

export const loadExpenses = async (): Promise<Expense[]> => {
  try {
    return await Bun.file(DATA_PATH).json();
  } catch {
    return [];
  }
};

export const saveExpenses = async (expenses: Expense[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(expenses, null, 2));
};

export const addExpense = async (
  amount: number,
  category: Category,
  date: string,
  notes = ''
): Promise<Expense> => {
  const expenses = await loadExpenses();
  const expense: Expense = {
    id: crypto.randomUUID(),
    amount: Math.round(amount * 100) / 100,
    category,
    date,
    notes,
    createdAt: new Date().toISOString(),
  };
  expenses.push(expense);
  await saveExpenses(expenses);
  return expense;
};

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses();
  const idx = expenses.findIndex((e) => e.id === id);
  if (idx === -1) return false;
  expenses.splice(idx, 1);
  await saveExpenses(expenses);
  return true;
};

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false;
    if (filter.endDate && e.date > filter.endDate) return false;
    if (filter.category && e.category !== filter.category) return false;
    return true;
  });
};

export const getExpensesByMonth = (expenses: Expense[], month: string): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month));
};

import type { Expense, Category, CategorySummary, MonthlySummary } from './types';
import { CATEGORIES } from './types';

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month));
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0);

  const categories: CategorySummary[] = CATEGORIES
    .map((category: Category) => {
      const catExpenses = monthExpenses.filter((e) => e.category === category);
      const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0);
      return {
        category,
        total: Math.round(catTotal * 100) / 100,
        count: catExpenses.length,
        percentage: total > 0 ? Math.round((catTotal / total) * 10000) / 100 : 0,
      };
    })
    .filter((c) => c.count > 0);

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  };
};

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)));
  return [...months].sort().reverse();
};

