const renderPieChartSVG = (categories: MonthlySummary['categories']): string => {
  if (categories.length === 0) return '';

  const size = 200;
  const cx = size / 2;
  const cy = size / 2;
  const radius = 85;
  let currentAngle = -Math.PI / 2;

  const paths = categories.map((cat) => {
    const angle = (cat.percentage / 100) * 2 * Math.PI;
    const startX = cx + radius * Math.cos(currentAngle);
    const startY = cy + radius * Math.sin(currentAngle);
    const endAngle = currentAngle + angle;
    const endX = cx + radius * Math.cos(endAngle);
    const endY = cy + radius * Math.sin(endAngle);
    const largeArc = angle > Math.PI ? 1 : 0;
    const color = CATEGORY_COLORS[cat.category];

    // Handle case of single category (full circle)
    let d: string;
    if (cat.percentage >= 99.99) {
      d = [
        `M ${cx} ${cy - radius}`,
        `A ${radius} ${radius} 0 1 1 ${cx - 0.01} ${cy - radius}`,
        'Z',
      ].join(' ');
    } else {
      d = [
        `M ${cx} ${cy}`,
        `L ${startX} ${startY}`,
        `A ${radius} ${radius} 0 ${largeArc} 1 ${endX} ${endY}`,
        'Z',
      ].join(' ');
    }

    currentAngle = endAngle;
    return `<path d="${d}" fill="${color}" stroke="#ffffff" stroke-width="2"/>`;
  });

  return `<svg viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">${paths.join('')}</svg>`;
};

