import { createSSR } from 'plaited';
import type { Category, ExpenseFilter } from './types';
import { CATEGORIES } from './types';
import { loadExpenses, addExpense, deleteExpense, filterExpenses } from './expenses';
import { computeMonthlySummary, getAvailableMonths } from './summary';
import { toCSV } from './export';
import { renderPage } from './ui';

const getToday = (): string => new Date().toISOString().slice(0, 10);
const getCurrentMonth = (): string => getToday().slice(0, 7);

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;

  // Serve main page
  if (path === '/' && req.method === 'GET') {
    const expenses = await loadExpenses();
    const months = getAvailableMonths(expenses);
    const selectedMonth = url.searchParams.get('month') ?? months[0] ?? getCurrentMonth();
    const summary = computeMonthlySummary(expenses, selectedMonth);

    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category') as Category | null;
    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && CATEGORIES.includes(category)) filter.category = category;

    const filteredExpenses = filterExpenses(expenses, filter);

    const ssr = createSSR();
    const html = ssr(renderPage(
      getToday(),
      expenses,
      filteredExpenses,
      summary,
      months,
      selectedMonth,
      filter,
    ));

    return new Response(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Expense Logger</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f9fafb; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    });
  }

  // Add expense
  if (path === '/api/expenses' && req.method === 'POST') {
    const body = await req.json();
    const { amount, category, date, notes } = body;

    if (!amount || !category || !date) {
      return Response.json({ error: 'amount, category, and date are required' }, { status: 400 });
    }
    if (typeof amount !== 'number' || amount <= 0) {
      return Response.json({ error: 'amount must be a positive number' }, { status: 400 });
    }
    if (!CATEGORIES.includes(category)) {
      return Response.json({ error: `category must be one of: ${CATEGORIES.join(', ')}` }, { status: 400 });
    }

    const expense = await addExpense(amount, category, date, notes ?? '');
    return Response.json(expense, { status: 201 });
  }

  // Delete expense
  if (path.startsWith('/api/expenses/') && req.method === 'DELETE') {
    const id = path.slice('/api/expenses/'.length);
    const deleted = await deleteExpense(id);
    if (!deleted) {
      return Response.json({ error: 'Expense not found' }, { status: 404 });
    }
    return Response.json({ success: true });
  }

  // List expenses with optional filters
  if (path === '/api/expenses' && req.method === 'GET') {
    const expenses = await loadExpenses();
    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category') as Category | null;
    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && CATEGORIES.includes(category)) filter.category = category;

    return Response.json(filterExpenses(expenses, filter));
  }

  // Monthly summary
  if (path === '/api/summary' && req.method === 'GET') {
    const month = url.searchParams.get('month') ?? getCurrentMonth();
    const expenses = await loadExpenses();
    return Response.json(computeMonthlySummary(expenses, month));
  }

  // CSV export
  if (path === '/api/export' && req.method === 'GET') {
    const expenses = await loadExpenses();
    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category') as Category | null;
    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && CATEGORIES.includes(category)) filter.category = category;

    const filtered = filterExpenses(expenses, filter);
    const csv = toCSV(filtered);
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv; charset=utf-8',
        'Content-Disposition': 'attachment; filename="expenses.csv"',
      },
    });
  }

  return Response.json({ error: 'Not found' }, { status: 404 });
};

