export type InventoryItem = {
  id: string
  name: string
  sku: string
  quantity: number
  category: string
  reorderThreshold: number
  createdAt: string
  updatedAt: string
}

export type NewItemInput = {
  name: string
  sku: string
  quantity: number
  category: string
  reorderThreshold: number
}

export type UpdateItemInput = {
  id: string
  name?: string
  sku?: string
  quantity?: number
  category?: string
  reorderThreshold?: number
}

export type SearchParams = {
  query: string
}

export type BulkImportResult = {
  imported: number
  skipped: number
  errors: string[]
}

import type { InventoryItem, NewItemInput, UpdateItemInput, BulkImportResult } from './types'

const DATA_PATH = 'data/inventory.json'

const loadItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const getAllItems = async (): Promise<InventoryItem[]> => {
  return loadItems()
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists: ${existing.name}`)
  }
  const timestamp = now()
  const newItem: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: timestamp,
    updatedAt: timestamp,
  }
  items.push(newItem)
  await saveItems(items)
  return newItem
}

export const updateItem = async (input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((item) => item.id === input.id)
  if (index === -1) {
    throw new Error(`Item with id "${input.id}" not found`)
  }
  if (input.sku) {
    const duplicate = items.find(
      (item) => item.sku.toLowerCase() === input.sku!.toLowerCase() && item.id !== input.id
    )
    if (duplicate) {
      throw new Error(`SKU "${input.sku}" is already used by: ${duplicate.name}`)
    }
  }
  const updated: InventoryItem = {
    ...items[index],
    ...(input.name !== undefined && { name: input.name }),
    ...(input.sku !== undefined && { sku: input.sku }),
    ...(input.quantity !== undefined && { quantity: input.quantity }),
    ...(input.category !== undefined && { category: input.category }),
    ...(input.reorderThreshold !== undefined && { reorderThreshold: input.reorderThreshold }),
    updatedAt: now(),
  }
  items[index] = updated
  await saveItems(items)
  return updated
}

export const deleteItem = async (id: string): Promise<boolean> => {
  const items = await loadItems()
  const filtered = items.filter((item) => item.id !== id)
  if (filtered.length === items.length) return false
  await saveItems(filtered)
  return true
}

export const adjustQuantity = async (id: string, delta: number): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const newQty = items[index].quantity + delta
  if (newQty < 0) {
    throw new Error(`Cannot reduce quantity below 0. Current: ${items[index].quantity}, delta: ${delta}`)
  }
  items[index] = { ...items[index], quantity: newQty, updatedAt: now() }
  await saveItems(items)
  return items[index]
}

export const searchItems = async (query: string): Promise<InventoryItem[]> => {
  const items = await loadItems()
  const q = query.toLowerCase().trim()
  if (!q) return items
  return items.filter(
    (item) =>
      item.name.toLowerCase().includes(q) ||
      item.sku.toLowerCase().includes(q)
  )
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await loadItems()
  return items.filter((item) => item.quantity < item.reorderThreshold)
}

export const getCategories = async (): Promise<string[]> => {
  const items = await loadItems()
  const cats = new Set(items.map((item) => item.category))
  return [...cats].sort()
}

export const getItemsByCategory = async (category: string): Promise<InventoryItem[]> => {
  const items = await loadItems()
  return items.filter((item) => item.category.toLowerCase() === category.toLowerCase())
}

export const bulkImport = async (data: unknown): Promise<BulkImportResult> => {
  if (!Array.isArray(data)) {
    throw new Error('Bulk import data must be a JSON array')
  }
  const items = await loadItems()
  const existingSkus = new Set(items.map((item) => item.sku.toLowerCase()))
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }

  for (let i = 0; i < data.length; i++) {
    const entry = data[i]
    if (!entry || typeof entry !== 'object') {
      result.errors.push(`Row ${i}: invalid object`)
      continue
    }
    const { name, sku, quantity, category, reorderThreshold } = entry as Record<string, unknown>
    if (typeof name !== 'string' || !name.trim()) {
      result.errors.push(`Row ${i}: missing or invalid "name"`)
      continue
    }
    if (typeof sku !== 'string' || !sku.trim()) {
      result.errors.push(`Row ${i}: missing or invalid "sku"`)
      continue
    }
    if (typeof quantity !== 'number' || quantity < 0) {
      result.errors.push(`Row ${i}: missing or invalid "quantity"`)
      continue
    }
    if (typeof category !== 'string' || !category.trim()) {
      result.errors.push(`Row ${i}: missing or invalid "category"`)
      continue
    }
    const threshold = typeof reorderThreshold === 'number' ? reorderThreshold : 10
    if (existingSkus.has(sku.toLowerCase())) {
      result.skipped++
      continue
    }
    const timestamp = now()
    items.push({
      id: generateId(),
      name: name.trim(),
      sku: sku.trim(),
      quantity,
      category: category.trim(),
      reorderThreshold: threshold,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(sku.toLowerCase())
    result.imported++
  }

  await saveItems(items)
  return result
}

export const lookupBarcode = async (barcode: string): Promise<InventoryItem | undefined> => {
  return getItemBySku(barcode.trim())
}

