import {
  getAllItems,
  getLowStockItems,
  getCategories,
  addItem,
  updateItem,
  deleteItem,
  adjustQuantity,
  searchItems,
  bulkImport,
  lookupBarcode,
  getItemById,
} from './inventory'
import {
  renderDashboard,
  renderAddForm,
  renderImportForm,
  renderImportResult,
  renderSearchResults,
  renderItemsTable,
} from './render'
import type { NewItemInput, UpdateItemInput } from './types'

export const handleDashboard = async (): Promise<string> => {
  const [items, lowStock, categories] = await Promise.all([
    getAllItems(),
    getLowStockItems(),
    getCategories(),
  ])
  return renderDashboard(items, lowStock, categories)
}

export const handleAddItem = async (input: NewItemInput): Promise<{ item: string; dashboard: string }> => {
  const item = await addItem(input)
  const dashboard = await handleDashboard()
  return { item: JSON.stringify(item), dashboard }
}

export const handleUpdateItem = async (input: UpdateItemInput): Promise<{ item: string; dashboard: string }> => {
  const item = await updateItem(input)
  const dashboard = await handleDashboard()
  return { item: JSON.stringify(item), dashboard }
}

export const handleDeleteItem = async (id: string): Promise<{ success: boolean; dashboard: string }> => {
  const success = await deleteItem(id)
  const dashboard = await handleDashboard()
  return { success, dashboard }
}

export const handleAdjustQuantity = async (
  id: string,
  delta: number
): Promise<{ item: string; dashboard: string }> => {
  const item = await adjustQuantity(id, delta)
  const dashboard = await handleDashboard()
  return { item: JSON.stringify(item), dashboard }
}

export const handleSearch = async (query: string): Promise<string> => {
  const [results, lowStock] = await Promise.all([searchItems(query), getLowStockItems()])
  return renderSearchResults(results, query, lowStock)
}

export const handleBarcodeLookup = async (
  barcode: string
): Promise<{ found: boolean; item?: string; table?: string }> => {
  const item = await lookupBarcode(barcode)
  if (!item) return { found: false }
  const lowStock = await getLowStockItems()
  const table = renderItemsTable([item], lowStock)
  return { found: true, item: JSON.stringify(item), table }
