import type { Book, ReadingStats, ReadingStatus, FilterOptions } from './types'

const DATA_PATH = 'data/books.json'

const generateId = (): string => crypto.randomUUID()

export const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

export const addBook = async (input: {
  title: string
  author: string
  genre: string
  pageCount: number
  coverUrl?: string
  status?: ReadingStatus
}): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: input.status ?? 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null
  book.currentPage = Math.min(Math.max(0, currentPage), book.pageCount)
  if (book.currentPage === book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  }
  await saveBooks(books)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null
  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  } else {
    book.dateCompleted = null
    if (status === 'want-to-read') {
      book.currentPage = 0
    }
  }
  await saveBooks(books)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const filtered = books.filter((b) => b.id !== id)
  if (filtered.length === books.length) return false
  await saveBooks(filtered)
  return true
}

export const filterBooks = (books: Book[], filters: FilterOptions): Book[] => {
  return books.filter((book) => {
    if (filters.status !== 'all' && book.status !== filters.status) return false
    if (filters.genre && filters.genre !== 'all' && book.genre.toLowerCase() !== filters.genre.toLowerCase()) return false
    return true
  })
}

export const getGenres = (books: Book[]): string[] => {
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const computeStats = (books: Book[]): ReadingStats => {
  const totalBooks = books.length
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    totalBooks === 0
      ? 0
      : Math.round(books.reduce((sum, b) => sum + (b.pageCount > 0 ? (b.currentPage / b.pageCount) * 100 : 0), 0) / totalBooks)
  return { totalBooks, booksCompleted, totalPagesRead, averageProgress }
}

import { createSSR } from 'plaited'
import type { ReadingStatus, FilterOptions } from './types'
import { loadBooks, addBook, updateProgress, updateStatus, removeBook, filterBooks, getGenres, computeStats } from './store'
import { renderPage } from './render'

const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
const isValidStatus = (s: unknown): s is ReadingStatus => validStatuses.includes(s as ReadingStatus)

const redirect = () => new Response(null, { status: 303, headers: { Location: '/' } })

const handleIndex = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const statusParam = url.searchParams.get('status') ?? 'all'
  const genreParam = url.searchParams.get('genre') ?? 'all'

  const filters: FilterOptions = {
    status: isValidStatus(statusParam) ? statusParam : 'all',
    genre: genreParam,
  }

  const allBooks = await loadBooks()
  const genres = getGenres(allBooks)
  const filtered = filterBooks(allBooks, filters)
  const stats = computeStats(allBooks)

  const tree = renderPage(filtered, stats, genres, filters)
  const { render } = createSSR()
  const html = render(tree)

  return new Response(`<!DOCTYPE html>${html}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const parseForm = async (req: Request): Promise<URLSearchParams> => {
  const text = await req.text()
  return new URLSearchParams(text)
}

const handleAdd = async (req: Request): Promise<Response> => {
  const form = await parseForm(req)
  const title = form.get('title')?.trim() ?? ''
  const author = form.get('author')?.trim() ?? ''
  const genre = form.get('genre')?.trim() ?? ''
  const pageCount = parseInt(form.get('pageCount') ?? '0', 10)
  const coverUrl = form.get('coverUrl')?.trim() ?? ''
  const status = form.get('status') ?? 'want-to-read'

  if (title && author && genre && pageCount > 0) {
    await addBook({
      title,
      author,
      genre,
      pageCount,
      coverUrl,
      status: isValidStatus(status) ? status : 'want-to-read',
    })
  }
  return redirect()
}

const handleUpdateProgress = async (req: Request): Promise<Response> => {
  const form = await parseForm(req)
  const bookId = form.get('bookId') ?? ''
  const currentPage = parseInt(form.get('currentPage') ?? '0', 10)
  if (bookId) {
    await updateProgress(bookId, currentPage)
  }
  return redirect()
}

const handleUpdateStatus = async (req: Request): Promise<Response> => {
  const form = await parseForm(req)
  const bookId = form.get('bookId') ?? ''
  const status = form.get('status') ?? ''
  if (bookId && isValidStatus(status)) {
    await updateStatus(bookId, status)
  }
  return redirect()
}

const handleRemove = async (req: Request): Promise<Response> => {
  const form = await parseForm(req)
  const bookId = form.get('bookId') ?? ''
  if (bookId) {
    await removeBook(bookId)
  }
  return redirect()
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    if (method === 'GET' && url.pathname === '/') return handleIndex(req)
    if (method === 'POST' && url.pathname === '/add') return handleAdd(req)
    if (method === 'POST' && url.pathname === '/update-progress') return handleUpdateProgress(req)
    if (method === 'POST' && url.pathname === '/update-status') return handleUpdateStatus(req)
    if (method === 'POST' && url.pathname === '/remove') return handleRemove(req)

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Reading List running at http://localhost:${server.port}`)

