import { BskyAgent } from '@atproto/api'
import type { SessionData, AuthResult } from './types'

const SESSION_PATH = 'data/session.json'

const agent = new BskyAgent({ service: 'https://bsky.social' })

export const getAgent = (): BskyAgent => agent

export const loadSession = async (): Promise<SessionData | null> => {
  try {
    const file = Bun.file(SESSION_PATH)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // No saved session
  }
  return null
}

const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const clearSession = async (): Promise<void> => {
  try {
    const file = Bun.file(SESSION_PATH)
    if (await file.exists()) {
      await Bun.write(SESSION_PATH, '{}')
    }
  } catch {
    // Ignore
  }
}

export const login = async (identifier: string, password: string): Promise<AuthResult> => {
  try {
    const response = await agent.login({ identifier, password })
    const session: SessionData = {
      did: response.data.did,
      handle: response.data.handle,
      accessJwt: response.data.accessJwt,
      refreshJwt: response.data.refreshJwt,
    }
    await saveSession(session)
    return { success: true, session }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Login failed'
    return { success: false, error: message }
  }
}

export const resumeSession = async (): Promise<AuthResult> => {
  const saved = await loadSession()
  if (!saved || !saved.accessJwt) {
    return { success: false, error: 'No saved session' }
  }
  try {
    await agent.resumeSession({
      did: saved.did,
      handle: saved.handle,
      accessJwt: saved.accessJwt,
      refreshJwt: saved.refreshJwt,
      active: true,
    })
    return { success: true, session: saved }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Session expired'
    await clearSession()
    return { success: false, error: message }
  }
}

export const isAuthenticated = (): boolean => {
  return agent.session !== undefined
}

import { getAgent } from './client'
import type { PostData, TimelineResponse } from './types'

const extractPostData = (feedItem: Record<string, unknown>): PostData => {
  const post = feedItem.post as Record<string, unknown>
  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = post.viewer as Record<string, unknown> | undefined

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: (author.displayName as string) || (author.handle as string),
      avatar: author.avatar as string | undefined,
    },
    text: (record.text as string) || '',
    createdAt: record.createdAt as string,
    likeCount: (post.likeCount as number) || 0,
    repostCount: (post.repostCount as number) || 0,
    replyCount: (post.replyCount as number) || 0,
    isLiked: !!viewer?.like,
    likeUri: viewer?.like as string | undefined,
  }
}

export const getTimeline = async (cursor?: string, limit = 25): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getTimeline({ cursor, limit })

  const posts = response.data.feed.map((item) => extractPostData(item as unknown as Record<string, unknown>))

  return {
    posts,
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (actor: string, cursor?: string, limit = 25): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  const posts = response.data.feed.map((item) => extractPostData(item as unknown as Record<string, unknown>))

  return {
    posts,
    cursor: response.data.cursor,
  }
}

import { RichText } from '@atproto/api'
import { getAgent } from './client'
import type { ActionResult } from './types'

const MAX_POST_LENGTH = 300

export const createPost = async (text: string): Promise<ActionResult> => {
  if (!text.trim()) {
    return { success: false, error: 'Post text cannot be empty' }
  }

  if (text.length > MAX_POST_LENGTH) {
    return { success: false, error: `Post exceeds ${MAX_POST_LENGTH} character limit (${text.length})` }
  }

  const agent = getAgent()

  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  try {
    const response = await agent.post({
      text: rt.text,
      facets: rt.facets,
      createdAt: new Date().toISOString(),
    })
    return { success: true, uri: response.uri }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to create post'
    return { success: false, error: message }
  }
}

export const likePost = async (uri: string, cid: string): Promise<ActionResult> => {
  const agent = getAgent()
  try {
    const response = await agent.like(uri, cid)
    return { success: true, uri: response.uri }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to like post'
    return { success: false, error: message }
  }
}

export const unlikePost = async (likeUri: string): Promise<ActionResult> => {
  const agent = getAgent()
  try {
