export type Room = {
  id: string
  name: string
  createdAt: string
}

export type Message = {
  id: string
  roomId: string
  sender: string
  text: string
  timestamp: string
}

export type ReadReceipt = {
  roomId: string
  userId: string
  lastReadMessageId: string | null
  lastReadAt: string
}

export type RoomWithUnread = Room & {
  unreadCount: number
}

import type { Room, ReadReceipt, RoomWithUnread, Message } from './types'

const ROOMS_PATH = 'data/rooms.json'
const RECEIPTS_PATH = 'data/read-receipts.json'

const generateId = (): string => crypto.randomUUID()

const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(ROOMS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_PATH, JSON.stringify(rooms, null, 2))
}

const loadReceipts = async (): Promise<ReadReceipt[]> => {
  const file = Bun.file(RECEIPTS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveReceipts = async (receipts: ReadReceipt[]): Promise<void> => {
  await Bun.write(RECEIPTS_PATH, JSON.stringify(receipts, null, 2))
}

const loadRoomMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(`data/rooms/${roomId}.jsonl`)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line))
}

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms()
  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
  }
  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const listRooms = async (userId: string): Promise<RoomWithUnread[]> => {
  const rooms = await loadRooms()
  const receipts = await loadReceipts()

  const result: RoomWithUnread[] = []

  for (const room of rooms) {
    const messages = await loadRoomMessages(room.id)
    const receipt = receipts.find(
      (r) => r.roomId === room.id && r.userId === userId
    )

    let unreadCount = 0
    if (!receipt || !receipt.lastReadMessageId) {
      unreadCount = messages.length
    } else {
      const lastReadIndex = messages.findIndex(
        (m) => m.id === receipt.lastReadMessageId
      )
      unreadCount =
        lastReadIndex === -1 ? messages.length : messages.length - lastReadIndex - 1
    }

    result.push({ ...room, unreadCount })
  }

  return result
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.id === roomId)
}

export const markRead = async (roomId: string, userId: string): Promise<void> => {
  const messages = await loadRoomMessages(roomId)
  const lastMessage = messages.at(-1)
  const receipts = await loadReceipts()

  const existing = receipts.find(
    (r) => r.roomId === roomId && r.userId === userId
  )

  if (existing) {
    existing.lastReadMessageId = lastMessage?.id ?? null
    existing.lastReadAt = new Date().toISOString()
  } else {
    receipts.push({
      roomId,
      userId,
      lastReadMessageId: lastMessage?.id ?? null,
      lastReadAt: new Date().toISOString(),
    })
  }

  await saveReceipts(receipts)
}

import type { Message } from './types'

const generateId = (): string => crypto.randomUUID()

const roomFilePath = (roomId: string): string => `data/rooms/${roomId}.jsonl`

export const getMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(roomFilePath(roomId))
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line))
}

export const sendMessage = async (
  roomId: string,
  sender: string,
  text: string
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }

  const file = Bun.file(roomFilePath(roomId))
  const existing = (await file.exists()) ? await file.text() : ''
  const line = JSON.stringify(message) + '\n'
  await Bun.write(roomFilePath(roomId), existing + line)

  return message
}

export const formatMessageText = (text: string): string => {
  // Bold: **text** → <strong>text</strong>
  let formatted = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic: *text* → <em>text</em> (but not inside bold tags)
  formatted = formatted.replace(
    /(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g,
    '<em>$1</em>'
  )
  return formatted
}

