export type Reply = {
  id: string
  body: string
  author: string
  createdAt: string
  votes: number
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  createdAt: string
  votes: number
  replies: Reply[]
}

export type SortMode = 'newest' | 'top' | 'active'

export type ForumData = {
  threads: Thread[]
}

{
  "threads": []
}

import type { ForumData, Thread, Reply, SortMode } from './types'

const DATA_PATH = 'data/threads.json'

const generateId = (): string => crypto.randomUUID()

const readData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    return { threads: [] }
  }
  return file.json()
}

const writeData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getThreads = async (sort: SortMode = 'newest', search?: string): Promise<Thread[]> => {
  const data = await readData()
  let threads = data.threads

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  switch (sort) {
    case 'newest':
      return threads.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'top':
      return threads.sort((a, b) => b.votes - a.votes)
    case 'active':
      return threads.sort((a, b) => b.replies.length - a.replies.length)
    default:
      return threads
  }
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const data = await readData()
  return data.threads.find((t) => t.id === id)
}

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const data = await readData()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: 0,
    replies: [],
  }
  data.threads.push(thread)
  await writeData(data)
  return thread
}

export const addReply = async (threadId: string, body: string, author: string): Promise<Reply | null> => {
  const data = await readData()
  const thread = data.threads.find((t) => t.id === threadId)
  if (!thread) return null

  const reply: Reply = {
    id: generateId(),
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: 0,
  }
  thread.replies.push(reply)
  await writeData(data)
  return reply
}

export const voteThread = async (threadId: string, direction: 'up' | 'down'): Promise<number | null> => {
  const data = await readData()
  const thread = data.threads.find((t) => t.id === threadId)
  if (!thread) return null

  thread.votes += direction === 'up' ? 1 : -1
  await writeData(data)
  return thread.votes
}

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: 'up' | 'down'
): Promise<number | null> => {
  const data = await readData()
  const thread = data.threads.find((t) => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find((r) => r.id === replyId)
  if (!reply) return null

  reply.votes += direction === 'up' ? 1 : -1
  await writeData(data)
  return reply.votes
}

