import { createSSR } from 'plaited'
import type { SortMode } from './types'
import { getThreads, getThread, createThread, addReply, voteThread, voteReply } from './store'
import { renderForum } from './views'

const renderPage = async (sort: SortMode, search: string, threadId?: string) => {
  const ssr = createSSR()
  if (threadId) {
    const thread = await getThread(threadId)
    if (thread) {
      return ssr(renderForum([], sort, search, thread))
    }
  }
  const threads = await getThreads(sort, search || undefined)
  return ssr(renderForum(threads, sort, search))
}

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const parseJsonBody = async (req: Request): Promise<Record<string, string>> => {
  return req.json()
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3000,
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)
    const path = url.pathname

    // GET / — render forum
    if (req.method === 'GET' && path === '/') {
      const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
      const search = url.searchParams.get('search') || ''
      const threadId = url.searchParams.get('thread') || undefined
      const html = await renderPage(sort, search, threadId)
      return htmlResponse(html)
    }

    // POST /api/threads — create thread
    if (req.method === 'POST' && path === '/api/threads') {
      const body = await parseJsonBody(req)
      const { title, author } = body
      const threadBody = body.body
      if (!title || !threadBody || !author) {
        return jsonResponse({ error: 'title, body, and author are required' }, 400)
      }
      const thread = await createThread(title, threadBody, author)
      return jsonResponse(thread, 201)
    }

    // POST /api/threads/:id/replies — add reply
    if (req.method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/replies$/)) {
      const threadId = path.split('/')[3]
      const body = await parseJsonBody(req)
      const { author } = body
      const replyBody = body.body
      if (!replyBody || !author) {
        return jsonResponse({ error: 'body and author are required' }, 400)
      }
      const reply = await addReply(threadId, replyBody, author)
      if (!reply) return jsonResponse({ error: 'Thread not found' }, 404)
      return jsonResponse(reply, 201)
    }

    // POST /api/threads/:id/vote — vote on thread
    if (req.method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/vote$/)) {
      const threadId = path.split('/')[3]
      const body = await parseJsonBody(req)
      const direction = body.direction as 'up' | 'down'
      if (direction !== 'up' && direction !== 'down') {
        return jsonResponse({ error: 'direction must be "up" or "down"' }, 400)
      }
      const score = await voteThread(threadId, direction)
      if (score === null) return jsonResponse({ error: 'Thread not found' }, 404)
      return jsonResponse({ votes: score })
    }

    // POST /api/threads/:id/replies/:replyId/vote — vote on reply
    if (req.method === 'POST' && path.match(/^\/api\/threads\/[^/]+\/replies\/[^/]+\/vote$/)) {
      const parts = path.split('/')
      const threadId = parts[3]
      const replyId = parts[5]
      const body = await parseJsonBody(req)
      const direction = body.direction as 'up' | 'down'
      if (direction !== 'up' && direction !== 'down') {
        return jsonResponse({ error: 'direction must be "up" or "down"' }, 400)
      }
      const score = await voteReply(threadId, replyId, direction)
      if (score === null) return jsonResponse({ error: 'Thread or reply not found' }, 404)
      return jsonResponse({ votes: score })
    }

    // GET /api/threads — list threads as JSON
    if (req.method === 'GET' && path === '/api/threads') {
      const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
      const search = url.searchParams.get('search') || undefined
      const threads = await getThreads(sort, search)
      return jsonResponse(threads)
    }

    // GET /api/threads/:id — single thread as JSON
    if (req.method === 'GET' && path.match(/^\/api\/threads\/[^/]+$/)) {
      const threadId = path.split('/')[3]
      const thread = await getThread(threadId)
      if (!thread) return jsonResponse({ error: 'Thread not found' }, 404)
      return jsonResponse(thread)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

