const ICON_MAP: Record<string, string> = {
  '01d': '☀️', '01n': '🌙',
  '02d': '⛅', '02n': '☁️',
  '03d': '☁️', '03n': '☁️',
  '04d': '☁️', '04n': '☁️',
  '09d': '🌧️', '09n': '🌧️',
  '10d': '🌦️', '10n': '🌧️',
  '11d': '⛈️', '11n': '⛈️',
  '13d': '❄️', '13n': '❄️',
  '50d': '🌫️', '50n': '🌫️',
}

export const getWeatherIcon = (iconCode: string): string =>
  ICON_MAP[iconCode] ?? '🌡️'

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const formatTemp = (celsius: number): string =>
  `${Math.round(celsius)}°C / ${celsiusToFahrenheit(celsius)}°F`

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

export const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dailyMap = new Map<string, { temps: number[]; humidities: number[]; winds: number[]; descriptions: string[]; icons: string[] }>()

  for (const entry of forecast.list) {
    const date = entry.dt_txt.split(' ')[0]
    if (!dailyMap.has(date)) {
      dailyMap.set(date, { temps: [], humidities: [], winds: [], descriptions: [], icons: [] })
    }
    const day = dailyMap.get(date)!
    day.temps.push(entry.main.temp)
    day.humidities.push(entry.main.humidity)
    day.winds.push(entry.wind.speed)
    day.descriptions.push(entry.weather[0]?.description ?? '')
    day.icons.push(entry.weather[0]?.icon ?? '01d')
  }

  const days: DayForecast[] = []
  for (const [date, data] of dailyMap) {
    const d = new Date(date)
    days.push({
      date,
      dayName: DAY_NAMES[d.getUTCDay()],
      tempMin: Math.min(...data.temps),
      tempMax: Math.max(...data.temps),
      humidity: Math.round(data.humidities.reduce((a, b) => a + b, 0) / data.humidities.length),
      wind: Math.round(data.winds.reduce((a, b) => a + b, 0) / data.winds.length * 10) / 10,
      description: data.descriptions[Math.floor(data.descriptions.length / 2)],
      icon: data.icons[Math.floor(data.icons.length / 2)],
    })
  }

  return days.slice(0, 5)
}

export const getPlaceholderCurrent = (city: string): CurrentWeather => {
  const seed = city.toLowerCase().split('').reduce((sum, ch) => sum + ch.charCodeAt(0), 0)
  const temp = 10 + (seed % 25)
  const humidity = 30 + (seed % 50)
  const windSpeed = 2 + (seed % 12)
  const conditions: Array<{ main: string; description: string; icon: string; id: number }> = [
    { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
    { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
    { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
    { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
    { id: 200, main: 'Thunderstorm', description: 'thunderstorm', icon: '11d' },
  ]
  const condition = conditions[seed % conditions.length]

  return {
    coord: { lon: -0.13 + (seed % 180), lat: 51.51 + (seed % 90) },
    weather: [condition],
    main: {
      temp,
      feels_like: temp - 2,
      temp_min: temp - 3,
      temp_max: temp + 3,
      pressure: 1010 + (seed % 20),
      humidity,
    },
    visibility: 10000,
    wind: { speed: windSpeed, deg: (seed * 37) % 360 },
    clouds: { all: (seed * 13) % 100 },
    dt: Math.floor(Date.now() / 1000),
    sys: { country: 'XX', sunrise: Math.floor(Date.now() / 1000) - 21600, sunset: Math.floor(Date.now() / 1000) + 21600 },
    name: city,
  }
}

export const getPlaceholderForecast = (city: string): ForecastResponse => {
  const seed = city.toLowerCase().split('').reduce((sum, ch) => sum + ch.charCodeAt(0), 0)
  const baseTemp = 10 + (seed % 25)
  const now = new Date()
  const list: ForecastResponse['list'] = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 8; hour++) {
      const dt = new Date(now)
      dt.setDate(dt.getDate() + day)
      dt.setHours(hour * 3, 0, 0, 0)

      const hourTemp = baseTemp + Math.sin((day + hour) * 0.7) * 5 + (Math.cos(seed + day) * 3)
      const icons = ['01d', '02d', '03d', '10d', '04d']
      const descs = ['clear sky', 'few clouds', 'scattered clouds', 'light rain', 'overcast clouds']
      const idx = (seed + day + hour) % icons.length

      list.push({
        dt: Math.floor(dt.getTime() / 1000),
        main: {
          temp: Math.round(hourTemp * 10) / 10,
          feels_like: Math.round((hourTemp - 1.5) * 10) / 10,
          temp_min: Math.round((hourTemp - 2) * 10) / 10,
          temp_max: Math.round((hourTemp + 2) * 10) / 10,
          pressure: 1012 + (day % 5),
          humidity: 45 + ((seed + day * 7) % 40),
        },
        weather: [{ id: 800 + idx, main: idx < 2 ? 'Clear' : 'Clouds', description: descs[idx], icon: icons[idx] }],
        wind: { speed: 3 + ((seed + day) % 10), deg: (seed * 37 + day * 45) % 360 },
        dt_txt: `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')} ${String(dt.getHours()).padStart(2, '0')}:00:00`,
      })
    }
  }

  return {
    list,
    city: { name: city, country: 'XX' },
  }
}

import { h } from 'plaited'
import type { DayForecast } from './types'
import { celsiusToFahrenheit } from './weather'

const CHART_WIDTH = 600
const CHART_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

export const renderTempChart = (days: DayForecast[]) => {
  if (days.length === 0) return h('div', {}, 'No forecast data')

  const allTemps = days.flatMap((d) => [d.tempMin, d.tempMax])
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2
  const tempRange = maxTemp - minTemp || 1

  const xStep = days.length > 1 ? plotWidth / (days.length - 1) : plotWidth / 2

  const toY = (temp: number): number =>
    PADDING.top + plotHeight - ((temp - minTemp) / tempRange) * plotHeight

  const toX = (i: number): number =>
    PADDING.left + i * xStep

  const highPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMax)}`)
  const lowPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMin)}`)

  const highLine = `M ${highPoints.join(' L ')}`
  const lowLine = `M ${lowPoints.join(' L ')}`

  const gridLines: number[] = []
  const gridStep = Math.ceil(tempRange / 5) || 1
  for (let t = minTemp; t <= maxTemp; t += gridStep) {
    gridLines.push(t)
  }

  return h('div', { style: 'width:100%;overflow-x:auto;' },
    h('svg', {
      viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
      width: String(CHART_WIDTH),
      height: String(CHART_HEIGHT),
      style: 'background:#1a1a2e;border-radius:8px;font-family:system-ui,sans-serif;',
    },
      // Grid lines
      ...gridLines.map((t) =>
        h('line', {
          x1: String(PADDING.left),
          y1: String(toY(t)),
          x2: String(CHART_WIDTH - PADDING.right),
          y2: String(toY(t)),
          stroke: '#333355',
          'stroke-width': '1',
        })
      ),
      // Grid labels (°C)
      ...gridLines.map((t) =>
        h('text', {
          x: String(PADDING.left - 8),
          y: String(toY(t) + 4),
          fill: '#8888aa',
          'font-size': '11',
          'text-anchor': 'end',
        }, `${Math.round(t)}°`)
      ),
      // X-axis day labels
      ...days.map((d, i) =>
        h('text', {
          x: String(toX(i)),
          y: String(CHART_HEIGHT - 8),
          fill: '#8888aa',
          'font-size': '11',
          'text-anchor': 'middle',
        }, d.dayName)
      ),
      // High temp line
      h('path', {
        d: highLine,
        fill: 'none',
        stroke: '#ff6b6b',
        'stroke-width': '2.5',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      // Low temp line
      h('path', {
        d: lowLine,
        fill: 'none',
        stroke: '#4ecdc4',
        'stroke-width': '2.5',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      // High temp dots and labels
      ...days.flatMap((d, i) => [
        h('circle', {
          cx: String(toX(i)),
          cy: String(toY(d.tempMax)),
          r: '4',
          fill: '#ff6b6b',
        }),
        h('text', {
          x: String(toX(i)),
          y: String(toY(d.tempMax) - 10),
          fill: '#ff6b6b',
          'font-size': '10',
          'text-anchor': 'middle',
        }, `${Math.round(d.tempMax)}°`),
      ]),
      // Low temp dots and labels
      ...days.flatMap((d, i) => [
        h('circle', {
          cx: String(toX(i)),
          cy: String(toY(d.tempMin)),
          r: '4',
          fill: '#4ecdc4',
        }),
        h('text', {
          x: String(toX(i)),
          y: String(toY(d.tempMin) + 16),
          fill: '#4ecdc4',
          'font-size': '10',
          'text-anchor': 'middle',
        }, `${Math.round(d.tempMin)}°`),
      ]),
      // Legend
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 100), cy: '14', r: '4', fill: '#ff6b6b' }),
      h('text', {
        x: String(CHART_WIDTH - PADDING.right - 92),
        y: '18',
        fill: '#ff6b6b',
        'font-size': '11',
      }, 'High'),
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 48), cy: '14', r: '4', fill: '#4ecdc4' }),
      h('text', {
        x: String(CHART_WIDTH - PADDING.right - 40),
        y: '18',
        fill: '#4ecdc4',
        'font-size': '11',
      }, 'Low'),
    )
  )
}

import { createSSR } from 'plaited'
import {
  getPlaceholderCurrent,
  getPlaceholderForecast,
  aggregateDailyForecasts,
} from './weather'
import { renderDashboard } from './ui'
import type { CurrentWeather, ForecastResponse } from './types'

const DATA_FILE = 'data/last-city.json'

const API_KEY = process.env.OPENWEATHERMAP_API_KEY ?? ''

const fetchCurrentWeather = async (city: string): Promise<CurrentWeather> => {
  if (!API_KEY) return getPlaceholderCurrent(city)

  const url = `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(city)}&units=metric&appid=${API_KEY}`
  const res = await fetch(url)
  if (!res.ok) return getPlaceholderCurrent(city)
  return res.json() as Promise<CurrentWeather>
}

const fetchForecast = async (city: string): Promise<ForecastResponse> => {
  if (!API_KEY) return getPlaceholderForecast(city)

  const url = `https://api.openweathermap.org/data/2.5/forecast?q=${encodeURIComponent(city)}&units=metric&appid=${API_KEY}`
  const res = await fetch(url)
  if (!res.ok) return getPlaceholderForecast(city)
  return res.json() as Promise<ForecastResponse>
}

const loadLastCity = async (): Promise<string> => {
  try {
    const file = Bun.file(DATA_FILE)
    if (await file.exists()) {
      const data = await file.json()
      return data.city ?? 'London'
    }
  } catch {
    // ignore
  }
  return 'London'
}

const saveLastCity = async (city: string): Promise<void> => {
  await Bun.write(DATA_FILE, JSON.stringify({ city, updatedAt: new Date().toISOString() }))
}

export const getWeatherDashboard = async (city?: string): Promise<string> => {
  const resolvedCity = city?.trim() || await loadLastCity()

  const [current, forecast] = await Promise.all([
    fetchCurrentWeather(resolvedCity),
    fetchForecast(resolvedCity),
  ])

  const days = aggregateDailyForecasts(forecast)

  if (city?.trim()) {
    await saveLastCity(resolvedCity)
  }

  const ssr = createSSR()
  const template = renderDashboard(resolvedCity, current, days)
  const html = ssr(template)

  return html
}

// CLI entry point
const main = async () => {
  const city = process.argv[2] ?? await loadLastCity()
  console.log(`Fetching weather for: ${city}`)

  const html = await getWeatherDashboard(city)
  const outputFile = 'data/dashboard.html'
  await Bun.write(outputFile, `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard - ${city}</title>
  <style>
    body { margin: 0; padding: 20px; background: #0a0a1a; min-height: 100vh; }
    * { box-sizing: border-box; }
  </style>
</head>
<body>
  ${html}
</body>
</html>`)

  console.log(`Dashboard written to ${outputFile}`)
}

main().catch(console.error)

