import type { DataRow, FieldInfo, FieldType, AnalysisResult } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

export const analyzeData = (data: DataRow[]): AnalysisResult => {
  if (!Array.isArray(data) || data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [], rowCount: 0 }
  }

  const keys = Object.keys(data[0])
  const fields: FieldInfo[] = keys.map((name) => {
    const values = data.map((row) => row[name])
    const numericCount = values.filter(isNumeric).length
    const threshold = values.length * 0.8
    const type: FieldType = numericCount >= threshold ? 'numeric' : 'categorical'
    return { name, type, sample: values[0] }
  })

  return {
    fields,
    numericFields: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categoricalFields: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
    rowCount: data.length,
  }
}

const escapeHtml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')

export const highlightJson = (input: string): string => {
  try {
    const parsed = JSON.parse(input)
    const formatted = JSON.stringify(parsed, null, 2)
    return tokenize(formatted)
  } catch {
    return escapeHtml(input)
  }
}

const tokenize = (json: string): string => {
  let result = ''
  let i = 0

  while (i < json.length) {
    const ch = json[i]

    if (ch === '"') {
      let end = i + 1
      while (end < json.length && json[end] !== '"') {
        if (json[end] === '\\') end++
        end++
      }
      end++
      const str = json.slice(i, end)

      let j = end
      while (j < json.length && json[j] === ' ') j++
      if (json[j] === ':') {
        result += `<span class="json-key">${escapeHtml(str)}</span>`
      } else {
        result += `<span class="json-string">${escapeHtml(str)}</span>`
      }
      i = end
    } else if (ch === '-' || (ch >= '0' && ch <= '9')) {
      let end = i + 1
      while (end < json.length && /[\d.eE+\-]/.test(json[end])) end++
      result += `<span class="json-number">${json.slice(i, end)}</span>`
      i = end
    } else if (json.slice(i, i + 4) === 'true') {
      result += `<span class="json-boolean">true</span>`
      i += 4
    } else if (json.slice(i, i + 5) === 'false') {
      result += `<span class="json-boolean">false</span>`
      i += 5
    } else if (json.slice(i, i + 4) === 'null') {
      result += `<span class="json-null">null</span>`
      i += 4
    } else if ('{}[],:'.includes(ch)) {
      result += `<span class="json-punct">${ch}</span>`
      i++
    } else {
      result += ch
      i++
    }
  }

  return result
}

import type { ChartConfig, DataRow } from './types'
import { DEFAULT_COLORS } from './types'

const escapeXml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

const niceNum = (range: number, round: boolean): number => {
  if (range === 0) return 1
  const exponent = Math.floor(Math.log10(Math.abs(range)))
  const fraction = range / Math.pow(10, exponent)
  let nice: number
  if (round) {
    if (fraction < 1.5) nice = 1
    else if (fraction < 3) nice = 2
    else if (fraction < 7) nice = 5
    else nice = 10
  } else {
    if (fraction <= 1) nice = 1
    else if (fraction <= 2) nice = 2
    else if (fraction <= 5) nice = 5
    else nice = 10
  }
  return nice * Math.pow(10, exponent)
}

const niceScale = (min: number, max: number, maxTicks = 6): { min: number; max: number; step: number; ticks: number[] } => {
  if (min === max) {
    min = min === 0 ? 0 : min - 1
    max = max === 0 ? 1 : max + 1
  }
  const range = niceNum(max - min, false)
  const step = niceNum(range / (maxTicks - 1), true)
  const niceMin = Math.floor(min / step) * step
  const niceMax = Math.ceil(max / step) * step
  const ticks: number[] = []
  for (let val = niceMin; val <= niceMax + step * 0.5; val += step) {
    ticks.push(Math.round(val * 1e10) / 1e10)
  }
  return { min: niceMin, max: niceMax, step, ticks }
}

const svgHeader = (width: number, height: number): string =>
  `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#fff">`

const renderTitle = (title: string, width: number): string =>
  title ? `<text x="${width / 2}" y="32" text-anchor="middle" font-size="18" font-weight="600" fill="#1a1a2e">${escapeXml(title)}</text>` : ''

export const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueField, colors } = config
  const palette = colors.length ? colors : DEFAULT_COLORS

  const margin = { top: title ? 56 : 30, right: 30, bottom: xAxisLabel ? 80 : 60, left: 80 }
  const chartW = width - margin.left - margin.right
  const chartH = height - margin.top - margin.bottom

  const categories = data.map((d) => String(d[categoryField] ?? ''))
  const values = data.map((d) => Number(d[valueField]) || 0)
  const scale = niceScale(0, Math.max(...values, 1))

  const barGroupW = chartW / data.length
  const barW = barGroupW * 0.7
  const barOff = (barGroupW - barW) / 2

  const parts: string[] = [svgHeader(width, height), renderTitle(title, width)]

  // Grid lines + Y-axis ticks
  for (const tick of scale.ticks) {
    const y = margin.top + chartH - ((tick - scale.min) / (scale.max - scale.min)) * chartH
    parts.push(`<line x1="${margin.left}" y1="${y}" x2="${margin.left + chartW}" y2="${y}" stroke="#e8e8e8" stroke-width="1"/>`)
    parts.push(`<text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" font-size="12" fill="#888">${tick}</text>`)
  }

  // Y-axis label
  if (yAxisLabel) {
    parts.push(`<text x="18" y="${margin.top + chartH / 2}" text-anchor="middle" font-size="13" fill="#555" transform="rotate(-90,18,${margin.top + chartH / 2})">${escapeXml(yAxisLabel)}</text>`)
  }

  // Bars
  for (let i = 0; i < data.length; i++) {
    const x = margin.left + i * barGroupW + barOff
    const barH = ((values[i] - scale.min) / (scale.max - scale.min)) * chartH
    const y = margin.top + chartH - barH
    const color = palette[i % palette.length]
    parts.push(`<rect x="${x}" y="${y}" width="${barW}" height="${barH}" fill="${color}" rx="3"><title>${escapeXml(categories[i])}: ${values[i]}</title></rect>`)
    parts.push(`<text x="${x + barW / 2}" y="${y - 6}" text-anchor="middle" font-size="11" font-weight="500" fill="#555">${values[i]}</text>`)
  }

  // X-axis labels
  const rotateLabels = categories.length > 8
  for (let i = 0; i < categories.length; i++) {
    const x = margin.left + i * barGroupW + barGroupW / 2
    const y = margin.top + chartH + 20
    if (rotateLabels) {
      parts.push(`<text x="${x}" y="${y}" text-anchor="end" font-size="11" fill="#555" transform="rotate(-45,${x},${y})">${escapeXml(categories[i])}</text>`)
    } else {
      parts.push(`<text x="${x}" y="${y}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(categories[i])}</text>`)
    }
  }

  // X-axis label
  if (xAxisLabel) {
    parts.push(`<text x="${margin.left + chartW / 2}" y="${height - 12}" text-anchor="middle" font-size="13" fill="#555">${escapeXml(xAxisLabel)}</text>`)
  }

  // Axes
  parts.push(`<line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + chartH}" stroke="#444" stroke-width="1.5"/>`)
  parts.push(`<line x1="${margin.left}" y1="${margin.top + chartH}" x2="${margin.left + chartW}" y2="${margin.top + chartH}" stroke="#444" stroke-width="1.5"/>`)

  parts.push('</svg>')
  return parts.join('\n')
}

export const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueField, colors } = config
  const palette = colors.length ? colors : DEFAULT_COLORS
  const color = palette[0]

  const margin = { top: title ? 56 : 30, right: 30, bottom: xAxisLabel ? 80 : 60, left: 80 }
  const chartW = width - margin.left - margin.right
  const chartH = height - margin.top - margin.bottom

  const categories = data.map((d) => String(d[categoryField] ?? ''))
  const values = data.map((d) => Number(d[valueField]) || 0)
  const minVal = Math.min(...values)
  const maxVal = Math.max(...values)
  const scale = niceScale(Math.min(0, minVal), Math.max(maxVal, 1))

  const parts: string[] = [svgHeader(width, height), renderTitle(title, width)]

  // Grid + Y-axis
  for (const tick of scale.ticks) {
    const y = margin.top + chartH - ((tick - scale.min) / (scale.max - scale.min)) * chartH
    parts.push(`<line x1="${margin.left}" y1="${y}" x2="${margin.left + chartW}" y2="${y}" stroke="#e8e8e8" stroke-width="1"/>`)
    parts.push(`<text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" font-size="12" fill="#888">${tick}</text>`)
  }

  if (yAxisLabel) {
    parts.push(`<text x="18" y="${margin.top + chartH / 2}" text-anchor="middle" font-size="13" fill="#555" transform="rotate(-90,18,${margin.top + chartH / 2})">${escapeXml(yAxisLabel)}</text>`)
  }

  // Compute points
  const n = Math.max(data.length - 1, 1)
  const points = values.map((v, i) => ({
    x: margin.left + (i / n) * chartW,
    y: margin.top + chartH - ((v - scale.min) / (scale.max - scale.min)) * chartH,
    value: v,
  }))

  // Area fill
  const areaPath =
    `M ${points[0].x} ${margin.top + chartH} ` +
    points.map((p) => `L ${p.x} ${p.y}`).join(' ') +
    ` L ${points[points.length - 1].x} ${margin.top + chartH} Z`
  parts.push(`<path d="${areaPath}" fill="${color}" opacity="0.08"/>`)

  // Line
  const linePath = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')
  parts.push(`<path d="${linePath}" fill="none" stroke="${color}" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>`)

  // Dots + value labels
  for (let i = 0; i < points.length; i++) {
    const p = points[i]
    parts.push(`<circle cx="${p.x}" cy="${p.y}" r="4.5" fill="${color}" stroke="#fff" stroke-width="2"><title>${escapeXml(categories[i])}: ${p.value}</title></circle>`)
  }

  // X-axis labels
  const rotateLabels = categories.length > 8
  for (let i = 0; i < categories.length; i++) {
    const x = margin.left + (i / n) * chartW
    const y = margin.top + chartH + 20
    if (rotateLabels) {
      parts.push(`<text x="${x}" y="${y}" text-anchor="end" font-size="11" fill="#555" transform="rotate(-45,${x},${y})">${escapeXml(categories[i])}</text>`)
    } else {
      parts.push(`<text x="${x}" y="${y}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(categories[i])}</text>`)
    }
  }

  if (xAxisLabel) {
    parts.push(`<text x="${margin.left + chartW / 2}" y="${height - 12}" text-anchor="middle" font-size="13" fill="#555">${escapeXml(xAxisLabel)}</text>`)
  }

  // Axes
  parts.push(`<line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + chartH}" stroke="#444" stroke-width="1.5"/>`)
  parts.push(`<line x1="${margin.left}" y1="${margin.top + chartH}" x2="${margin.left + chartW}" y2="${margin.top + chartH}" stroke="#444" stroke-width="1.5"/>`)

  parts.push('</svg>')
  return parts.join('\n')
}

export const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, categoryField, valueField, colors } = config
  const palette = colors.length ? colors : DEFAULT_COLORS

  const categories = data.map((d) => String(d[categoryField] ?? ''))
  const values = data.map((d) => Math.abs(Number(d[valueField])) || 0)
  const total = values.reduce((a, b) => a + b, 0) || 1

  const cx = width * 0.38
  const cy = height / 2 + (title ? 14 : 0)
  const r = Math.min(width * 0.32, height * 0.36)

  const parts: string[] = [svgHeader(width, height), renderTitle(title, width)]

  let startAngle = -Math.PI / 2

  for (let i = 0; i < values.length; i++) {
    if (values[i] === 0) continue
    const sliceAngle = (values[i] / total) * 2 * Math.PI
    const endAngle = startAngle + sliceAngle
    const largeArc = sliceAngle > Math.PI ? 1 : 0
    const color = palette[i % palette.length]

    if (values.length === 1) {
      parts.push(`<circle cx="${cx}" cy="${cy}" r="${r}" fill="${color}"/>`)
    } else {
      const x1 = cx + r * Math.cos(startAngle)
      const y1 = cy + r * Math.sin(startAngle)
      const x2 = cx + r * Math.cos(endAngle)
      const y2 = cy + r * Math.sin(endAngle)
      parts.push(`<path d="M ${cx} ${cy} L ${x1.toFixed(2)} ${y1.toFixed(2)} A ${r} ${r} 0 ${largeArc} 1 ${x2.toFixed(2)} ${y2.toFixed(2)} Z" fill="${color}" stroke="#fff" stroke-width="2"><title>${escapeXml(categories[i])}: ${values[i]} (${((values[i] / total) * 100).toFixed(1)}%)</title></path>`)
    }

    // Percentage label on slice
    const midAngle = startAngle + sliceAngle / 2
    const pct = ((values[i] / total) * 100).toFixed(1)
    if (sliceAngle > 0.25) {
      const lx = cx + r * 0.62 * Math.cos(midAngle)
      const ly = cy + r * 0.62 * Math.sin(midAngle)
      parts.push(`<text x="${lx.toFixed(2)}" y="${ly.toFixed(2)}" text-anchor="middle" dominant-baseline="middle" font-size="12" font-weight="600" fill="#fff">${pct}%</text>`)
    }

    startAngle = endAngle
  }

  // Legend
  const legendX = width * 0.72
  const legendStartY = cy - (values.length * 26) / 2
  for (let i = 0; i < categories.length; i++) {
    const y = legendStartY + i * 26
    const color = palette[i % palette.length]
    parts.push(`<rect x="${legendX}" y="${y}" width="14" height="14" rx="3" fill="${color}"/>`)
    parts.push(`<text x="${legendX + 22}" y="${y + 12}" font-size="12" fill="#555">${escapeXml(categories[i])} (${values[i]})</text>`)
  }

  parts.push('</svg>')
  return parts.join('\n')
}

export const renderChart = (data: DataRow[], config: ChartConfig): string => {
  switch (config.chartType) {
    case 'bar':
      return renderBarChart(data, config)
    case 'line':
      return renderLineChart(data, config)
    case 'pie':
      return renderPieChart(data, config)
    default:
      return renderBarChart(data, config)
  }
}

