const clientScript = `
const $ = (s) => document.getElementById(s);
const textarea = $('json-input');
const pre = $('editor-highlight');
const status = $('status');

const escHtml = (s) => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const hl = (json) => {
  let r='',i=0;
  while(i<json.length){
    const c=json[i];
    if(c==='"'){let e=i+1;while(e<json.length&&json[e]!=='"'){if(json[e]==='\\\\')e++;e++}e++;
      const s=json.slice(i,e);let j=e;while(j<json.length&&json[j]===' ')j++;
      r+=json[j]===':'?'<span class="json-key">'+escHtml(s)+'</span>':'<span class="json-string">'+escHtml(s)+'</span>';i=e;
    }else if(c==='-'||(c>='0'&&c<='9')){let e=i+1;while(e<json.length&&/[\\d.eE+\\-]/.test(json[e]))e++;
      r+='<span class="json-number">'+json.slice(i,e)+'</span>';i=e;
    }else if(json.slice(i,i+4)==='true'){r+='<span class="json-boolean">true</span>';i+=4;
    }else if(json.slice(i,i+5)==='false'){r+='<span class="json-boolean">false</span>';i+=5;
    }else if(json.slice(i,i+4)==='null'){r+='<span class="json-null">null</span>';i+=4;
    }else if('{}[],:'.includes(c)){r+='<span class="json-punct">'+c+'</span>';i++;
    }else{r+=c;i++;}
  }return r;
};

const updateHL = () => { pre.innerHTML = hl(textarea.value); };
textarea.addEventListener('input', updateHL);
textarea.addEventListener('scroll', () => { pre.scrollTop=textarea.scrollTop; pre.scrollLeft=textarea.scrollLeft; });
updateHL();

const showStatus = (msg, type) => { status.className='status status-'+type; status.textContent=msg; status.style.display='block'; };
const hideStatus = () => { status.style.display='none'; };

$('btn-format').addEventListener('click', () => {
  try { textarea.value = JSON.stringify(JSON.parse(textarea.value), null, 2); updateHL(); hideStatus(); }
  catch(e) { showStatus('Invalid JSON: '+e.message, 'error'); }
});

$('btn-sample').addEventListener('click', async () => {
  const res = await fetch('/api/sample');
  textarea.value = await res.text();
  updateHL(); hideStatus();
  analyzeFields();
});

const analyzeFields = async () => {
  try {
    const data = JSON.parse(textarea.value);
    if(!Array.isArray(data)||!data.length) { showStatus('Data must be a non-empty JSON array','error'); return; }
    const res = await fetch('/api/analyze', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(data) });
    const analysis = await res.json();
    const catSel = $('sel-category'), valSel = $('sel-value');
    catSel.innerHTML=''; valSel.innerHTML='';
    analysis.categoricalFields.forEach(f => { catSel.add(new Option(f,f)); });
    analysis.numericFields.forEach(f => { valSel.add(new Option(f,f)); });
    if(!analysis.categoricalFields.length) analysis.fields.forEach(f => catSel.add(new Option(f.name,f.name)));
    if(!analysis.numericFields.length) analysis.fields.forEach(f => valSel.add(new Option(f.name,f.name)));
    const badges = $('field-badges');
    badges.innerHTML = analysis.fields.map(f =>
      '<span class="badge '+(f.type==='numeric'?'badge-num':'badge-cat')+'">'+escHtml(f.name)+' ('+f.type+')</span>'
    ).join('');
    showStatus(analysis.rowCount+' rows, '+analysis.fields.length+' fields detected','success');
  } catch(e) { showStatus('Error: '+e.message,'error'); }
};

$('btn-analyze').addEventListener('click', analyzeFields);

document.querySelectorAll('.chart-type-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.chart-type-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    $('chart-type-val').value = btn.dataset.type;
    const axisFields = document.querySelectorAll('.axis-field');
    axisFields.forEach(el => el.style.display = btn.dataset.type==='pie'?'none':'');
  });
});

$('btn-generate').addEventListener('click', async () => {
  hideStatus();
  try {
    const data = JSON.parse(textarea.value);
    if(!Array.isArray(data)||!data.length) { showStatus('Data must be a non-empty JSON array','error'); return; }
    const colors = [];
    document.querySelectorAll('.color-swatch').forEach(el => colors.push(el.value));
    const config = {
      chartType: $('chart-type-val').value,
      title: $('inp-title').value,
      xAxisLabel: $('inp-xlabel').value,
      yAxisLabel: $('inp-ylabel').value,
      categoryField: $('sel-category').value,
      valueField: $('sel-value').value,
      colors,
      width: parseInt($('inp-width').value)||800,
      height: parseInt($('inp-height').value)||500
    };
    const res = await fetch('/api/generate', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({data,config}) });
    if(!res.ok) { const e = await res.json(); showStatus(e.error||'Generation failed','error'); return; }
    const svg = await res.text();
    $('chart-container').innerHTML = svg;
    $('btn-download').style.display = '';
    $('chart-placeholder')?.remove();
  } catch(e) { showStatus('Error: '+e.message,'error'); }
});

$('btn-download').addEventListener('click', () => {
  const svg = $('chart-container').innerHTML;
  const blob = new Blob([svg], {type:'image/svg+xml'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href=url; a.download='chart.svg'; a.click();
  URL.revokeObjectURL(url);
});

// Auto-analyze on load
setTimeout(analyzeFields, 200);
`

