import { renderPage } from './ui'
import { analyzeData } from './data-analyzer'
import { renderChart } from './chart-renderer'
import type { ChartConfig, DataRow } from './types'

const sampleData = await Bun.file('data/sample.json').json()

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url

  // Main page
  if (pathname === '/' && req.method === 'GET') {
    const html = renderPage()
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  // Sample data
  if (pathname === '/api/sample' && req.method === 'GET') {
    return new Response(JSON.stringify(sampleData, null, 2), {
      headers: { 'Content-Type': 'text/plain' },
    })
  }

  // Analyze fields
  if (pathname === '/api/analyze' && req.method === 'POST') {
    try {
      const data: DataRow[] = await req.json()
      const analysis = analyzeData(data)
      return Response.json(analysis)
    } catch (err) {
      return Response.json({ error: 'Invalid JSON data' }, { status: 400 })
    }
  }

  // Generate chart
  if (pathname === '/api/generate' && req.method === 'POST') {
    try {
      const body = await req.json() as { data: DataRow[]; config: ChartConfig }
      const { data, config } = body

      if (!Array.isArray(data) || data.length === 0) {
        return Response.json({ error: 'Data must be a non-empty array' }, { status: 400 })
      }
      if (!config.categoryField || !config.valueField) {
        return Response.json({ error: 'Category and value fields are required' }, { status: 400 })
      }

      const svg = renderChart(data, {
        chartType: config.chartType || 'bar',
        title: config.title || '',
        xAxisLabel: config.xAxisLabel || '',
        yAxisLabel: config.yAxisLabel || '',
        categoryField: config.categoryField,
        valueField: config.valueField,
        colors: Array.isArray(config.colors) ? config.colors : [],
        width: Math.min(Math.max(config.width || 800, 300), 1600),
        height: Math.min(Math.max(config.height || 500, 200), 1000),
      })

      return new Response(svg, {
        headers: { 'Content-Type': 'image/svg+xml' },
      })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Chart generation failed'
      return Response.json({ error: message }, { status: 400 })
    }
  }

  return new Response('Not Found', { status: 404 })
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: handleRequest,
})

console.log(`Chart Generator running at http://localhost:${server.port}`)

