export type MarkerCategory = {
  id: string
  label: string
  color: string
}

export type MapMarker = {
  id: string
  title: string
  description: string
  lat: number
  lng: number
  category: string
}

export type MapCircle = {
  id: string
  lat: number
  lng: number
  radius: number
  color: string
  label: string
}

export type SearchResult = {
  display_name: string
  lat: string
  lon: string
}

export type MapState = {
  markers: MapMarker[]
  circles: MapCircle[]
  categories: MarkerCategory[]
  center: { lat: number; lng: number }
  zoom: number
  activeCategory: string | null
}

import type { MapMarker, MapCircle, MarkerCategory } from './types'

const MARKERS_PATH = 'data/markers.json'
const CIRCLES_PATH = 'data/circles.json'
const CATEGORIES_PATH = 'data/categories.json'

export const loadMarkers = async (): Promise<MapMarker[]> => {
  try {
    return await Bun.file(MARKERS_PATH).json()
  } catch {
    return []
  }
}

export const saveMarkers = async (markers: MapMarker[]): Promise<void> => {
  await Bun.write(MARKERS_PATH, JSON.stringify(markers, null, 2))
}

export const loadCircles = async (): Promise<MapCircle[]> => {
  try {
    return await Bun.file(CIRCLES_PATH).json()
  } catch {
    return []
  }
}

export const saveCircles = async (circles: MapCircle[]): Promise<void> => {
  await Bun.write(CIRCLES_PATH, JSON.stringify(circles, null, 2))
}

export const loadCategories = async (): Promise<MarkerCategory[]> => {
  try {
    return await Bun.file(CATEGORIES_PATH).json()
  } catch {
    return []
  }
}

export const addMarker = async (marker: Omit<MapMarker, 'id'>): Promise<MapMarker> => {
  const markers = await loadMarkers()
  const newMarker: MapMarker = {
    ...marker,
    id: `marker-${Date.now()}`,
  }
  markers.push(newMarker)
  await saveMarkers(markers)
  return newMarker
}

export const removeMarker = async (id: string): Promise<void> => {
  const markers = await loadMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  await saveMarkers(filtered)
}

export const addCircle = async (circle: Omit<MapCircle, 'id'>): Promise<MapCircle> => {
  const circles = await loadCircles()
  const newCircle: MapCircle = {
    ...circle,
    id: `circle-${Date.now()}`,
  }
  circles.push(newCircle)
  await saveCircles(circles)
  return newCircle
}

export const removeCircle = async (id: string): Promise<void> => {
  const circles = await loadCircles()
  const filtered = circles.filter((c) => c.id !== id)
  await saveCircles(filtered)
}

import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  if (!query.trim()) return []

  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
  })

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) return []

  const results: SearchResult[] = await response.json()
  return results.map((r) => ({
    display_name: r.display_name,
    lat: r.lat,
    lon: r.lon,
  }))
}

