export const renderSidebar = (
  markers: MapMarker[],
  categories: MarkerCategory[],
  activeCategory: string | null
) => {
  const filtered = activeCategory
    ? markers.filter((m) => m.category === activeCategory)
    : markers

  const getCategoryColor = (catId: string) =>
    categories.find((c) => c.id === catId)?.color ?? '#999'

  const getCategoryLabel = (catId: string) =>
    categories.find((c) => c.id === catId)?.label ?? catId

  return h('div', { class: 'sidebar' },
    h('div', { class: 'sidebar-header' },
      h('h2', {}, 'Interactive Map'),
      h('div', { class: 'search-box' },
        h('input', {
          type: 'text',
          id: 'search-input',
          placeholder: 'Search location...',
          'p-trigger': 'keyup:search-keyup',
        }),
        h('button', { 'p-trigger': 'click:search-submit' }, 'Go'),
