    ),
    h('div', { class: 'category-filters' },
      h('span', {
        class: `category-chip ${!activeCategory ? 'active' : ''}`,
        style: 'background:#555; color:white;',
        'p-trigger': 'click:filter-all',
      }, 'All'),
      ...categories.map((cat) =>
        h('span', {
          class: `category-chip ${activeCategory === cat.id ? 'active' : ''}`,
