export const renderMapScript = (
  markers: MapMarker[],
  circles: MapCircle[],
  categories: MarkerCategory[]
) => {
  const categoryMap = Object.fromEntries(categories.map((c) => [c.id, c.color]))

  return h('script', {}, `
    (function() {
      var map = L.map('map').setView([39.8283, -98.5795], 4);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors',
        maxZoom: 19,
      }).addTo(map);

      var categoryColors = ${JSON.stringify(categoryMap)};

      function makePinIcon(color) {
        return L.icon({
          iconUrl: 'data:image/svg+xml,' + encodeURIComponent(
            '<svg xmlns="http://www.w3.org/2000/svg" width="25" height="41" viewBox="0 0 25 41">' +
            '<path d="M12.5 0C5.6 0 0 5.6 0 12.5C0 21.9 12.5 41 12.5 41S25 21.9 25 12.5C25 5.6 19.4 0 12.5 0z" fill="' + color + '"/>' +
            '<circle cx="12.5" cy="12.5" r="6" fill="white"/>' +
            '</svg>'
          ),
          iconSize: [25, 41],
          iconAnchor: [12, 41],
          popupAnchor: [1, -34],
        });
      }

      var markersData = ${JSON.stringify(markers)};
      var leafletMarkers = {};

      markersData.forEach(function(m) {
        var color = categoryColors[m.category] || '#999';
        var marker = L.marker([m.lat, m.lng], { icon: makePinIcon(color) })
          .addTo(map)
          .bindPopup('<b>' + m.title + '</b><br>' + m.description);
        leafletMarkers[m.id] = marker;
      });

      var circlesData = ${JSON.stringify(circles)};
      circlesData.forEach(function(c) {
        L.circle([c.lat, c.lng], {
          radius: c.radius,
          color: c.color,
          fillColor: c.color,
          fillOpacity: 0.15,
          weight: 2,
        }).addTo(map).bindPopup('<b>' + c.label + '</b><br>Radius: ' + c.radius + 'm');
      });

      // Sidebar marker click-to-center
      document.querySelectorAll('[data-marker-id][p-trigger="click:marker-focus"]').forEach(function(el) {
        el.addEventListener('click', function(e) {
          if (e.target.classList.contains('marker-card-delete')) return;
          var lat = parseFloat(el.getAttribute('data-lat'));
          var lng = parseFloat(el.getAttribute('data-lng'));
          var id = el.getAttribute('data-marker-id');
          map.setView([lat, lng], 15);
          if (leafletMarkers[id]) leafletMarkers[id].openPopup();
        });
      });

      // Delete marker
      document.querySelectorAll('.marker-card-delete').forEach(function(el) {
        el.addEventListener('click', function(e) {
          e.stopPropagation();
          var id = el.getAttribute('data-marker-id');
          fetch('/api/markers/' + id, { method: 'DELETE' }).then(function() {
            location.reload();
          });
        });
      });

      // Category filter
      document.querySelectorAll('[p-trigger="click:filter-category"]').forEach(function(el) {
        el.addEventListener('click', function() {
          var cat = el.getAttribute('data-category');
          window.location.href = '/?category=' + cat;
        });
      });
      var filterAll = document.querySelector('[p-trigger="click:filter-all"]');
      if (filterAll) filterAll.addEventListener('click', function() {
        window.location.href = '/';
      });

      // Search
      var searchInput = document.getElementById('search-input');
      var searchResults = document.getElementById('search-results');

      function doSearch() {
        var q = searchInput.value.trim();
        if (!q) { searchResults.classList.remove('active'); return; }
        fetch('/api/search?q=' + encodeURIComponent(q))
          .then(function(r) { return r.json(); })
          .then(function(results) {
            searchResults.innerHTML = '';
            if (results.length === 0) {
              searchResults.classList.remove('active');
              return;
            }
            results.forEach(function(r) {
              var div = document.createElement('div');
              div.className = 'search-result-item';
              div.textContent = r.display_name;
              div.addEventListener('click', function() {
                map.setView([parseFloat(r.lat), parseFloat(r.lon)], 14);
                searchResults.classList.remove('active');
                searchInput.value = '';
              });
              searchResults.appendChild(div);
            });
            searchResults.classList.add('active');
          });
      }

      document.querySelector('[p-trigger="click:search-submit"]')
        .addEventListener('click', doSearch);
      searchInput.addEventListener('keyup', function(e) {
        if (e.key === 'Enter') doSearch();
      });

      // Add marker modal
      var markerModal = document.getElementById('add-marker-modal');
      var circleModal = document.getElementById('add-circle-modal');

      document.querySelector('[p-trigger="click:add-marker-open"]')
        .addEventListener('click', function() {
          var center = map.getCenter();
          document.getElementById('marker-lat').value = center.lat.toFixed(6);
          document.getElementById('marker-lng').value = center.lng.toFixed(6);
          markerModal.classList.add('active');
        });

      document.querySelector('[p-trigger="click:add-circle-open"]')
        .addEventListener('click', function() {
          var center = map.getCenter();
          document.getElementById('circle-lat').value = center.lat.toFixed(6);
          document.getElementById('circle-lng').value = center.lng.toFixed(6);
          circleModal.classList.add('active');
        });

      document.querySelectorAll('[p-trigger="click:modal-close"]').forEach(function(el) {
        el.addEventListener('click', function() {
          markerModal.classList.remove('active');
          circleModal.classList.remove('active');
        });
      });

      document.querySelector('[p-trigger="click:marker-save"]')
        .addEventListener('click', function() {
          var body = {
            title: document.getElementById('marker-title').value,
            description: document.getElementById('marker-desc').value,
            category: document.getElementById('marker-category').value,
            lat: parseFloat(document.getElementById('marker-lat').value),
            lng: parseFloat(document.getElementById('marker-lng').value),
          };
          fetch('/api/markers', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
          }).then(function() { location.reload(); });
        });

      document.querySelector('[p-trigger="click:circle-save"]')
        .addEventListener('click', function() {
          var body = {
            label: document.getElementById('circle-label').value,
            lat: parseFloat(document.getElementById('circle-lat').value),
            lng: parseFloat(document.getElementById('circle-lng').value),
            radius: parseFloat(document.getElementById('circle-radius').value),
            color: document.getElementById('circle-color').value,
          };
          fetch('/api/circles', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
          }).then(function() { location.reload(); });
        });

      // Close modals on overlay click
      [markerModal, circleModal].forEach(function(modal) {
        modal.addEventListener('click', function(e) {
          if (e.target === modal) modal.classList.remove('active');
        });
      });
    })();
  `)
}

import { h } from 'plaited'
import { createSSR } from 'plaited'
import { loadMarkers, loadCircles, loadCategories, addMarker, removeMarker, addCircle } from './store'
import { searchLocation } from './search'
import {
  renderStyles,
  renderSidebar,
  renderAddMarkerModal,
  renderAddCircleModal,
  renderMapScript,
} from './render'
import type { MapMarker, MapCircle } from './types'

const renderPage = async (categoryFilter: string | null) => {
  const [markers, circles, categories] = await Promise.all([
    loadMarkers(),
    loadCircles(),
    loadCategories(),
  ])

  const ssr = createSSR()

  const page = h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Interactive Map'),
      h('link', {
        rel: 'stylesheet',
        href: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
      }),
      h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }),
      renderStyles(),
    ),
    h('body', {},
      h('div', { class: 'map-container' },
        renderSidebar(markers, categories, categoryFilter),
        h('div', { id: 'map' }),
      ),
      renderAddMarkerModal(categories),
      renderAddCircleModal(),
      renderMapScript(markers, circles, categories),
    ),
  )

  return ssr(page)
}

const handleApiRequest = async (req: Request, url: URL): Promise<Response> => {
  const path = url.pathname

  // Search locations
  if (path === '/api/search' && req.method === 'GET') {
    const query = url.searchParams.get('q') ?? ''
    const results = await searchLocation(query)
    return Response.json(results)
  }

  // Add marker
  if (path === '/api/markers' && req.method === 'POST') {
    const body = await req.json() as Omit<MapMarker, 'id'>
    const marker = await addMarker(body)
    return Response.json(marker, { status: 201 })
  }

  // Delete marker
  if (path.startsWith('/api/markers/') && req.method === 'DELETE') {
    const id = path.split('/').pop() ?? ''
    await removeMarker(id)
    return Response.json({ ok: true })
  }

  // Add circle
  if (path === '/api/circles' && req.method === 'POST') {
    const body = await req.json() as Omit<MapCircle, 'id'>
    const circle = await addCircle(body)
    return Response.json(circle, { status: 201 })
  }

  return Response.json({ error: 'Not found' }, { status: 404 })
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    // API routes
    if (url.pathname.startsWith('/api/')) {
      return handleApiRequest(req, url)
    }

    // Main page
    if (url.pathname === '/' || url.pathname === '/index.html') {
      const categoryFilter = url.searchParams.get('category')
      const html = await renderPage(categoryFilter)
      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Interactive Map running at http://localhost:${server.port}`)

