      "ms":   { "label": "Milliseconds (ms)", "toBase": 0.001,   "fromBase": 1000 },
      "s":    { "label": "Seconds (s)",        "toBase": 1,       "fromBase": 1 },
      "min":  { "label": "Minutes (min)",      "toBase": 60,      "fromBase": 0.0166667 },
      "hr":   { "label": "Hours (hr)",         "toBase": 3600,    "fromBase": 0.000277778 },
      "day":  { "label": "Days (day)",         "toBase": 86400,   "fromBase": 0.0000115741 },
      "week": { "label": "Weeks (week)",       "toBase": 604800,  "fromBase": 0.00000165344 }
    }
  }
}

type UnitDef = {
  label: string;
  toBase?: number;
  fromBase?: number;
};

type Category = {
  label: string;
  baseUnit: string;
  units: Record<string, UnitDef>;
};

type UnitsData = Record<string, Category>;

type ConversionResult = {
  value: number;
  formula: string;
  fromLabel: string;
  toLabel: string;
};

const loadUnits = async (): Promise<UnitsData> => {
  return Bun.file('data/units.json').json();
};

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  const labels: Record<string, string> = { C: '°C', F: '°F', K: 'K' };

  if (from === to) {
    return { value, formula: `${from} = ${to}`, fromLabel: labels[from], toLabel: labels[to] };
  }

  const conversions: Record<string, { calc: (v: number) => number; formula: string }> = {
    'C-F': { calc: (v) => v * 9 / 5 + 32, formula: '°F = °C × 9/5 + 32' },
    'C-K': { calc: (v) => v + 273.15, formula: 'K = °C + 273.15' },
    'F-C': { calc: (v) => (v - 32) * 5 / 9, formula: '°C = (°F − 32) × 5/9' },
    'F-K': { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: 'K = (°F − 32) × 5/9 + 273.15' },
    'K-C': { calc: (v) => v - 273.15, formula: '°C = K − 273.15' },
    'K-F': { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: '°F = (K − 273.15) × 9/5 + 32' },
  };

  const key = `${from}-${to}`;
  const conv = conversions[key]!;

  return {
    value: conv.calc(value),
    formula: conv.formula,
    fromLabel: labels[from],
    toLabel: labels[to],
  };
};

const convertUnit = (
  value: number,
  from: string,
  to: string,
  category: Category,
): ConversionResult => {
  const fromUnit = category.units[from]!;
  const toUnit = category.units[to]!;

  if (from === to) {
    return { value, formula: `1 ${from} = 1 ${to}`, fromLabel: fromUnit.label, toLabel: toUnit.label };
  }

  const baseValue = value * fromUnit.toBase!;
  const result = baseValue * toUnit.fromBase!;

  const factor = fromUnit.toBase! * toUnit.fromBase!;
  const formula = `1 ${from} = ${formatNumber(factor)} ${to}`;

  return {
    value: result,
    formula,
    fromLabel: fromUnit.label,
    toLabel: toUnit.label,
  };
};

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString();
  const str = n.toPrecision(8);
  return parseFloat(str).toString();
};

const convert = async (
  categoryKey: string,
  value: number,
  from: string,
  to: string,
): Promise<ConversionResult> => {
  const units = await loadUnits();
  const category = units[categoryKey];

  if (!category) {
    throw new Error(`Unknown category: ${categoryKey}`);
  }

  if (!category.units[from]) {
    throw new Error(`Unknown unit: ${from} in category ${categoryKey}`);
  }

  if (!category.units[to]) {
    throw new Error(`Unknown unit: ${to} in category ${categoryKey}`);
  }

  if (categoryKey === 'temperature') {
    return convertTemperature(value, from, to);
  }

  return convertUnit(value, from, to, category);
};

const getCategories = async (): Promise<Array<{ key: string; label: string }>> => {
  const units = await loadUnits();
  return Object.entries(units).map(([key, cat]) => ({ key, label: cat.label }));
};

const getUnitsForCategory = async (categoryKey: string): Promise<Array<{ key: string; label: string }>> => {
  const units = await loadUnits();
  const category = units[categoryKey];
  if (!category) return [];
  return Object.entries(category.units).map(([key, unit]) => ({ key, label: unit.label }));
};

export { convert, getCategories, getUnitsForCategory, formatNumber };
export type { ConversionResult, UnitsData, Category, UnitDef };

