const styleToString = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';');

const render = async (params: RenderParams = {}) => {
  const activeCategory = params.category ?? 'length';
  const inputValue = params.value ?? '1';
  const numericValue = parseFloat(inputValue) || 0;

  const categories = await getCategories();
  const units = await getUnitsForCategory(activeCategory);

  const fromUnit = params.from ?? units[0]?.key ?? '';
  const toUnit = params.to ?? (units.length > 1 ? units[1]?.key : units[0]?.key) ?? '';

  let result: ConversionResult | null = null;
  let error: string | null = null;

  try {
    result = await convert(activeCategory, numericValue, fromUnit, toUnit);
  } catch (e) {
    error = e instanceof Error ? e.message : 'Conversion failed';
  }

  const tabElements = categories.map(({ key, label }) =>
    h('button', {
      style: styleToString(key === activeCategory ? styles.tabActive : styles.tab),
      'p-trigger': 'click:selectCategory',
      'data-category': key,
    }, label)
  );

  const unitOptions = units.map(({ key, label }) =>
    h('option', { value: key }, label)
  );

  const template = h('div', { style: styleToString(styles.container) },
    h('h1', { style: styleToString(styles.title) }, 'Unit Converter'),

    h('div', { style: styleToString(styles.tabs) }, ...tabElements),

    h('div', { style: styleToString(styles.inputGroup) },
      h('label', { style: styleToString(styles.label) }, 'Value'),
      h('input', {
        type: 'number',
        value: inputValue,
        style: styleToString(styles.input),
        'p-trigger': 'input:updateValue',
        'p-target': 'valueInput',
        step: 'any',
      }),
    ),

    h('div', { style: styleToString(styles.row) },
      h('div', { style: styleToString(styles.col) },
        h('label', { style: styleToString(styles.label) }, 'From'),
        h('select', {
          style: styleToString(styles.select),
          'p-trigger': 'change:updateFrom',
          'p-target': 'fromSelect',
          value: fromUnit,
        }, ...unitOptions.map(({ tag, attrs, children }) =>
          h(tag, { ...attrs, ...(attrs.value === fromUnit ? { selected: 'selected' } : {}) }, ...children)
        )),
      ),
      h('button', {
        style: styleToString(styles.swapBtn),
        'p-trigger': 'click:swapUnits',
        title: 'Swap units',
      }, '\u21C4'),
      h('div', { style: styleToString(styles.col) },
        h('label', { style: styleToString(styles.label) }, 'To'),
        h('select', {
          style: styleToString(styles.select),
          'p-trigger': 'change:updateTo',
          'p-target': 'toSelect',
          value: toUnit,
        }, ...unitOptions.map(({ tag, attrs, children }) =>
          h(tag, { ...attrs, ...(attrs.value === toUnit ? { selected: 'selected' } : {}) }, ...children)
        )),
      ),
    ),

    result
      ? h('div', { style: styleToString(styles.resultBox), 'p-target': 'resultArea' },
          h('p', { style: styleToString(styles.resultValue) },
            formatNumber(result.value),
          ),
          h('p', { style: styleToString(styles.resultLabel) },
            `${inputValue} ${result.fromLabel} = ${formatNumber(result.value)} ${result.toLabel}`,
          ),
          h('div', { style: styleToString(styles.formulaBox) },
            h('div', { style: styleToString(styles.formulaLabel) }, 'Formula'),
            result.formula,
          ),
        )
      : error
        ? h('div', { style: styleToString(styles.resultBox) },
            h('p', { style: 'color:#cc3333;margin:0' }, error),
          )
        : h(Fragment, {}),
  );

  return template;
};

const renderToString = async (params: RenderParams = {}): Promise<string> => {
  const template = await render(params);
  const ssr = createSSR();
  return ssr(template);
};

export { render, renderToString };
export type { RenderParams };

