import type { CalendarEvent } from './types';

const DATA_PATH = 'data/events.json';

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const generateId = (): string =>
  crypto.randomUUID();

export const createEvent = async (event: Omit<CalendarEvent, 'id'>): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const newEvent: CalendarEvent = { id: generateId(), ...event };
  events.push(newEvent);
  await saveEvents(events);
  return newEvent;
};

export const updateEvent = async (id: string, updates: Partial<Omit<CalendarEvent, 'id'>>): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const index = events.findIndex(e => e.id === id);
  if (index === -1) return null;
  events[index] = { ...events[index], ...updates };
  await saveEvents(events);
  return events[index];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter(e => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find(e => e.id === id) ?? null;
};

import type { CalendarEvent } from './types';

const parseDate = (dateStr: string): Date => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return new Date(year, month - 1, day);
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

export const doesEventOccurOn = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.date === targetDate) return true;
  if (!event.recurrence) return false;

  const eventDate = parseDate(event.date);
  const target = parseDate(targetDate);

  if (target < eventDate) return false;

  switch (event.recurrence) {
    case 'daily':
      return true;
    case 'weekly':
      return eventDate.getDay() === target.getDay();
    case 'monthly':
      return eventDate.getDate() === target.getDate();
    default:
      return false;
  }
};

export const getEventsForDate = (events: CalendarEvent[], targetDate: string): CalendarEvent[] =>
  events
    .filter(event => doesEventOccurOn(event, targetDate))
    .sort((a, b) => a.startTime.localeCompare(b.startTime));

export const getEventsForMonth = (events: CalendarEvent[], year: number, month: number): Map<number, CalendarEvent[]> => {
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const dayMap = new Map<number, CalendarEvent[]>();

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDate(new Date(year, month, day));
    const dayEvents = getEventsForDate(events, dateStr);
    if (dayEvents.length > 0) {
      dayMap.set(day, dayEvents);
    }
  }

  return dayMap;
};

