export const renderMonthView = (
  year: number,
  month: number,
  events: CalendarEvent[],
  todayYear: number,
  todayMonth: number,
  todayDay: number,
) => {
  const firstDay = getFirstDayOfMonth(year, month);
  const daysInMonth = getDaysInMonth(year, month);
  const eventMap = getEventsForMonth(events, year, month);

  const dayHeaders = DAY_LABELS.map(label =>
    h('div', { style: styles.dayHeader }, label)
  );

  const emptyCells = Array.from({ length: firstDay }, (_, i) =>
    h('div', { style: styles.dayCellEmpty, key: `empty-${i}` })
  );

  const dayCells = Array.from({ length: daysInMonth }, (_, i) => {
    const day = i + 1;
    const isToday = year === todayYear && month === todayMonth && day === todayDay;
    const dayEvents = eventMap.get(day) ?? [];

    const cellStyle = {
      ...styles.dayCell,
      ...(isToday ? styles.dayCellToday : {}),
    };

    const dayLabel = isToday
      ? h('div', { style: styles.todayNumber }, String(day))
      : h('div', { style: styles.dayNumber }, String(day));

    const dots = dayEvents.length > 0
      ? h('div', { style: styles.dotsRow },
          ...dayEvents.slice(0, 5).map(ev => renderCategoryDot(ev.category))
        )
      : null;

    return h('div', {
      style: cellStyle,
      'p-trigger': `select-day:${day}`,
      key: `day-${day}`,
    }, dayLabel, dots);
  });

  const legend = h('div', { style: styles.legend },
    ...(['work', 'personal', 'health', 'social'] as EventCategory[]).map(cat =>
      h('span', { style: styles.legendItem },
        renderCategoryDot(cat),
        cat,
      )
    )
  );

  return h('div', { style: styles.container },
    h('div', { style: styles.header },
      h('div', { style: styles.btnGroup },
        h('button', { style: styles.navBtn, 'p-trigger': 'prev-month' }, '\u2190'),
        h('h2', { style: styles.title }, `${MONTH_NAMES[month]} ${year}`),
        h('button', { style: styles.navBtn, 'p-trigger': 'next-month' }, '\u2192'),
      ),
      h('button', { style: styles.addBtn, 'p-trigger': 'add-event' }, '+ Add Event'),
    ),
    legend,
    h('div', { style: styles.grid },
      ...dayHeaders,
      ...emptyCells,
      ...dayCells,
    ),
  );
};

export const renderDayView = (
