import { createSSR } from 'plaited';
import type { CalendarEvent, EventCategory, RecurrencePattern, ViewState } from './types';
import { loadEvents, createEvent, updateEvent, deleteEvent, getEventById } from './store';
import { renderMonthView, renderDayView, renderEventForm } from './render';
import { todayDate, formatDateStr } from './calendar-utils';

const ssr = createSSR();

const renderPage = (bodyContent: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Calendar</title>
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f8fafc; min-height: 100vh; padding: 16px; }
  </style>
</head>
<body>${bodyContent}</body>
</html>`;

const parseMonth = (url: URL): { year: number; month: number } => {
  const today = todayDate();
  const year = parseInt(url.searchParams.get('year') ?? String(today.year), 10);
  const month = parseInt(url.searchParams.get('month') ?? String(today.month), 10);
  return { year, month };
};

const handleMonthView = async (url: URL): Promise<Response> => {
  const { year, month } = parseMonth(url);
  const events = await loadEvents();
  const today = todayDate();
  const template = renderMonthView(year, month, events, today.year, today.month, today.day);
  const html = renderPage(ssr(template));
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
};

const handleDayView = async (url: URL): Promise<Response> => {
  const year = parseInt(url.searchParams.get('year') ?? '2026', 10);
  const month = parseInt(url.searchParams.get('month') ?? '0', 10);
  const day = parseInt(url.searchParams.get('day') ?? '1', 10);
  const events = await loadEvents();
  const template = renderDayView(year, month, day, events);
  const html = renderPage(ssr(template));
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
};

const handleFormView = async (url: URL): Promise<Response> => {
  const eventId = url.searchParams.get('id');
  const prefillDate = url.searchParams.get('date') ?? undefined;
  const event = eventId ? await getEventById(eventId) : null;
  const template = renderEventForm(event, prefillDate);
  const html = renderPage(ssr(template));
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
};

const handleCreateEvent = async (req: Request): Promise<Response> => {
  const body = await req.json() as {
    title: string;
    date: string;
    startTime: string;
    endTime: string;
    description: string;
    category: EventCategory;
    recurrence: RecurrencePattern | null;
  };

  const event = await createEvent({
    title: body.title,
    date: body.date,
    startTime: body.startTime,
    endTime: body.endTime,
    description: body.description ?? '',
    category: body.category ?? 'personal',
    recurrence: body.recurrence || null,
  });

  return Response.json({ success: true, event });
};

const handleUpdateEvent = async (req: Request, id: string): Promise<Response> => {
  const body = await req.json() as Partial<Omit<CalendarEvent, 'id'>>;
  if (body.recurrence === ('' as unknown)) {
    body.recurrence = null;
  }
  const event = await updateEvent(id, body);
  if (!event) return Response.json({ error: 'Event not found' }, { status: 404 });
  return Response.json({ success: true, event });
};

const handleDeleteEvent = async (id: string): Promise<Response> => {
  const deleted = await deleteEvent(id);
  if (!deleted) return Response.json({ error: 'Event not found' }, { status: 404 });
  return Response.json({ success: true });
};

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;
  const method = req.method;

  // Page routes
  if (method === 'GET') {
    if (path === '/' || path === '/month') return handleMonthView(url);
    if (path === '/day') return handleDayView(url);
    if (path === '/event/new') return handleFormView(url);
    if (path === '/event/edit') return handleFormView(url);
  }

  // API routes
  if (path === '/api/events' && method === 'GET') {
    const events = await loadEvents();
    return Response.json(events);
  }

  if (path === '/api/events' && method === 'POST') {
    return handleCreateEvent(req);
  }

  if (path.startsWith('/api/events/') && method === 'PUT') {
    const id = path.split('/').pop()!;
    return handleUpdateEvent(req, id);
  }

  if (path.startsWith('/api/events/') && method === 'DELETE') {
    const id = path.split('/').pop()!;
    return handleDeleteEvent(id);
  }

  return new Response('Not Found', { status: 404 });
};

export default {
  port: 3000,
  fetch: router,
};

