type InlineRule = {
  pattern: RegExp
  replace: string | ((...args: string[]) => string)
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const processInline = (text: string): string => {
  const rules: InlineRule[] = [
    { pattern: /`([^`]+)`/g, replace: '<code>$1</code>' },
    { pattern: /!\[([^\]]*)\]\(([^)]+)\)/g, replace: '<img src="$2" alt="$1" />' },
    { pattern: /\[([^\]]+)\]\(([^)]+)\)/g, replace: '<a href="$2">$1</a>' },
    { pattern: /\*\*([^*]+)\*\*/g, replace: '<strong>$1</strong>' },
    { pattern: /__([^_]+)__/g, replace: '<strong>$1</strong>' },
    { pattern: /\*([^*]+)\*/g, replace: '<em>$1</em>' },
    { pattern: /_([^_]+)_/g, replace: '<em>$1</em>' },
    { pattern: /~~([^~]+)~~/g, replace: '<del>$1</del>' },
  ]
  let result = text
  for (const rule of rules) {
    result = result.replace(rule.pattern, rule.replace as string)
  }
  return result
}

const parseTable = (lines: string[]): string => {
  const rows = lines.map((line) =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())
  )
  if (rows.length < 2) return lines.map((l) => `<p>${processInline(escapeHtml(l))}</p>`).join('\n')

  const header = rows[0]
  const separator = rows[1]
  const isSeparator = separator.every((cell) => /^:?-+:?$/.test(cell))
  if (!isSeparator) return lines.map((l) => `<p>${processInline(escapeHtml(l))}</p>`).join('\n')

  const alignments = separator.map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const alignAttr = (i: number) => (alignments[i] ? ` style="text-align:${alignments[i]}"` : '')

  let html = '<table>\n<thead>\n<tr>\n'
  for (let i = 0; i < header.length; i++) {
    html += `<th${alignAttr(i)}>${processInline(escapeHtml(header[i]))}</th>\n`
  }
  html += '</tr>\n</thead>\n<tbody>\n'

  for (let r = 2; r < rows.length; r++) {
    html += '<tr>\n'
    for (let i = 0; i < header.length; i++) {
      const cell = rows[r][i] ?? ''
      html += `<td${alignAttr(i)}>${processInline(escapeHtml(cell))}</td>\n`
    }
    html += '</tr>\n'
  }
  html += '</tbody>\n</table>'
  return html
}

export const parseMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    const fenceMatch = line.match(/^```(\w*)/)
    if (fenceMatch) {
      const lang = fenceMatch[1]
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${lang}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Table detection
    if (line.includes('|') && i + 1 < lines.length && /^\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)*\|?$/.test(lines[i + 1])) {
      const tableLines: string[] = []
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      output.push(parseTable(tableLines))
      continue
    }

    // Blank line
    if (line.trim() === '') {
      i++
      continue
    }

    // Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${processInline(escapeHtml(headingMatch[2]))}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line.trim())) {
      output.push('<hr />')
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && (lines[i].startsWith('>') || (lines[i].trim() !== '' && quoteLines.length > 0 && !lines[i].startsWith('#')))) {
        if (lines[i].startsWith('>')) {
          quoteLines.push(lines[i].replace(/^>\s?/, ''))
        } else {
          quoteLines.push(lines[i])
        }
        i++
      }
      output.push(`<blockquote>${parseMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*[-*+]\s/, ''))
        i++
      }
      const items = listItems.map((item) => `<li>${processInline(escapeHtml(item))}</li>`).join('\n')
      output.push(`<ul>\n${items}\n</ul>`)
      continue
    }

    // Ordered list
    if (/^[\s]*\d+\.\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*\d+\.\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*\d+\.\s/, ''))
        i++
      }
      const items = listItems.map((item) => `<li>${processInline(escapeHtml(item))}</li>`).join('\n')
      output.push(`<ol>\n${items}\n</ol>`)
      continue
    }

    // Paragraph — collect contiguous non-blank, non-special lines
    const paraLines: string[] = []
    while (
      i < lines.length &&
      lines[i].trim() !== '' &&
      !lines[i].match(/^#{1,6}\s/) &&
      !lines[i].startsWith('```') &&
      !lines[i].startsWith('>') &&
      !/^[\s]*[-*+]\s/.test(lines[i]) &&
      !/^[\s]*\d+\.\s/.test(lines[i]) &&
      !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i].trim())
    ) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${processInline(escapeHtml(paraLines.join('\n')))}</p>`)
    }
  }

  return output.join('\n')
}

import { resolve } from 'path'

export type Document = {
  id: string
  title: string
  content: string
  createdAt: string
  updatedAt: string
}

const DATA_PATH = resolve(import.meta.dir, 'data/documents.json')

export const loadDocuments = async (): Promise<Document[]> => {
  try {
    const file = Bun.file(DATA_PATH)
    const exists = await file.exists()
    if (!exists) return []
    return await file.json()
  } catch {
    return []
  }
}

export const saveDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await loadDocuments()
  const doc: Document = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
  docs.push(doc)
  await saveDocuments(docs)
  return doc
}

export const updateDocument = async (id: string, title: string, content: string): Promise<Document | null> => {
  const docs = await loadDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return null
  docs[idx] = { ...docs[idx], title, content, updatedAt: new Date().toISOString() }
  await saveDocuments(docs)
  return docs[idx]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await loadDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await saveDocuments(filtered)
  return true
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await loadDocuments()
  return docs.find((d) => d.id === id) ?? null
}

