        updatePreview();

        const insertFormat = (action) => {
          const start = editor.selectionStart;
          const end = editor.selectionEnd;
          const selected = editor.value.substring(start, end);
          let insertion = '';
          let cursorOffset = 0;

          const formats = {
            h1: { prefix: '# ', suffix: '', placeholder: 'Heading 1' },
            h2: { prefix: '## ', suffix: '', placeholder: 'Heading 2' },
            h3: { prefix: '### ', suffix: '', placeholder: 'Heading 3' },
            bold: { prefix: '**', suffix: '**', placeholder: 'bold text' },
            italic: { prefix: '*', suffix: '*', placeholder: 'italic text' },
            link: { prefix: '[', suffix: '](url)', placeholder: 'link text' },
            image: { prefix: '![', suffix: '](url)', placeholder: 'alt text' },
            code: { prefix: '\`', suffix: '\`', placeholder: 'code' },
            codeblock: { prefix: '\`\`\`\\n', suffix: '\\n\`\`\`', placeholder: 'code block' },
            ul: { prefix: '- ', suffix: '', placeholder: 'list item' },
            ol: { prefix: '1. ', suffix: '', placeholder: 'list item' },
            quote: { prefix: '> ', suffix: '', placeholder: 'blockquote' },
            hr: { prefix: '\\n---\\n', suffix: '', placeholder: '' },
            table: { prefix: '| Header 1 | Header 2 |\\n| --- | --- |\\n| Cell 1 | Cell 2 |', suffix: '', placeholder: '' },
          };

          const fmt = formats[action];
          if (!fmt) return;

          if (fmt.placeholder === '' && action === 'hr') {
            insertion = fmt.prefix;
          } else if (fmt.placeholder === '' && action === 'table') {
            insertion = fmt.prefix;
          } else {
            const text = selected || fmt.placeholder;
            insertion = fmt.prefix + text + fmt.suffix;
          }

          editor.value = editor.value.substring(0, start) + insertion + editor.value.substring(end);
          editor.focus();
          const newPos = start + insertion.length;
          editor.selectionStart = newPos;
          editor.selectionEnd = newPos;
          updatePreview();
        };

        // Make insertFormat available globally
        window.insertFormat = insertFormat;
        `,
      ),
    ),
  )

  return '<!DOCTYPE html>' + html
}

import { parseMarkdown } from './markdown'
import { loadDocuments, createDocument, updateDocument, deleteDocument, getDocument } from './documents'
import { renderEditor } from './editor'

const PORT = Number(process.env.PORT) || 3000

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('multipart/form-data')) {
    const formData = await req.formData()
    const result: Record<string, string> = {}
    formData.forEach((value, key) => {
      result[key] = value.toString()
    })
    return result
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text()
    const params = new URLSearchParams(text)
    const result: Record<string, string> = {}
    params.forEach((value, key) => {
      result[key] = value
    })
    return result
  }
  return {}
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    // POST /preview — return rendered markdown HTML fragment
    if (method === 'POST' && url.pathname === '/preview') {
      const data = await parseFormData(req)
      const html = parseMarkdown(data.content ?? '')
      return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
    }

    // POST /save — create or update document
    if (method === 'POST' && url.pathname === '/save') {
      const data = await parseFormData(req)
      const title = data.title ?? 'Untitled'
      const content = data.content ?? ''
      const id = data.id

      if (id) {
        await updateDocument(id, title, content)
        return Response.redirect(`/?id=${id}`, 303)
      }
      const doc = await createDocument(title, content)
      return Response.redirect(`/?id=${doc.id}`, 303)
    }

    // POST /delete/:id — delete document
    const deleteMatch = url.pathname.match(/^\/delete\/(.+)$/)
    if (method === 'POST' && deleteMatch) {
      await deleteDocument(deleteMatch[1])
      return Response.redirect('/', 303)
    }

    // GET / — main editor page
    if (method === 'GET' && (url.pathname === '/' || url.pathname === '')) {
      const docId = url.searchParams.get('id')
      const documents = await loadDocuments()
      const activeDoc = docId ? await getDocument(docId) : null
      const previewHtml = parseMarkdown(activeDoc?.content ?? '# Hello World\n\nStart writing markdown here...')
      const html = renderEditor(documents, activeDoc, previewHtml)
      return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
    }

    return new Response('Not Found', { status: 404 })
  },
})

