{
  "name": "@node/color-palette",
  "version": "1.0.0",
  "description": "Generate harmonious color palettes using color theory rules with contrast checking",
  "modnet": {
    "contentType": "art",
    "structure": "form",
    "mechanics": ["filter", "sort"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "typescript": "^5.0.0"
  }
}

// --- Color Types ---

type RGB = { r: number; g: number; b: number }
type HSL = { h: number; s: number; l: number }
type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

// --- Conversion Utilities ---

const clamp = (v: number, min: number, max: number): number =>
  Math.min(Math.max(v, min), max)

const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    clamp(Math.round(n), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    let tt = t
    if (tt < 0) tt += 1
    if (tt > 1) tt -= 1
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

const isValidHex = (hex: string): boolean =>
  /^#?([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/.test(hex)

const normalizeHex = (hex: string): string => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  return `#${full.toLowerCase()}`
}

const makeColorValue = (hex: string): ColorValue => {
  const normalized = normalizeHex(hex)
  const rgb = hexToRgb(normalized)
  return { hex: normalized, rgb, hsl: rgbToHsl(rgb) }
}

const colorFromHsl = (hsl: HSL): ColorValue => {
  const rgb = hslToRgb(hsl)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

// --- Harmony Generation ---

const rotateHue = (h: number, deg: number): number => ((h + deg) % 360 + 360) % 360

const generateHarmony = (base: ColorValue, mode: HarmonyMode): ColorValue[] => {
  const { h, s, l } = base.hsl
  const offsets: number[] = (() => {
    switch (mode) {
      case 'complementary':
        return [0, 180]
      case 'analogous':
        return [-30, 0, 30]
      case 'triadic':
        return [0, 120, 240]
      case 'split-complementary':
        return [0, 150, 210]
      case 'tetradic':
        return [0, 90, 180, 270]
    }
  })()
  return offsets.map((offset) =>
    colorFromHsl({ h: rotateHue(h, offset), s, l })
  )
}

// --- WCAG Contrast ---

const luminance = (rgb: RGB): number => {
  const channel = (c: number): number => {
    const srgb = c / 255
    return srgb <= 0.03928 ? srgb / 12.92 : Math.pow((srgb + 0.055) / 1.055, 2.4)
  }
  return 0.2126 * channel(rgb.r) + 0.7152 * channel(rgb.g) + 0.0722 * channel(rgb.b)
}

type ContrastResult = {
  ratio: number
  aa: boolean
  aaLarge: boolean
  aaa: boolean
  aaaLarge: boolean
}

const contrastRatio = (color1: ColorValue, color2: ColorValue): ContrastResult => {
  const l1 = luminance(color1.rgb)
  const l2 = luminance(color2.rgb)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  const ratio = (lighter + 0.05) / (darker + 0.05)
  return {
    ratio: Math.round(ratio * 100) / 100,
    aa: ratio >= 4.5,
    aaLarge: ratio >= 3,
    aaa: ratio >= 7,
    aaaLarge: ratio >= 4.5,
  }
}

export {
  hexToRgb,
  rgbToHex,
  rgbToHsl,
  hslToRgb,
  isValidHex,
  normalizeHex,
  makeColorValue,
  colorFromHsl,
  generateHarmony,
  contrastRatio,
  luminance,
}

