const renderSwatch = (color: ColorValue, index: number) => {
  const textColor = textColorFor(color.hex)
  return h('div', {
    style: { ...styles.swatchCard },
    'data-index': String(index),
  },
    h('div', {
      style: {
        ...styles.swatchColor,
        backgroundColor: color.hex,
      },
      'p-trigger': 'click:selectContrast',
      'data-hex': color.hex,
      title: 'Click to select for contrast check',
    },
      h('span', {
        style: { color: textColor, fontSize: '14px', fontWeight: '600' },
      }, color.hex.toUpperCase()),
    ),
    h('div', { style: styles.swatchInfo },
      h('div', {
        style: styles.colorLabel,
        'p-trigger': 'click:copyValue',
        'data-value': color.hex.toUpperCase(),
        title: 'Click to copy',
      }, `HEX: ${color.hex.toUpperCase()}`),
      h('div', {
        style: styles.colorLabel,
        'p-trigger': 'click:copyValue',
        'data-value': `rgb(${color.rgb.r}, ${color.rgb.g}, ${color.rgb.b})`,
        title: 'Click to copy',
      }, `RGB: ${color.rgb.r}, ${color.rgb.g}, ${color.rgb.b}`),
      h('div', {
