type Preset = { name: string; hex: string }

const renderPage = (
  palette: ColorValue[],
  mode: HarmonyMode,
  baseHex: string,
  presets: Preset[],
  contrast1Index: number,
  contrast2Index: number,
) => {
  const contrast1 = palette[contrast1Index] ?? palette[0]
  const contrast2 = palette[contrast2Index] ?? palette[1] ?? palette[0]
  const result = contrastRatio(contrast1, contrast2)

  return h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Color Palette Generator'),
      h('style', {}, `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #0f172a; }
        select option { background: #1e293b; color: #f8fafc; }
        input[type="color"]::-webkit-color-swatch-wrapper { padding: 2px; }
        input[type="color"]::-webkit-color-swatch { border: none; border-radius: 6px; }
        .color-label:hover { background: #334155; }
        .swatch-card:hover { border-color: #6366f1 !important; }
        .preset-btn:hover { transform: scale(1.2); }
      `),
    ),
    h('body', {},
      h('div', { style: styles.page },
        // Header
        h('div', { style: styles.header },
          h('h1', { style: styles.title }, 'Color Palette Generator'),
          h('p', { style: styles.subtitle }, 'Generate harmonious palettes using color theory'),
        ),

        // Presets
        h('div', { style: styles.presetsRow },
          ...presets.map((preset) =>
            h('button', {
              class: 'preset-btn',
              style: {
                ...styles.presetBtn,
                backgroundColor: preset.hex,
              },
              'p-trigger': 'click:selectPreset',
              'data-hex': preset.hex,
              title: preset.name,
            }),
          ),
        ),

        // Input Controls
        h('form', {
          method: 'GET',
          action: '/',
          style: styles.inputRow,
        },
          h('input', {
            type: 'color',
            name: 'color',
            value: baseHex,
            style: styles.colorInput,
            'p-trigger': 'change:updateColor',
          }),
          h('input', {
            type: 'text',
            name: 'color',
            value: baseHex.toUpperCase(),
            placeholder: '#FF6B35',
            style: styles.hexInput,
            maxlength: '7',
            pattern: '#[0-9A-Fa-f]{6}',
          }),
          h('select', {
            name: 'mode',
            style: styles.modeSelect,
          },
            ...(['complementary', 'analogous', 'triadic', 'split-complementary', 'tetradic'] as const).map(
              (m) =>
                h('option', {
                  value: m,
                  ...(m === mode ? { selected: '' } : {}),
                }, m.charAt(0).toUpperCase() + m.slice(1)),
            ),
          ),
          h('button', {
            type: 'submit',
            style: styles.generateBtn,
          }, 'Generate'),
        ),

        // Palette Swatches
        h('div', { style: styles.swatchGrid },
          ...palette.map((color, i) => renderSwatch(color, i)),
        ),

        // Contrast Checker
        h('div', { style: styles.contrastSection },
          h('h2', { style: styles.contrastTitle }, 'WCAG Contrast Checker'),
          h('div', { style: styles.contrastPickers },
            h('div', { style: styles.contrastPickerGroup },
              h('div', {
                style: {
                  ...styles.contrastSwatch,
                  backgroundColor: contrast1.hex,
                },
              }),
              h('select', {
                name: 'c1',
                style: styles.contrastSelect,
                'p-trigger': 'change:updateContrast',
              },
                ...palette.map((c, i) =>
                  h('option', {
                    value: String(i),
                    ...(i === contrast1Index ? { selected: '' } : {}),
                  }, c.hex.toUpperCase()),
                ),
              ),
            ),
            h('span', { style: { color: '#64748b', fontSize: '20px' } }, 'vs'),
            h('div', { style: styles.contrastPickerGroup },
              h('div', {
                style: {
                  ...styles.contrastSwatch,
                  backgroundColor: contrast2.hex,
                },
              }),
              h('select', {
                name: 'c2',
                style: styles.contrastSelect,
                'p-trigger': 'change:updateContrast',
              },
                ...palette.map((c, i) =>
                  h('option', {
                    value: String(i),
                    ...(i === contrast2Index ? { selected: '' } : {}),
                  }, c.hex.toUpperCase()),
                ),
              ),
            ),
          ),
          renderContrastResult(contrast1, contrast2, result),
        ),
      ),

      // Copy toast
      h('div', {
        id: 'copy-toast',
        'p-target': 'toast',
        style: styles.copyToast,
      }, 'Copied!'),

      // Client-side script for copy & interactivity
      h('script', {}, `
        document.addEventListener('click', async (e) => {
          const target = e.target.closest('[p-trigger]');
          if (!target) return;
          const trigger = target.getAttribute('p-trigger');

          if (trigger === 'click:copyValue') {
            const value = target.dataset.value;
            try {
              await navigator.clipboard.writeText(value);
              const toast = document.getElementById('copy-toast');
              toast.textContent = 'Copied: ' + value;
              toast.style.opacity = '1';
              setTimeout(() => { toast.style.opacity = '0'; }, 1500);
            } catch(err) {
              console.error('Copy failed', err);
            }
          }

          if (trigger === 'click:selectPreset') {
            const hex = target.dataset.hex;
            const form = document.querySelector('form');
            const inputs = form.querySelectorAll('input[name="color"]');
            inputs.forEach(inp => inp.value = hex);
            form.submit();
          }

          if (trigger === 'click:selectContrast') {
            // handled via form controls
          }
        });

        // Sync color picker with text input
        const colorPicker = document.querySelector('input[type="color"]');
        const textInput = document.querySelector('input[type="text"]');
        if (colorPicker && textInput) {
          colorPicker.addEventListener('input', () => {
            textInput.value = colorPicker.value.toUpperCase();
          });
          textInput.addEventListener('input', () => {
            const v = textInput.value;
            if (/^#[0-9A-Fa-f]{6}$/.test(v)) {
              colorPicker.value = v;
            }
          });
        }

        // Contrast select changes
        const contrastSelects = document.querySelectorAll('[name="c1"], [name="c2"]');
        contrastSelects.forEach(sel => {
          sel.addEventListener('change', () => {
            const url = new URL(window.location);
            const c1 = document.querySelector('[name="c1"]').value;
            const c2 = document.querySelector('[name="c2"]').value;
            url.searchParams.set('c1', c1);
            url.searchParams.set('c2', c2);
            window.location = url.toString();
          });
        });
      `),
    ),
  )
}

