import { makeColorValue, generateHarmony, isValidHex } from './color'
import type { HarmonyMode } from './color'
import { renderPage } from './render'
import type { Preset } from './render'
import { createSSR } from '@plaited/ssr'

const VALID_MODES: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

const DEFAULT_COLOR = '#6366f1'
const DEFAULT_MODE: HarmonyMode = 'analogous'

const loadPresets = async (): Promise<Preset[]> => {
  const file = Bun.file('data/presets.json')
  return file.json()
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname !== '/') {
      return new Response('Not found', { status: 404 })
    }

    const rawColor = url.searchParams.get('color') ?? DEFAULT_COLOR
    const rawMode = url.searchParams.get('mode') ?? DEFAULT_MODE
    const c1Param = url.searchParams.get('c1')
    const c2Param = url.searchParams.get('c2')

    const baseHex = isValidHex(rawColor) ? rawColor : DEFAULT_COLOR
    const mode = VALID_MODES.includes(rawMode as HarmonyMode)
      ? (rawMode as HarmonyMode)
      : DEFAULT_MODE

    const base = makeColorValue(baseHex)
    const palette = generateHarmony(base, mode)

    const contrast1Index = c1Param !== null ? Math.min(parseInt(c1Param, 10) || 0, palette.length - 1) : 0
    const contrast2Index = c2Param !== null ? Math.min(parseInt(c2Param, 10) || 0, palette.length - 1) : Math.min(1, palette.length - 1)

    const presets = await loadPresets()

    const html = renderPage(palette, mode, base.hex, presets, contrast1Index, contrast2Index)
    const { render } = createSSR()
    const output = render(html)

    return new Response(`<!DOCTYPE html>${output}`, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Color Palette Generator running at http://localhost:${server.port}`)

