import type { Project, SortOption, GalleryQuery } from './types'

const DATA_PATH = 'data/projects.json'

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

export const getProjects = async (query: GalleryQuery = {}): Promise<Project[]> => {
  let projects = await loadProjects()

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    projects = projects.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (query.q) {
    const q = query.q.toLowerCase()
    projects = projects.filter(
      (p) => p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q),
    )
  }

  const sort = query.sort ?? 'date-desc'
  return sortProjects(projects, sort)
}

export const getProject = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) tagSet.add(t)
  }
  return [...tagSet].sort()
}

export const addProject = async (project: Project): Promise<Project> => {
  const projects = await loadProjects()
  projects.push(project)
  await saveProjects(projects)
  return project
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<Project | undefined> => {
  const projects = await loadProjects()
  const idx = projects.findIndex((p) => p.id === id)
  if (idx === -1) return undefined
  projects[idx] = { ...projects[idx], ...updates, id }
  await saveProjects(projects)
  return projects[idx]
}

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await loadProjects()
  const idx = projects.findIndex((p) => p.id === id)
  if (idx === -1) return false
  projects.splice(idx, 1)
  await saveProjects(projects)
  return true
}

