export const renderGallery = (
  projects: Project[],
  allTags: string[],
  activeTag: string,
  query: string,
  sort: SortOption,
) => {
  const currentParams = new URLSearchParams()
  if (query) currentParams.set('q', query)
  if (sort && sort !== 'date-desc') currentParams.set('sort', sort)

  const tagUrl = (tag: string) => {
    const params = new URLSearchParams(currentParams)
    if (tag) params.set('tag', tag)
    else params.delete('tag')
    const qs = params.toString()
    return qs ? `/?${qs}` : '/'
  }

  return h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', {}, 'Portfolio Gallery'),
      h('style', {}, cssReset + layoutStyles + controlStyles + gridStyles),
    ),
    h('body', {},
      h('div', { class: 'container' },
        h('header', { class: 'header' },
          h('h1', {}, 'Portfolio'),
          h('p', {}, 'A collection of projects and experiments'),
        ),
        h('form', { method: 'get', action: '/', class: 'controls' },
          h('input', {
            class: 'search-input',
            type: 'search',
            name: 'q',
            placeholder: 'Search projects...',
            value: query,
          }),
          activeTag ? h('input', { type: 'hidden', name: 'tag', value: activeTag }) : '',
          h('div', { class: 'select-wrap' },
            h('select', { name: 'sort', onchange: 'this.form.submit()' },
              renderSortOption('date-desc', 'Newest first', sort),
              renderSortOption('date-asc', 'Oldest first', sort),
              renderSortOption('alpha-asc', 'A \u2192 Z', sort),
              renderSortOption('alpha-desc', 'Z \u2192 A', sort),
            ),
          ),
        ),
        h('div', { class: 'tag-filters' },
          h('a', { href: tagUrl(''), class: `tag-btn${activeTag === '' ? ' active' : ''}` }, 'All'),
          ...allTags.map((tag) =>
            h('a', { href: tagUrl(tag), class: `tag-btn${activeTag === tag ? ' active' : ''}` }, tag),
          ),
        ),
        projects.length > 0
          ? h('div', { class: 'grid' }, ...projects.map(renderCard))
          : h('div', { class: 'empty-state' },
              h('p', {}, 'No projects found matching your criteria.'),
            ),
      ),
    ),
  )
}

export const renderDetail = (project: Project) => {
