    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })

  return h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', {}, `${project.title} — Portfolio`),
      h('style', {}, cssReset + layoutStyles + detailStyles),
    ),
    h('body', {},
      h('div', { class: 'container' },
        h('a', { href: '/', class: 'back-link' }, svgArrowLeft, ' Back to gallery'),
        h('div', { class: 'detail' },
          h('div', { class: 'detail-header' },
            h('h1', { class: 'detail-title' }, project.title),
            h('div', { class: 'detail-meta' },
              h('span', {}, `Added ${dateStr}`),
              h('div', { class: 'detail-tags' },
                ...project.tags.map((tag) =>
                  h('a', { href: `/?tag=${encodeURIComponent(tag)}`, class: 'detail-tag' }, tag),
                ),
              ),
            ),
          ),
          project.images.length > 0
            ? h('div', { class: 'carousel', id: 'carousel' },
                h('div', { class: 'carousel-track', id: 'track' },
                  ...project.images.map((img, i) =>
                    h('div', { class: 'carousel-slide' },
                      h('img', {
                        src: img,
                        alt: `${project.title} screenshot ${i + 1}`,
                        style: 'cursor:pointer',
                        onclick: `openLightbox(${i})`,
                      }),
                    ),
                  ),
                ),
                project.images.length > 1
                  ? h(Fragment, {},
                      h('button', {
                        class: 'carousel-nav carousel-prev',
                        onclick: 'scrollCarousel(-1)',
                        'aria-label': 'Previous image',
                      }, '\u2039'),
                      h('button', {
                        class: 'carousel-nav carousel-next',
                        onclick: 'scrollCarousel(1)',
                        'aria-label': 'Next image',
                      }, '\u203A'),
                      h('div', { class: 'carousel-dots', id: 'dots' },
                        ...project.images.map((_, i) =>
                          h('button', {
                            class: `carousel-dot${i === 0 ? ' active' : ''}`,
                            onclick: `goToSlide(${i})`,
                            'aria-label': `Go to image ${i + 1}`,
                          }),
                        ),
                      ),
                    )
                  : '',
              )
            : '',
          h('div', { class: 'detail-links' },
            ...(project.demoUrl
              ? [h('a', { href: project.demoUrl, target: '_blank', rel: 'noopener' }, svgExternalLink, ' Live Demo')]
              : []),
            ...(project.sourceUrl
              ? [h('a', { href: project.sourceUrl, target: '_blank', rel: 'noopener' }, svgCode, ' Source Code')]
              : []),
          ),
          h('p', { class: 'detail-desc' }, project.fullDescription),
        ),
      ),
      // Lightbox overlay
      h('div', { class: 'lightbox-overlay', id: 'lightbox' },
        h('button', { class: 'lightbox-close', onclick: 'closeLightbox()', 'aria-label': 'Close' }, '\u00D7'),
        h('button', {
          class: 'lightbox-nav lightbox-prev',
          onclick: 'lightboxNav(-1)',
          'aria-label': 'Previous',
        }, '\u2039'),
        h('img', { class: 'lightbox-img', id: 'lightbox-img', src: '', alt: 'Lightbox image' }),
        h('button', {
          class: 'lightbox-nav lightbox-next',
          onclick: 'lightboxNav(1)',
          'aria-label': 'Next',
        }, '\u203A'),
      ),
      // Inline script for carousel and lightbox interactivity
      h('script', {}, `
        const images = ${JSON.stringify(project.images)};
        let currentSlide = 0;
        let lightboxIndex = 0;

        const track = document.getElementById('track');
        const dots = document.querySelectorAll('.carousel-dot');

        function updateDots() {
          dots.forEach((d, i) => d.classList.toggle('active', i === currentSlide));
        }

        function scrollCarousel(dir) {
          currentSlide = Math.max(0, Math.min(images.length - 1, currentSlide + dir));
          track.children[currentSlide].scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'start' });
          updateDots();
        }

        function goToSlide(i) {
          currentSlide = i;
          track.children[i].scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'start' });
          updateDots();
        }

        function openLightbox(i) {
          lightboxIndex = i;
          const lb = document.getElementById('lightbox');
          document.getElementById('lightbox-img').src = images[i];
          lb.classList.add('open');
          document.body.style.overflow = 'hidden';
        }

        function closeLightbox() {
          document.getElementById('lightbox').classList.remove('open');
          document.body.style.overflow = '';
        }

        function lightboxNav(dir) {
          lightboxIndex = (lightboxIndex + dir + images.length) % images.length;
          document.getElementById('lightbox-img').src = images[lightboxIndex];
        }

        document.getElementById('lightbox').addEventListener('click', function(e) {
          if (e.target === this) closeLightbox();
        });

        document.addEventListener('keydown', function(e) {
          const lb = document.getElementById('lightbox');
          if (!lb.classList.contains('open')) return;
          if (e.key === 'Escape') closeLightbox();
          if (e.key === 'ArrowLeft') lightboxNav(-1);
          if (e.key === 'ArrowRight') lightboxNav(1);
        });
      `),
    ),
  )
}

