import { createSSR } from 'plaited'
import type { GalleryQuery, SortOption } from './types'
import { getProjects, getProject, getAllTags, addProject, updateProject, deleteProject } from './store'
import { renderGallery, renderDetail, render404 } from './render'

const ssr = createSSR()

const htmlResponse = (template: ReturnType<typeof renderGallery>, status = 200) =>
  new Response(`<!DOCTYPE html>${ssr(template)}`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const parseSort = (val: string | null): SortOption => {
  const valid: SortOption[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']
  return valid.includes(val as SortOption) ? (val as SortOption) : 'date-desc'
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // --- HTML routes ---

    if (method === 'GET' && pathname === '/') {
      const query: GalleryQuery = {
        tag: url.searchParams.get('tag') ?? undefined,
        q: url.searchParams.get('q') ?? undefined,
        sort: parseSort(url.searchParams.get('sort')),
      }
      const [projects, allTags] = await Promise.all([getProjects(query), getAllTags()])
      return htmlResponse(renderGallery(projects, allTags, query.tag ?? '', query.q ?? '', query.sort!))
    }

    const detailMatch = pathname.match(/^\/project\/([a-zA-Z0-9_-]+)$/)
    if (method === 'GET' && detailMatch) {
      const project = await getProject(detailMatch[1])
      if (!project) return htmlResponse(render404(), 404)
      return htmlResponse(renderDetail(project))
    }

    // --- JSON API routes ---

    if (method === 'POST' && pathname === '/projects') {
      const body = await req.json()
      const project = await addProject(body)
      return jsonResponse(project, 201)
    }

    const apiMatch = pathname.match(/^\/projects\/([a-zA-Z0-9_-]+)$/)
    if (apiMatch) {
      const id = apiMatch[1]
      if (method === 'PUT') {
        const body = await req.json()
        const updated = await updateProject(id, body)
        if (!updated) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(updated)
      }
      if (method === 'DELETE') {
        const deleted = await deleteProject(id)
        if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse({ ok: true })
      }
    }

    return htmlResponse(render404(), 404)
  },
})

