export type Tool = 'brush' | 'eraser' | 'rectangle' | 'circle' | 'line'

export type Point = {
  x: number
  y: number
}

export type Stroke = {
  tool: Tool
  color: string
  size: number
  points: Point[]
}

export type ShapeStroke = {
  tool: 'rectangle' | 'circle' | 'line'
  color: string
  size: number
  start: Point
  end: Point
}

export type DrawAction = Stroke | ShapeStroke

export type Layer = {
  id: string
  name: string
  visible: boolean
  actions: DrawAction[]
}

export type CanvasState = {
  layers: Layer[]
  activeLayerId: string
  width: number
  height: number
}

export type HistoryEntry = {
  layers: Layer[]
  activeLayerId: string
}

export type DrawingMeta = {
  id: string
  name: string
  createdAt: string
  updatedAt: string
  width: number
  height: number
  layerCount: number
}

export const isShapeStroke = (action: DrawAction): action is ShapeStroke =>
  'start' in action && 'end' in action

import type { Layer, CanvasState, DrawAction } from './types'

let idCounter = 0

export const createLayerId = (): string => {
  idCounter += 1
  return `layer-${Date.now()}-${idCounter}`
}

export const createLayer = (name: string): Layer => ({
  id: createLayerId(),
  name,
  visible: true,
  actions: [],
})

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const layer = createLayer('Layer 1')
  return {
    layers: [layer],
    activeLayerId: layer.id,
    width,
    height,
  }
}

export const addLayer = (state: CanvasState): CanvasState => {
  const layer = createLayer(`Layer ${state.layers.length + 1}`)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const layers = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? layers[layers.length - 1].id : state.activeLayerId
  return { ...state, layers, activeLayerId }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
})

export const addActionToLayer = (
  state: CanvasState,
  layerId: string,
  action: DrawAction,
): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, actions: [...l.actions, action] } : l,
  ),
})

export const clearLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, actions: [] } : l)),
})

export const clearAllLayers = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => ({ ...l, actions: [] })),
})

export const moveLayer = (
  state: CanvasState,
  layerId: string,
  direction: 'up' | 'down',
): CanvasState => {
  const idx = state.layers.findIndex((l) => l.id === layerId)
  if (idx === -1) return state
  const newIdx = direction === 'up' ? idx + 1 : idx - 1
  if (newIdx < 0 || newIdx >= state.layers.length) return state
  const layers = [...state.layers]
  const [removed] = layers.splice(idx, 1)
  layers.splice(newIdx, 0, removed)
  return { ...state, layers }
}

import type { CanvasState, HistoryEntry } from './types'

export type HistoryStack = {
  past: HistoryEntry[]
  future: HistoryEntry[]
  maxSize: number
}

export const createHistory = (maxSize = 50): HistoryStack => ({
  past: [],
  future: [],
  maxSize,
})

const snapshotState = (state: CanvasState): HistoryEntry => ({
  layers: state.layers.map((l) => ({ ...l, actions: [...l.actions] })),
  activeLayerId: state.activeLayerId,
})

export const pushHistory = (history: HistoryStack, state: CanvasState): HistoryStack => {
  const entry = snapshotState(state)
  const past = [...history.past, entry]
  if (past.length > history.maxSize) past.shift()
  return { ...history, past, future: [] }
}

export const undo = (
  history: HistoryStack,
  currentState: CanvasState,
): { history: HistoryStack; state: CanvasState } | null => {
  if (history.past.length === 0) return null
  const past = [...history.past]
  const entry = past.pop()!
  const future = [snapshotState(currentState), ...history.future]
  return {
    history: { ...history, past, future },
    state: { ...currentState, layers: entry.layers, activeLayerId: entry.activeLayerId },
  }
}

export const redo = (
  history: HistoryStack,
  currentState: CanvasState,
): { history: HistoryStack; state: CanvasState } | null => {
  if (history.future.length === 0) return null
  const future = [...history.future]
  const entry = future.shift()!
  const past = [...history.past, snapshotState(currentState)]
  return {
    history: { ...history, past, future },
    state: { ...currentState, layers: entry.layers, activeLayerId: entry.activeLayerId },
  }
}

import type { CanvasState, DrawingMeta } from './types'

const DATA_DIR = 'data/drawings'

const ensureDir = async () => {
  const dir = Bun.file(`${DATA_DIR}/.keep`)
  if (!(await dir.exists())) {
    await Bun.write(dir, '')
  }
}

export const saveDrawing = async (
  id: string,
  name: string,
  state: CanvasState,
  pngBase64?: string,
): Promise<DrawingMeta> => {
  await ensureDir()

  const now = new Date().toISOString()
  const metaPath = `${DATA_DIR}/${id}.json`
  const existingFile = Bun.file(metaPath)
  const existing = (await existingFile.exists())
    ? ((await existingFile.json()) as DrawingMeta)
    : null

  const meta: DrawingMeta = {
    id,
    name,
    createdAt: existing?.createdAt ?? now,
    updatedAt: now,
    width: state.width,
    height: state.height,
    layerCount: state.layers.length,
  }

  await Bun.write(`${DATA_DIR}/${id}.json`, JSON.stringify(meta, null, 2))
  await Bun.write(`${DATA_DIR}/${id}.state.json`, JSON.stringify(state, null, 2))

  if (pngBase64) {
    const raw = atob(pngBase64)
    const bytes = new Uint8Array(raw.length)
    for (let i = 0; i < raw.length; i++) {
      bytes[i] = raw.charCodeAt(i)
    }
    await Bun.write(`${DATA_DIR}/${id}.png`, bytes)
  }

  return meta
}

export const loadDrawing = async (
  id: string,
): Promise<{ meta: DrawingMeta; state: CanvasState } | null> => {
  const metaFile = Bun.file(`${DATA_DIR}/${id}.json`)
  const stateFile = Bun.file(`${DATA_DIR}/${id}.state.json`)

  if (!(await metaFile.exists()) || !(await stateFile.exists())) return null

  const meta = (await metaFile.json()) as DrawingMeta
  const state = (await stateFile.json()) as CanvasState
  return { meta, state }
}

export const listDrawings = async (): Promise<DrawingMeta[]> => {
  await ensureDir()
  const glob = new Bun.Glob(`${DATA_DIR}/*.json`)
  const results: DrawingMeta[] = []

  for await (const path of glob.scan('.')) {
    if (path.endsWith('.state.json')) continue
    if (path.endsWith('.keep')) continue
    const file = Bun.file(path)
    const meta = (await file.json()) as DrawingMeta
    results.push(meta)
  }

  return results.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const metaFile = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await metaFile.exists())) return false

  const { unlink } = await import('node:fs/promises')
  const paths = [`${DATA_DIR}/${id}.json`, `${DATA_DIR}/${id}.state.json`, `${DATA_DIR}/${id}.png`]

  for (const p of paths) {
    try {
      await unlink(p)
    } catch {
      // file may not exist
    }
  }
  return true
}

