export const renderPage = (toolbarHtml: string, layersPanelHtml: string, width: number, height: number) => `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Drawing Canvas</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #1a1a1a; color: #eee; overflow: hidden; height: 100vh; display: flex; flex-direction: column; }
  #canvas-area { flex: 1; display: flex; overflow: hidden; }
  #canvas-container { flex: 1; display: flex; align-items: center; justify-content: center; overflow: auto; background: #333; background-image: repeating-conic-gradient(#3a3a3a 0% 25%, transparent 0% 50%) 50% / 20px 20px; }
  canvas { cursor: crosshair; box-shadow: 0 4px 20px rgba(0,0,0,0.5); }
  button:hover { opacity: 0.85; }
</style>
</head>
<body>
${toolbarHtml}
<div id="canvas-area">
  <div id="canvas-container">
    <canvas id="drawing-canvas" width="${width}" height="${height}"></canvas>
  </div>
  ${layersPanelHtml}
</div>
<input type="file" id="file-input" accept=".png,image/png" style="display:none;">
<script>
${getClientScript()}
</script>
</body>
</html>`

const getClientScript = () => `
(function() {
  const canvas = document.getElementById('drawing-canvas');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  let currentTool = 'brush';
  let currentColor = '#ffffff';
  let brushSize = 4;
  let isDrawing = false;
  let currentPoints = [];
  let shapeStart = null;

  // Layer & history state
  let layers = [{ id: 'layer-1', name: 'Layer 1', visible: true, actions: [] }];
  let activeLayerId = 'layer-1';
  let history = { past: [], future: [] };
  const MAX_HISTORY = 50;

  // Off-screen canvases for compositing
  const createOffscreen = () => {
    const c = document.createElement('canvas');
    c.width = W;
    c.height = H;
    return c;
  };

  const pushHistory = () => {
    const snapshot = JSON.parse(JSON.stringify(layers));
    history.past.push({ layers: snapshot, activeLayerId });
    if (history.past.length > MAX_HISTORY) history.past.shift();
    history.future = [];
  };

  const getActiveLayer = () => layers.find(l => l.id === activeLayerId);

  const drawAction = (tctx, action) => {
    tctx.lineCap = 'round';
    tctx.lineJoin = 'round';

    if (action.tool === 'eraser') {
      tctx.globalCompositeOperation = 'destination-out';
      tctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      tctx.globalCompositeOperation = 'source-over';
      tctx.strokeStyle = action.color;
    }
    tctx.lineWidth = action.size;

    if (action.start && action.end) {
      tctx.beginPath();
      if (action.tool === 'rectangle') {
        const x = Math.min(action.start.x, action.end.x);
        const y = Math.min(action.start.y, action.end.y);
        const w = Math.abs(action.end.x - action.start.x);
        const h = Math.abs(action.end.y - action.start.y);
        tctx.strokeRect(x, y, w, h);
      } else if (action.tool === 'circle') {
        const cx = (action.start.x + action.end.x) / 2;
        const cy = (action.start.y + action.end.y) / 2;
        const rx = Math.abs(action.end.x - action.start.x) / 2;
        const ry = Math.abs(action.end.y - action.start.y) / 2;
        tctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
        tctx.stroke();
      } else if (action.tool === 'line') {
        tctx.moveTo(action.start.x, action.start.y);
        tctx.lineTo(action.end.x, action.end.y);
        tctx.stroke();
      }
    } else if (action.points && action.points.length > 0) {
      tctx.beginPath();
      tctx.moveTo(action.points[0].x, action.points[0].y);
      for (let i = 1; i < action.points.length; i++) {
        tctx.lineTo(action.points[i].x, action.points[i].y);
      }
      if (action.points.length === 1) {
        tctx.lineTo(action.points[0].x + 0.1, action.points[0].y + 0.1);
      }
      tctx.stroke();
    }
    tctx.globalCompositeOperation = 'source-over';
  };

  const renderLayers = () => {
    ctx.clearRect(0, 0, W, H);
    // Fill with white background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, W, H);

    for (const layer of layers) {
      if (!layer.visible) continue;
      const off = createOffscreen();
      const octx = off.getContext('2d');
      for (const action of layer.actions) {
        drawAction(octx, action);
      }
      ctx.drawImage(off, 0, 0);
    }
    updateLayerThumbnails();
  };

  const updateLayerThumbnails = () => {
    for (const layer of layers) {
      const el = document.querySelector('[data-layer-id="' + layer.id + '"]');
      if (!el) continue;
      const off = createOffscreen();
      const octx = off.getContext('2d');
      octx.fillStyle = '#111';
      octx.fillRect(0, 0, W, H);
      for (const action of layer.actions) {
        drawAction(octx, action);
      }
      const thumbW = el.clientWidth * 2;
      const thumbH = el.clientHeight * 2;
      const thumbCanvas = document.createElement('canvas');
      thumbCanvas.width = thumbW;
      thumbCanvas.height = thumbH;
      const tctx = thumbCanvas.getContext('2d');
      tctx.drawImage(off, 0, 0, thumbW, thumbH);
      el.style.backgroundImage = 'url(' + thumbCanvas.toDataURL() + ')';
      el.style.backgroundSize = 'cover';
    }
  };

  const getPos = (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
  };

  const isShapeTool = () => ['rectangle', 'circle', 'line'].includes(currentTool);

  // Event handlers
  canvas.addEventListener('pointerdown', (e) => {
    e.preventDefault();
    canvas.setPointerCapture(e.pointerId);
    isDrawing = true;
    const pos = getPos(e);
    if (isShapeTool()) {
      shapeStart = pos;
    } else {
      currentPoints = [pos];
    }
    pushHistory();
  });

  canvas.addEventListener('pointermove', (e) => {
    if (!isDrawing) return;
    e.preventDefault();
    const pos = getPos(e);
    if (isShapeTool()) {
      // Preview shape
      renderLayers();
      const previewCtx = ctx;
      previewCtx.strokeStyle = currentTool === 'eraser' ? '#999' : currentColor;
      previewCtx.lineWidth = brushSize;
      previewCtx.lineCap = 'round';
      previewCtx.lineJoin = 'round';
      previewCtx.setLineDash([5, 5]);
      previewCtx.beginPath();
      if (currentTool === 'rectangle') {
        const x = Math.min(shapeStart.x, pos.x);
        const y = Math.min(shapeStart.y, pos.y);
        previewCtx.strokeRect(x, y, Math.abs(pos.x - shapeStart.x), Math.abs(pos.y - shapeStart.y));
      } else if (currentTool === 'circle') {
        const cx = (shapeStart.x + pos.x) / 2;
        const cy = (shapeStart.y + pos.y) / 2;
        const rx = Math.abs(pos.x - shapeStart.x) / 2;
        const ry = Math.abs(pos.y - shapeStart.y) / 2;
        previewCtx.ellipse(cx, cy, rx || 1, ry || 1, 0, 0, Math.PI * 2);
        previewCtx.stroke();
      } else if (currentTool === 'line') {
        previewCtx.moveTo(shapeStart.x, shapeStart.y);
        previewCtx.lineTo(pos.x, pos.y);
        previewCtx.stroke();
      }
      previewCtx.setLineDash([]);
    } else {
      currentPoints.push(pos);
      // Draw live stroke
      const layer = getActiveLayer();
      if (layer && layer.visible) {
        renderLayers();
        drawAction(ctx, { tool: currentTool, color: currentColor, size: brushSize, points: currentPoints });
      }
    }
  });

  const finishDrawing = () => {
    if (!isDrawing) return;
    isDrawing = false;
    const layer = getActiveLayer();
    if (!layer || !layer.visible) return;

    if (isShapeTool() && shapeStart) {
      const pos = currentPoints.length > 0 ? currentPoints[currentPoints.length - 1] : shapeStart;
      layer.actions.push({
        tool: currentTool,
        color: currentColor,
        size: brushSize,
        start: shapeStart,
        end: pos,
      });
      shapeStart = null;
    } else if (currentPoints.length > 0) {
      layer.actions.push({
        tool: currentTool,
        color: currentColor,
        size: brushSize,
        points: [...currentPoints],
      });
    }
    currentPoints = [];
    renderLayers();
  };

  canvas.addEventListener('pointerup', (e) => {
    if (isShapeTool() && shapeStart) {
      const pos = getPos(e);
      const layer = getActiveLayer();
      if (layer && layer.visible) {
        layer.actions.push({
          tool: currentTool,
          color: currentColor,
          size: brushSize,
          start: shapeStart,
          end: pos,
        });
      }
      isDrawing = false;
      shapeStart = null;
      renderLayers();
    } else {
      finishDrawing();
    }
  });

  canvas.addEventListener('pointerleave', finishDrawing);

  // Toolbar events via delegation
  document.addEventListener('click', (e) => {
    const btn = e.target.closest('[p-trigger]');
    if (!btn) return;
    const trigger = btn.getAttribute('p-trigger');

    if (trigger.startsWith('tool-select:')) {
      currentTool = trigger.split(':')[1];
      updateToolbarUI();
    } else if (trigger === 'undo') {
      if (history.past.length > 0) {
        const snapshot = history.past.pop();
        history.future.unshift({ layers: JSON.parse(JSON.stringify(layers)), activeLayerId });
        layers = snapshot.layers;
        activeLayerId = snapshot.activeLayerId;
        renderLayers();
        updateLayersPanelUI();
      }
    } else if (trigger === 'redo') {
      if (history.future.length > 0) {
        const snapshot = history.future.shift();
        history.past.push({ layers: JSON.parse(JSON.stringify(layers)), activeLayerId });
        layers = snapshot.layers;
        activeLayerId = snapshot.activeLayerId;
        renderLayers();
        updateLayersPanelUI();
      }
    } else if (trigger === 'clear') {
      pushHistory();
      const layer = getActiveLayer();
      if (layer) layer.actions = [];
      renderLayers();
    } else if (trigger === 'save') {
      saveAsPNG();
    } else if (trigger === 'load') {
      document.getElementById('file-input').click();
    } else if (trigger === 'add-layer') {
      pushHistory();
      const id = 'layer-' + Date.now();
      layers.push({ id, name: 'Layer ' + (layers.length + 1), visible: true, actions: [] });
      activeLayerId = id;
      renderLayers();
      updateLayersPanelUI();
    } else if (trigger.startsWith('select-layer:')) {
      activeLayerId = trigger.split(':')[1];
      updateLayersPanelUI();
    } else if (trigger.startsWith('toggle-visibility:')) {
      const lid = trigger.split(':')[1];
      const layer = layers.find(l => l.id === lid);
      if (layer) layer.visible = !layer.visible;
      renderLayers();
      updateLayersPanelUI();
    } else if (trigger.startsWith('remove-layer:')) {
      if (layers.length <= 1) return;
      pushHistory();
      const lid = trigger.split(':')[1];
      layers = layers.filter(l => l.id !== lid);
      if (activeLayerId === lid) activeLayerId = layers[layers.length - 1].id;
      renderLayers();
      updateLayersPanelUI();
    } else if (trigger === 'move-layer-up') {
      const idx = layers.findIndex(l => l.id === activeLayerId);
      if (idx < layers.length - 1) {
        pushHistory();
        [layers[idx], layers[idx + 1]] = [layers[idx + 1], layers[idx]];
        renderLayers();
        updateLayersPanelUI();
      }
    } else if (trigger === 'move-layer-down') {
      const idx = layers.findIndex(l => l.id === activeLayerId);
      if (idx > 0) {
        pushHistory();
        [layers[idx], layers[idx - 1]] = [layers[idx - 1], layers[idx]];
        renderLayers();
        updateLayersPanelUI();
      }
    }
  });

  document.addEventListener('input', (e) => {
    const trigger = e.target.getAttribute('p-trigger');
    if (trigger === 'color-change') {
      currentColor = e.target.value;
    } else if (trigger === 'size-change') {
      brushSize = parseInt(e.target.value, 10);
      document.querySelector('[p-trigger="size-change"]').parentElement.childNodes[0].textContent = 'Size: ' + brushSize;
    }
  });

  // File input for load
  document.getElementById('file-input').addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const img = new Image();
    img.onload = () => {
      pushHistory();
      const layer = getActiveLayer();
      if (!layer) return;
      // Create temp canvas to draw image
      const off = createOffscreen();
      const octx = off.getContext('2d');
      octx.drawImage(img, 0, 0, W, H);
      // We store the loaded image as a special action
      layer.actions.push({
        tool: 'brush',
        color: '#000',
        size: 1,
        points: [],
        _imageData: off.toDataURL(),
      });
      renderLayers();
    };
    img.src = URL.createObjectURL(file);
    e.target.value = '';
  });

  // Override drawAction to handle _imageData
  const origDrawAction = drawAction;

  const saveAsPNG = () => {
    const link = document.createElement('a');
    link.download = 'drawing-' + Date.now() + '.png';
    link.href = canvas.toDataURL('image/png');
    link.click();

    // Also save to server
    const pngData = canvas.toDataURL('image/png').split(',')[1];
    fetch('/api/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        id: 'drawing-' + Date.now(),
        name: 'Drawing',
        state: { layers, activeLayerId, width: W, height: H },
        png: pngData,
      }),
    }).catch(() => {});
  };

  const updateToolbarUI = () => {
    document.querySelectorAll('#toolbar button[p-trigger^="tool-select:"]').forEach(btn => {
      const tool = btn.getAttribute('p-trigger').split(':')[1];
      btn.style.border = '1px solid ' + (tool === currentTool ? '#4a9eff' : '#555');
      btn.style.background = tool === currentTool ? '#1a3a5c' : '#333';
    });
  };

  const updateLayersPanelUI = () => {
    const panel = document.getElementById('layer-list');
    if (!panel) return;
    panel.innerHTML = '';
    [...layers].reverse().forEach(layer => {
      const div = document.createElement('div');
      div.setAttribute('p-trigger', 'select-layer:' + layer.id);
      div.style.cssText = 'display:flex;align-items:center;gap:6px;padding:8px;cursor:pointer;border-bottom:1px solid #333;background:' + (activeLayerId === layer.id ? '#1a3a5c' : 'transparent') + ';';

      const visBtn = document.createElement('button');
      visBtn.setAttribute('p-trigger', 'toggle-visibility:' + layer.id);
      visBtn.style.cssText = 'width:20px;height:20px;border:1px solid #555;border-radius:3px;cursor:pointer;font-size:10px;background:' + (layer.visible ? '#4a9eff' : '#333') + ';color:#fff;display:flex;align-items:center;justify-content:center;padding:0;';
      visBtn.title = layer.visible ? 'Hide layer' : 'Show layer';
      visBtn.textContent = layer.visible ? '\\u2713' : '';
      div.appendChild(visBtn);

      const thumb = document.createElement('div');
      thumb.className = 'layer-thumb';
      thumb.setAttribute('data-layer-id', layer.id);
      thumb.style.cssText = 'width:40px;height:30px;background:#111;border:1px solid #555;border-radius:2px;overflow:hidden;';
      div.appendChild(thumb);

      const name = document.createElement('span');
      name.style.cssText = 'color:#ccc;font-size:12px;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
      name.textContent = layer.name;
      div.appendChild(name);

      if (layers.length > 1) {
        const removeBtn = document.createElement('button');
        removeBtn.setAttribute('p-trigger', 'remove-layer:' + layer.id);
        removeBtn.style.cssText = 'width:18px;height:18px;background:#533;color:#eaa;border:1px solid #744;border-radius:3px;cursor:pointer;font-size:10px;display:flex;align-items:center;justify-content:center;padding:0;';
        removeBtn.title = 'Remove layer';
        removeBtn.textContent = '\\u00d7';
        div.appendChild(removeBtn);
      }

      panel.appendChild(div);
    });
    updateLayerThumbnails();
  };

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z' && !e.shiftKey) {
        e.preventDefault();
        document.querySelector('[p-trigger="undo"]')?.click();
      } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
        e.preventDefault();
        document.querySelector('[p-trigger="redo"]')?.click();
      } else if (e.key === 's') {
        e.preventDefault();
        saveAsPNG();
      }
    }
  });

  // Initial render
  renderLayers();
})();
`

import { h } from 'plaited'
import { renderToolbar, renderLayersPanel, renderPage } from './renderer'
import { saveDrawing, loadDrawing, listDrawings, deleteDrawing } from './storage'
import type { CanvasState } from './types'

const WIDTH = 800
const HEIGHT = 600

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (url.pathname === '/' || url.pathname === '') {
    const toolbarHtml = renderToolbar('brush', '#ffffff', 4)
    const layersPanelHtml = renderLayersPanel(
      [{ id: 'layer-1', name: 'Layer 1', visible: true }],
      'layer-1',
    )
    const html = renderPage(
      String(toolbarHtml),
      String(layersPanelHtml),
      WIDTH,
      HEIGHT,
    )
    return new Response(html, { headers: { 'Content-Type': 'text/html' } })
  }

  if (url.pathname === '/api/save' && req.method === 'POST') {
    const body = (await req.json()) as {
      id: string
      name: string
      state: CanvasState
      png?: string
    }
    const meta = await saveDrawing(body.id, body.name, body.state, body.png)
    return Response.json(meta)
  }

  if (url.pathname === '/api/load' && req.method === 'GET') {
    const id = url.searchParams.get('id')
    if (!id) return Response.json({ error: 'Missing id' }, { status: 400 })
    const result = await loadDrawing(id)
    if (!result) return Response.json({ error: 'Not found' }, { status: 404 })
    return Response.json(result)
  }

  if (url.pathname === '/api/drawings' && req.method === 'GET') {
    const drawings = await listDrawings()
    return Response.json(drawings)
  }

  if (url.pathname === '/api/delete' && req.method === 'DELETE') {
    const id = url.searchParams.get('id')
    if (!id) return Response.json({ error: 'Missing id' }, { status: 400 })
    const ok = await deleteDrawing(id)
    return Response.json({ ok })
  }

  return new Response('Not found', { status: 404 })
}

const server = Bun.serve({
  port: 3000,
  fetch: handleRequest,
})

console.log(`Drawing Canvas running at http://localhost:${server.port}`)

