export type Song = {
  id: string
  title: string
  artist: string
  album: string
  durationSeconds: number
  artUrl: string
}

export type Playlist = {
  id: string
  name: string
  description: string
  createdAt: string
  songs: Song[]
}

export type RepeatMode = 'none' | 'all' | 'one'

export type ShuffleState = {
  enabled: boolean
  shuffledIndices: number[]
}

export type PlaybackState = {
  playlistId: string | null
  songIndex: number
  isPlaying: boolean
  progressSeconds: number
  repeat: RepeatMode
  shuffle: ShuffleState
}

export type AddSongInput = {
  title: string
  artist: string
  album?: string
  durationSeconds?: number
  artUrl?: string
}

export type CreatePlaylistInput = {
  name: string
  description?: string
}

export type ReorderInput = {
  playlistId: string
  fromIndex: number
  toIndex: number
}

import type { Playlist, Song, PlaybackState, AddSongInput, CreatePlaylistInput, RepeatMode } from './types'

const DATA_PATH = 'data/playlists.json'

const generateId = (): string => crypto.randomUUID()

// ─── Playlist persistence ────────────────────────────────────────

export const loadPlaylists = async (): Promise<Playlist[]> => {
  try {
    return await Bun.file(DATA_PATH).json()
  } catch {
    return []
  }
}

export const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const playlists = await loadPlaylists()
  return playlists.find((p) => p.id === id)
}

export const createPlaylist = async (input: CreatePlaylistInput): Promise<Playlist> => {
  const playlists = await loadPlaylists()
  const playlist: Playlist = {
    id: generateId(),
    name: input.name,
    description: input.description ?? '',
    createdAt: new Date().toISOString(),
    songs: [],
  }
  playlists.push(playlist)
  await savePlaylists(playlists)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const idx = playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  playlists.splice(idx, 1)
  await savePlaylists(playlists)
  return true
}

export const renamePlaylist = async (id: string, name: string): Promise<Playlist | undefined> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === id)
  if (!playlist) return undefined
  playlist.name = name
  await savePlaylists(playlists)
  return playlist
}

// ─── Song CRUD ───────────────────────────────────────────────────

export const addSong = async (playlistId: string, input: AddSongInput): Promise<Song | undefined> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return undefined
  const song: Song = {
    id: generateId(),
    title: input.title,
    artist: input.artist,
    album: input.album ?? '',
    durationSeconds: input.durationSeconds ?? 0,
    artUrl: input.artUrl ?? '',
  }
  playlist.songs.push(song)
  await savePlaylists(playlists)
  return song
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  await savePlaylists(playlists)
  return true
}

export const reorderSong = async (playlistId: string, fromIndex: number, toIndex: number): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  await savePlaylists(playlists)
  return true
}

// ─── Playback state (in-memory, not persisted) ──────────────────

let playback: PlaybackState = {
  playlistId: null,
  songIndex: 0,
  isPlaying: false,
  progressSeconds: 0,
  repeat: 'none',
  shuffle: { enabled: false, shuffledIndices: [] },
}

export const getPlaybackState = (): PlaybackState => ({ ...playback })

export const startPlayback = async (playlistId: string, songIndex: number): Promise<PlaybackState> => {
  const playlist = await getPlaylist(playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) return playback
  playback = {
    playlistId,
    songIndex,
    isPlaying: true,
    progressSeconds: 0,
    repeat: playback.repeat,
    shuffle: playback.shuffle,
  }
  return { ...playback }
}

export const togglePlay = (): PlaybackState => {
  playback.isPlaying = !playback.isPlaying
  return { ...playback }
}

export const seekTo = (seconds: number): PlaybackState => {
  playback.progressSeconds = Math.max(0, seconds)
  return { ...playback }
}

const buildShuffleIndices = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const toggleShuffle = async (): Promise<PlaybackState> => {
  playback.shuffle.enabled = !playback.shuffle.enabled
  if (playback.shuffle.enabled && playback.playlistId) {
    const playlist = await getPlaylist(playback.playlistId)
    if (playlist) {
      playback.shuffle.shuffledIndices = buildShuffleIndices(playlist.songs.length, playback.songIndex)
    }
  } else {
    playback.shuffle.shuffledIndices = []
  }
  return { ...playback }
}

export const cycleRepeat = (): PlaybackState => {
  const modes: RepeatMode[] = ['none', 'all', 'one']
  const idx = modes.indexOf(playback.repeat)
  playback.repeat = modes[(idx + 1) % modes.length]
  return { ...playback }
}

const resolveNextIndex = (playlist: Playlist, direction: 1 | -1): number | null => {
  const count = playlist.songs.length
  if (count === 0) return null

  if (playback.repeat === 'one') return playback.songIndex

  if (playback.shuffle.enabled) {
    const shuffled = playback.shuffle.shuffledIndices
    const pos = shuffled.indexOf(playback.songIndex)
    const nextPos = pos + direction
    if (nextPos >= 0 && nextPos < shuffled.length) return shuffled[nextPos]
    if (playback.repeat === 'all') return direction === 1 ? shuffled[0] : shuffled[shuffled.length - 1]
    return null
  }

  const next = playback.songIndex + direction
  if (next >= 0 && next < count) return next
  if (playback.repeat === 'all') return direction === 1 ? 0 : count - 1
  return null
}

export const skipNext = async (): Promise<PlaybackState> => {
  if (!playback.playlistId) return playback
  const playlist = await getPlaylist(playback.playlistId)
  if (!playlist) return playback
  const next = resolveNextIndex(playlist, 1)
  if (next !== null) {
    playback.songIndex = next
    playback.progressSeconds = 0
  } else {
    playback.isPlaying = false
    playback.progressSeconds = 0
  }
  return { ...playback }
}

export const skipPrevious = async (): Promise<PlaybackState> => {
  if (!playback.playlistId) return playback
  // If more than 3 seconds in, restart current song
  if (playback.progressSeconds > 3) {
    playback.progressSeconds = 0
    return { ...playback }
  }
  const playlist = await getPlaylist(playback.playlistId)
  if (!playlist) return playback
  const prev = resolveNextIndex(playlist, -1)
  if (prev !== null) {
    playback.songIndex = prev
    playback.progressSeconds = 0
  }
  return { ...playback }
}

