import type { Song, AddSongInput, CreatePlaylistInput, ReorderInput } from './types'
import {
  loadPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  addSong,
  removeSong,
  reorderSong,
  getPlaybackState,
  startPlayback,
  togglePlay,
  seekTo,
  toggleShuffle,
  cycleRepeat,
  skipNext,
  skipPrevious,
} from './store'
import { renderPlaylistList, renderPlaylistDetail } from './render'

// ─── Resolve the currently-playing song ──────────────────────────

const getNowPlayingSong = async (): Promise<Song | null> => {
  const pb = getPlaybackState()
  if (!pb.playlistId) return null
  const pl = await getPlaylist(pb.playlistId)
  if (!pl || pb.songIndex < 0 || pb.songIndex >= pl.songs.length) return null
  return pl.songs[pb.songIndex]
}

// ─── Route handlers ──────────────────────────────────────────────

export const handleListPlaylists = async (): Promise<string> => {
  const playlists = await loadPlaylists()
  const pb = getPlaybackState()
  const nowSong = await getNowPlayingSong()
  return renderPlaylistList(playlists, pb, nowSong)
}

export const handleViewPlaylist = async (playlistId: string): Promise<string | null> => {
  const playlist = await getPlaylist(playlistId)
  if (!playlist) return null
  const pb = getPlaybackState()
  const nowSong = await getNowPlayingSong()
  return renderPlaylistDetail(playlist, pb, nowSong)
}

export const handleCreatePlaylist = async (input: CreatePlaylistInput): Promise<{ id: string }> => {
  const pl = await createPlaylist(input)
  return { id: pl.id }
}

export const handleDeletePlaylist = async (playlistId: string): Promise<boolean> => {
  return deletePlaylist(playlistId)
}

export const handleRenamePlaylist = async (playlistId: string, name: string): Promise<boolean> => {
  const result = await renamePlaylist(playlistId, name)
  return result !== undefined
}

export const handleAddSong = async (playlistId: string, input: AddSongInput): Promise<{ id: string } | null> => {
  const song = await addSong(playlistId, input)
  if (!song) return null
  return { id: song.id }
}

export const handleRemoveSong = async (playlistId: string, songId: string): Promise<boolean> => {
  return removeSong(playlistId, songId)
}

export const handleReorderSong = async (input: ReorderInput): Promise<boolean> => {
  return reorderSong(input.playlistId, input.fromIndex, input.toIndex)
}

// ─── Playback handlers ──────────────────────────────────────────

export const handlePlaySong = async (playlistId: string, songIndex: number) => {
  return startPlayback(playlistId, songIndex)
}

export const handleTogglePlay = () => togglePlay()

export const handleSeek = (seconds: number) => seekTo(seconds)

export const handleSkipNext = () => skipNext()

export const handleSkipPrevious = () => skipPrevious()

export const handleToggleShuffle = () => toggleShuffle()

export const handleCycleRepeat = () => cycleRepeat()

export const handleGetPlayback = () => getPlaybackState()

// ─── Server ──────────────────────────────────────────────────────

const parseBody = async (req: Request): Promise<Record<string, unknown>> => {
  try {
    return (await req.json()) as Record<string, unknown>
  } catch {
    return {}
  }
}

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const notFound = () => json({ error: 'Not found' }, 404)

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // ── HTML views ─────────────────────────────────────────────
  if (method === 'GET' && pathname === '/') {
    return htmlResponse(await handleListPlaylists())
  }

  if (method === 'GET' && pathname.startsWith('/playlist/')) {
    const id = pathname.split('/')[2]
    const html = await handleViewPlaylist(id)
    return html ? htmlResponse(html) : notFound()
  }

  // ── Playlist API ───────────────────────────────────────────
  if (method === 'GET' && pathname === '/api/playlists') {
    return json(await loadPlaylists())
  }

  if (method === 'POST' && pathname === '/api/playlists') {
    const body = await parseBody(req)
    const result = await handleCreatePlaylist(body as CreatePlaylistInput)
    return json(result, 201)
  }

  if (method === 'DELETE' && pathname.startsWith('/api/playlists/')) {
    const id = pathname.split('/')[3]
    const ok = await handleDeletePlaylist(id)
    return ok ? json({ ok: true }) : notFound()
  }

  if (method === 'PATCH' && pathname.startsWith('/api/playlists/') && pathname.endsWith('/rename')) {
    const id = pathname.split('/')[3]
    const body = await parseBody(req)
    const ok = await handleRenamePlaylist(id, body.name as string)
    return ok ? json({ ok: true }) : notFound()
  }

  // ── Song API ───────────────────────────────────────────────
  if (method === 'POST' && pathname.match(/^\/api\/playlists\/[^/]+\/songs$/)) {
    const playlistId = pathname.split('/')[3]
    const body = await parseBody(req)
    const result = await handleAddSong(playlistId, body as AddSongInput)
    return result ? json(result, 201) : notFound()
  }

  if (method === 'DELETE' && pathname.match(/^\/api\/playlists\/[^/]+\/songs\/[^/]+$/)) {
    const parts = pathname.split('/')
    const playlistId = parts[3]
    const songId = parts[5]
    const ok = await handleRemoveSong(playlistId, songId)
    return ok ? json({ ok: true }) : notFound()
  }

  if (method === 'POST' && pathname.match(/^\/api\/playlists\/[^/]+\/reorder$/)) {
    const playlistId = pathname.split('/')[3]
    const body = await parseBody(req)
    const ok = await handleReorderSong({
      playlistId,
      fromIndex: body.fromIndex as number,
      toIndex: body.toIndex as number,
    })
    return ok ? json({ ok: true }) : json({ error: 'Invalid reorder' }, 400)
  }

  // ── Playback API ───────────────────────────────────────────
  if (method === 'GET' && pathname === '/api/playback') {
    return json(handleGetPlayback())
  }

  if (method === 'POST' && pathname === '/api/playback/play') {
    const body = await parseBody(req)
    const state = await handlePlaySong(body.playlistId as string, body.songIndex as number)
    return json(state)
  }

  if (method === 'POST' && pathname === '/api/playback/toggle') {
    return json(handleTogglePlay())
  }

  if (method === 'POST' && pathname === '/api/playback/seek') {
    const body = await parseBody(req)
    return json(handleSeek(body.seconds as number))
  }

  if (method === 'POST' && pathname === '/api/playback/next') {
    return json(await handleSkipNext())
  }

  if (method === 'POST' && pathname === '/api/playback/previous') {
    return json(await handleSkipPrevious())
  }

  if (method === 'POST' && pathname === '/api/playback/shuffle') {
    return json(await handleToggleShuffle())
  }

  if (method === 'POST' && pathname === '/api/playback/repeat') {
    return json(handleCycleRepeat())
  }

  return notFound()
}

const PORT = Number(Bun.env.PORT ?? 3000)

Bun.serve({
  port: PORT,
  fetch: router,
})

