/**
 * Client-side interactivity for the playlist manager.
 * This script is served as inline <script> or loaded by the SSR pages.
 * It handles drag-to-reorder, playback controls, and form submissions
 * by calling the JSON API and re-rendering affected sections.
 */

export const clientScript = `
<script>
(function() {
  // ─── State ───────────────────────────────────────────────
  let dragSrcIndex = null;
  let progressTimer = null;
  let currentPlayback = null;

  // ─── API helpers ─────────────────────────────────────────
  const api = (method, path, body) =>
    fetch(path, {
      method,
      headers: body ? { 'Content-Type': 'application/json' } : {},
      body: body ? JSON.stringify(body) : undefined,
    }).then(r => r.json());

  const reload = () => window.location.reload();

  // ─── Drag and drop ──────────────────────────────────────
  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('[data-index]');
    if (!row) return;
    dragSrcIndex = parseInt(row.dataset.index, 10);
    e.dataTransfer.effectAllowed = 'move';
    row.style.opacity = '0.5';
  });

  document.addEventListener('dragend', (e) => {
    const row = e.target.closest('[data-index]');
    if (row) row.style.opacity = '1';
    dragSrcIndex = null;
  });

  document.addEventListener('dragover', (e) => {
    const row = e.target.closest('[data-index]');
    if (!row) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  });

  document.addEventListener('drop', async (e) => {
    const row = e.target.closest('[data-index]');
    if (!row || dragSrcIndex === null) return;
    e.preventDefault();
    const toIndex = parseInt(row.dataset.index, 10);
    const playlistId = row.dataset.playlistId;
    if (dragSrcIndex === toIndex) return;
    await api('POST', '/api/playlists/' + playlistId + '/reorder', {
      fromIndex: dragSrcIndex,
      toIndex: toIndex,
    });
    reload();
  });

  // ─── Event delegation for buttons ──────────────────────
  document.addEventListener('click', async (e) => {
    const btn = e.target.closest('button, [data-playlist-id]');
    if (!btn) return;

    const trigger = btn.getAttribute('p-trigger');
    if (!trigger) {
      // Playlist card click
      const id = btn.dataset.playlistId;
      if (id && !btn.closest('button')) {
        window.location.href = '/playlist/' + id;
      }
      return;
    }

    let parsed;
    try { parsed = JSON.parse(trigger); } catch { return; }
    const action = parsed.click;
    if (!action) return;

    e.preventDefault();
    e.stopPropagation();

    switch (action) {
      case 'showCreatePlaylist': {
        const form = document.querySelector('[p-target="createPlaylistForm"]');
        if (form) form.style.display = form.style.display === 'none' ? 'block' : 'none';
        break;
      }
      case 'openPlaylist': {
        const id = btn.dataset.playlistId || btn.closest('[data-playlist-id]')?.dataset.playlistId;
        if (id) window.location.href = '/playlist/' + id;
        break;
      }
      case 'backToPlaylists':
        window.location.href = '/';
        break;
      case 'playSong': {
        const pid = btn.dataset.playlistId;
        const idx = parseInt(btn.dataset.songIndex, 10);
        await api('POST', '/api/playback/play', { playlistId: pid, songIndex: idx });
        reload();
        break;
      }
      case 'playAll': {
        const pid = btn.dataset.playlistId;
        await api('POST', '/api/playback/play', { playlistId: pid, songIndex: 0 });
        reload();
        break;
      }
      case 'removeSong': {
        const pid = btn.dataset.playlistId;
        const sid = btn.dataset.songId;
        await api('DELETE', '/api/playlists/' + pid + '/songs/' + sid);
        reload();
        break;
      }
      case 'deletePlaylist': {
        const pid = btn.dataset.playlistId;
        if (confirm('Delete this playlist?')) {
          await api('DELETE', '/api/playlists/' + pid);
          window.location.href = '/';
        }
        break;
      }
      case 'togglePlay':
        await api('POST', '/api/playback/toggle');
        reload();
        break;
      case 'skipNext':
        await api('POST', '/api/playback/next');
        reload();
        break;
      case 'skipPrevious':
        await api('POST', '/api/playback/previous');
        reload();
        break;
      case 'toggleShuffle':
        await api('POST', '/api/playback/shuffle');
        reload();
        break;
      case 'cycleRepeat':
        await api('POST', '/api/playback/repeat');
        reload();
        break;
    }
  });

  // ─── Progress bar seek ─────────────────────────────────
  document.addEventListener('click', async (e) => {
    const bar = e.target.closest('[p-target="progressBar"]');
    if (!bar) return;
    const rect = bar.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    // Get current song duration from the time display
    const timeLabels = bar.parentElement.querySelectorAll('span');
    if (timeLabels.length >= 2) {
      const durationText = timeLabels[timeLabels.length - 1].textContent;
      const parts = durationText.split(':');
      const totalSec = parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
      const seekSec = Math.floor(pct * totalSec);
      await api('POST', '/api/playback/seek', { seconds: seekSec });
      reload();
    }
  });

  // ─── Form submissions ─────────────────────────────────
  document.addEventListener('submit', async (e) => {
    const form = e.target.closest('form');
    if (!form) return;

    const trigger = form.getAttribute('p-trigger');
    if (!trigger) return;

    let parsed;
    try { parsed = JSON.parse(trigger); } catch { return; }
    const action = parsed.submit;
    if (!action) return;

    e.preventDefault();
    const fd = new FormData(form);

    switch (action) {
      case 'createPlaylist': {
        await api('POST', '/api/playlists', {
          name: fd.get('name'),
          description: fd.get('description') || '',
        });
        reload();
        break;
      }
      case 'addSong': {
        const pid = form.dataset.playlistId;
        await api('POST', '/api/playlists/' + pid + '/songs', {
          title: fd.get('title'),
          artist: fd.get('artist'),
          album: fd.get('album') || '',
          durationSeconds: parseInt(fd.get('duration'), 10) || 0,
          artUrl: fd.get('artUrl') || '',
        });
        reload();
        break;
      }
    }
  });

  // ─── Simulated playback progress ──────────────────────
  const startProgressSimulation = async () => {
    const res = await fetch('/api/playback');
    currentPlayback = await res.json();
    if (!currentPlayback.isPlaying) return;

    progressTimer = setInterval(async () => {
      if (!currentPlayback || !currentPlayback.isPlaying) {
        clearInterval(progressTimer);
        return;
      }
      currentPlayback.progressSeconds += 1;
      await api('POST', '/api/playback/seek', { seconds: currentPlayback.progressSeconds });

      // Update progress bar visually without reload
      const barOuter = document.querySelector('[p-target="progressBar"]');
      if (barOuter) {
        const timeLabels = barOuter.parentElement.querySelectorAll('span');
        if (timeLabels.length >= 2) {
          const durationText = timeLabels[timeLabels.length - 1].textContent;
          const parts = durationText.split(':');
          const totalSec = parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
          const pct = Math.min((currentPlayback.progressSeconds / totalSec) * 100, 100);
          const barInner = barOuter.firstElementChild;
          if (barInner) barInner.style.width = pct + '%';
          // Update current time label
          const curMin = Math.floor(currentPlayback.progressSeconds / 60);
          const curSec = currentPlayback.progressSeconds % 60;
          timeLabels[0].textContent = curMin + ':' + String(curSec).padStart(2, '0');

          // Auto-advance when song ends
          if (currentPlayback.progressSeconds >= totalSec) {
            clearInterval(progressTimer);
            await api('POST', '/api/playback/next');
            reload();
          }
        }
      }
    }, 1000);
  };

  startProgressSimulation();
})();
</script>
`

