input.content:
{
  "name": "@node/physics-simulator",
  "version": "1.0.0",
  "description": "Interactive Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "main": "server.ts",
  "modnet": {
    "contentType": "science",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

{
  "pendulum": {
    "length": 2.0,
    "gravity": 9.81,
    "initialAngle": 0.785
  },
  "projectile": {
    "angle": 45,
    "velocity": 20,
    "gravity": 9.81
  },
  "spring": {
    "springConstant": 10,
    "mass": 1.0,
    "initialDisplacement": 1.0
  }
}

type Vec2 = { x: number; y: number };

type PendulumState = {
  L: number;
  g: number;
  theta: number;
  omega: number;
  trail: Vec2[];
};

type ProjectileState = {
  angle: number;
  v0: number;
  g: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  trail: Vec2[];
  launched: boolean;
  done: boolean;
};

type SpringState = {
  k: number;
  m: number;
  x: number;
  v: number;
  trail: number[];
};

type SimState = {
  pendulum: PendulumState;
  projectile: ProjectileState;
  spring: SpringState;
};

export type { Vec2, PendulumState, ProjectileState, SpringState, SimState };

export const clientScript = `
(() => {
  var $ = function(s) { return document.querySelector(s); };
  var $$ = function(s) { return document.querySelectorAll(s); };

  var active = 'pendulum';
  var playing = false;
  var speed = 1;
  var lastTs = 0;
  var accumulator = 0;
  var FIXED_DT = 0.004;

  var sims = {
    pendulum: { L: 2, g: 9.81, theta: Math.PI / 4, omega: 0, trail: [] },
    projectile: {
      angle: 45, v0: 20, g: 9.81,
      x: 0, y: 0, vx: 0, vy: 0,
      trail: [], launched: false, done: false
    },
    spring: { k: 10, m: 1, x: 1, v: 0, trail: [] }
  };

  var canvas = $('#sim-canvas');
  var ctx = canvas.getContext('2d');
  var dpr = window.devicePixelRatio || 1;
  canvas.width = 700 * dpr;
  canvas.height = 450 * dpr;
  canvas.style.width = '700px';
  canvas.style.height = '450px';
  ctx.scale(dpr, dpr);
  var W = 700;
  var H = 450;

  /* ===== PHYSICS ===== */

  var stepPendulum = function(s, dt) {
    var alpha = -(s.g / s.L) * Math.sin(s.theta);
    s.omega += alpha * dt;
    s.theta += s.omega * dt;
  };

  var stepProjectile = function(s, dt) {
    if (!s.launched || s.done) return;
    s.vy -= s.g * dt;
    s.x += s.vx * dt;
    s.y += s.vy * dt;
    s.trail.push({ x: s.x, y: s.y });
    if (s.y < 0 && s.trail.length > 1) {
      s.y = 0;
      s.done = true;
    }
  };

  var stepSpring = function(s, dt) {
    var a = -(s.k / s.m) * s.x;
    s.v += a * dt;
    s.x += s.v * dt;
  };

  /* ===== RENDERING ===== */

  var clear = function() {
    ctx.fillStyle = '#0d1117';
    ctx.fillRect(0, 0, W, H);
  };

  var drawPendulum = function(s) {
    clear();
    var px = W / 2, py = 50;
    var scale = Math.min(100, (H - 100) / s.L);
    var bx = px + s.L * scale * Math.sin(s.theta);
    var by = py + s.L * scale * Math.cos(s.theta);

    s.trail.push({ x: bx, y: by });
    if (s.trail.length > 400) s.trail.shift();

    for (var i = 0; i < s.trail.length; i++) {
      var a = (i / s.trail.length) * 0.4;
      ctx.fillStyle = 'rgba(99,179,237,' + a + ')';
      ctx.beginPath();
      ctx.arc(s.trail[i].x, s.trail[i].y, 1.5, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.strokeStyle = '#30363d';
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(px - 50, py);
    ctx.lineTo(px + 50, py);
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(px, py);
    ctx.lineTo(bx, by);
    ctx.strokeStyle = '#8b949e';
    ctx.lineWidth = 2;
    ctx.stroke();

    if (Math.abs(s.theta) > 0.02) {
      ctx.beginPath();
      var sa = Math.PI / 2;
      var ea = Math.PI / 2 - s.theta;
      ctx.arc(px, py, 35, Math.min(sa, ea), Math.max(sa, ea));
      ctx.strokeStyle = '#f0883e';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.fillStyle = '#f0883e';
      ctx.font = '11px monospace';
      var deg = (Math.abs(s.theta) * 180 / Math.PI).toFixed(1);
      ctx.fillText(deg + '\\u00B0', px + 40, py + 18);
    }

    var grad = ctx.createRadialGradient(bx - 4, by - 4, 2, bx, by, 18);
    grad.addColorStop(0, '#79c0ff');
    grad.addColorStop(1, '#388bfd');
    ctx.beginPath();
    ctx.arc(bx, by, 18, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
    ctx.strokeStyle = '#58a6ff';
    ctx.lineWidth = 1.5;
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(px, py, 5, 0, Math.PI * 2);
    ctx.fillStyle = '#8b949e';
    ctx.fill();

    ctx.fillStyle = '#8b949e';
    ctx.font = '12px monospace';
    ctx.fillText('L = ' + s.L.toFixed(1) + ' m', 14, 25);
    ctx.fillText('g = ' + s.g.toFixed(1) + ' m/s\\u00B2', 14, 42);
  };

  var drawProjectile = function(s) {
    clear();
    var rad = s.angle * Math.PI / 180;
    var maxR = Math.max((s.v0 * s.v0 * Math.sin(2 * rad)) / s.g, 10);
    var maxH = Math.max((s.v0 * s.v0 * Math.pow(Math.sin(rad), 2)) / (2 * s.g), 5);
    var sx = (W - 110) / maxR;
    var sy = (H - 90) / maxH;
    var scale = Math.min(sx, sy);
    var ox = 65, oy = H - 40;

    ctx.strokeStyle = '#161b22';
    ctx.lineWidth = 0.5;
    var gStep = Math.pow(10, Math.floor(Math.log10(Math.max(maxR, 1) / 4)));
    if (gStep < 1) gStep = 1;
    for (var gx = 0; gx <= maxR * 1.1; gx += gStep) {
      var x = ox + gx * scale;
      if (x > W - 10) break;
      ctx.beginPath();
      ctx.moveTo(x, oy);
      ctx.lineTo(x, 20);
      ctx.stroke();
      ctx.fillStyle = '#30363d';
      ctx.font = '10px monospace';
      ctx.fillText(gx.toFixed(0) + 'm', x - 8, oy + 15);
    }
    for (var gy = 0; gy <= maxH * 1.1; gy += gStep) {
      var y = oy - gy * scale;
      if (y < 10) break;
      ctx.beginPath();
      ctx.moveTo(ox, y);
      ctx.lineTo(W - 10, y);
      ctx.stroke();
      if (gy > 0) {
        ctx.fillStyle = '#30363d';
        ctx.font = '10px monospace';
        ctx.fillText(gy.toFixed(0) + 'm', 10, y + 4);
      }
    }

    ctx.strokeStyle = '#30363d';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(ox - 15, oy);
    ctx.lineTo(W - 10, oy);
    ctx.stroke();

    ctx.setLineDash([4, 4]);
    ctx.strokeStyle = '#1c2128';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    var tTotal = 2 * s.v0 * Math.sin(rad) / s.g;
    for (var t = 0; t <= tTotal; t += tTotal / 120) {
      var tx = s.v0 * Math.cos(rad) * t;
      var ty = s.v0 * Math.sin(rad) * t - 0.5 * s.g * t * t;
      var cx = ox + tx * scale;
      var cy = oy - ty * scale;
      if (t === 0) ctx.moveTo(cx, cy);
      else ctx.lineTo(cx, cy);
    }
    ctx.stroke();
    ctx.setLineDash([]);

    if (s.trail.length > 1) {
      ctx.beginPath();
      ctx.moveTo(ox + s.trail[0].x * scale, oy - s.trail[0].y * scale);
      for (var i = 1; i < s.trail.length; i++) {
        ctx.lineTo(ox + s.trail[i].x * scale, oy - s.trail[i].y * scale);
      }
      ctx.strokeStyle = '#3fb950';
      ctx.lineWidth = 2.5;
      ctx.stroke();

      var dotStep = Math.max(1, Math.floor(s.trail.length / 35));
      for (var i = 0; i < s.trail.length; i += dotStep) {
        ctx.beginPath();
        ctx.arc(ox + s.trail[i].x * scale, oy - s.trail[i].y * scale, 2.5, 0, Math.PI * 2);
        ctx.fillStyle = '#3fb950';
        ctx.fill();
      }
    }

    var cx = ox + s.x * scale;
    var cy = oy - Math.max(0, s.y) * scale;
    var grad = ctx.createRadialGradient(cx - 2, cy - 2, 1, cx, cy, 9);
    grad.addColorStop(0, '#56d364');
    grad.addColorStop(1, '#238636');
    ctx.beginPath();
    ctx.arc(cx, cy, 9, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();

    if (s.launched && !s.done) {
      var vScale = 3;
      var vLen = Math.sqrt(s.vx * s.vx + s.vy * s.vy);
      if (vLen > 0.5) {
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.lineTo(cx + s.vx * vScale, cy - s.vy * vScale);
        ctx.strokeStyle = '#f0883e';
        ctx.lineWidth = 2;
        ctx.stroke();
        var arrowAngle = Math.atan2(-s.vy, s.vx);
        var ax = cx + s.vx * vScale;
        var ay = cy - s.vy * vScale;
        ctx.beginPath();
        ctx.moveTo(ax, ay);
        ctx.lineTo(ax - 10 * Math.cos(arrowAngle - 0.4), ay + 10 * Math.sin(arrowAngle - 0.4));
        ctx.lineTo(ax - 10 * Math.cos(arrowAngle + 0.4), ay + 10 * Math.sin(arrowAngle + 0.4));
        ctx.closePath();
        ctx.fillStyle = '#f0883e';
        ctx.fill();
      }
    }

    if (!s.launched) {
      var len = 55;
      ctx.beginPath();
      ctx.moveTo(ox, oy);
      ctx.lineTo(ox + len * Math.cos(rad), oy - len * Math.sin(rad));
      ctx.strokeStyle = '#f0883e';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.beginPath();
      ctx.arc(ox, oy, 28, -rad, 0);
      ctx.strokeStyle = '#f0883e';
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    ctx.fillStyle = '#8b949e';
    ctx.font = '12px monospace';
    ctx.fillText('\\u03B8 = ' + s.angle + '\\u00B0', 14, 25);
    ctx.fillText('v\\u2080 = ' + s.v0 + ' m/s', 14, 42);
  };

  var drawSpring = function(s) {
    clear();
    var wallX = 55;
    var eqX = 350;
    var cy = 190;
    var scale = 100;
    var massX = eqX + s.x * scale;

    ctx.strokeStyle = '#30363d';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(wallX - 20, cy + 35);
    ctx.lineTo(W - 20, cy + 35);
    ctx.stroke();

    ctx.fillStyle = '#21262d';
    ctx.fillRect(wallX - 18, cy - 75, 18, 150);
    for (var i = 0; i < 8; i++) {
      ctx.beginPath();
      ctx.moveTo(wallX - 18, cy - 65 + i * 20);
      ctx.lineTo(wallX, cy - 55 + i * 20);
      ctx.strokeStyle = '#30363d';
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    ctx.setLineDash([6, 4]);
    ctx.strokeStyle = '#484f58';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(eqX, cy - 55);
    ctx.lineTo(eqX, cy + 55);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.fillStyle = '#484f58';
    ctx.font = '10px monospace';
    ctx.fillText('equilibrium', eqX - 32, cy - 60);

    var springStart = wallX;
    var springEnd = massX - 25;
    var numCoils = 18;
    var coilW = (springEnd - springStart - 20) / (numCoils * 2);
    var amp = 14;
    var strain = Math.abs(s.x);
    var r = Math.min(255, Math.floor(100 + strain * 155));
    var g = Math.max(80, Math.floor(200 - strain * 120));

    ctx.beginPath();
    ctx.moveTo(springStart, cy);
    ctx.lineTo(springStart + 10, cy);
    var coilStart = springStart + 10;
    for (var i = 0; i < numCoils * 2; i++) {
      var x = coilStart + (i + 1) * coilW;
      var y = (i % 2 === 0) ? cy - amp : cy + amp;
      ctx.lineTo(x, y);
    }
    ctx.lineTo(springEnd - 10, cy);
    ctx.lineTo(springEnd, cy);
    ctx.strokeStyle = 'rgb(' + r + ',' + g + ',120)';
    ctx.lineWidth = 2.5;
    ctx.stroke();

    var blockW = 50, blockH = 50;
    var bx = massX - blockW / 2;
    var by = cy - blockH / 2;
    ctx.fillStyle = '#da3633';
    ctx.fillRect(bx, by, blockW, blockH);
    ctx.strokeStyle = '#f85149';
    ctx.lineWidth = 1.5;
    ctx.strokeRect(bx, by, blockW, blockH);
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 14px monospace';
    ctx.fillText('m', massX - 5, cy + 5);

    var force = -(s.k) * s.x;
    if (Math.abs(force) > 0.5) {
      var fScale = 0.4;
      var fx = force * fScale;
      ctx.beginPath();
      ctx.moveTo(massX, cy - 45);
      ctx.lineTo(massX + fx, cy - 45);
      ctx.strokeStyle = '#f0883e';
      ctx.lineWidth = 2;
      ctx.stroke();
      var dir = force > 0 ? 1 : -1;
      ctx.beginPath();
      ctx.moveTo(massX + fx, cy - 45);
      ctx.lineTo(massX + fx - dir * 8, cy - 51);
      ctx.lineTo(massX + fx - dir * 8, cy - 39);
      ctx.closePath();
      ctx.fillStyle = '#f0883e';
      ctx.fill();
      ctx.fillStyle = '#f0883e';
      ctx.font = '11px monospace';
      ctx.fillText('F = ' + force.toFixed(1) + ' N', massX + fx * 0.3 - 20, cy - 54);
    }

    s.trail.push(s.x);
    if (s.trail.length > 400) s.trail.shift();

    var graphTop = 300;
    var graphH = 120;
    var graphLeft = 55;
    var graphRight = W - 25;

    ctx.fillStyle = '#0d1117';
    ctx.fillRect(graphLeft, graphTop, graphRight - graphLeft, graphH);
    ctx.strokeStyle = '#21262d';
    ctx.lineWidth = 1;
    ctx.strokeRect(graphLeft, graphTop, graphRight - graphLeft, graphH);

    ctx.setLineDash([3, 3]);
    ctx.strokeStyle = '#30363d';
    ctx.beginPath();
    ctx.moveTo(graphLeft, graphTop + graphH / 2);
    ctx.lineTo(graphRight, graphTop + graphH / 2);
    ctx.stroke();
    ctx.setLineDash([]);

    if (s.trail.length > 1) {
      var maxDisp = 2.5;
      ctx.beginPath();
      for (var i = 0; i < s.trail.length; i++) {
        var gxp = graphLeft + (i / 400) * (graphRight - graphLeft);
        var gyp = graphTop + graphH / 2 - (s.trail[i] / maxDisp) * (graphH / 2);
        if (i === 0) ctx.moveTo(gxp, gyp);
        else ctx.lineTo(gxp, gyp);
      }
      ctx.strokeStyle = '#f85149';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    }

    ctx.fillStyle = '#484f58';
    ctx.font = '10px monospace';
    ctx.fillText('x(t)', graphLeft + 4, graphTop + 13);
    ctx.fillText('+x', graphLeft + 4, graphTop + 25);
    ctx.fillText('-x', graphLeft + 4, graphTop + graphH - 5);

    ctx.fillStyle = '#8b949e';
    ctx.font = '12px monospace';
    ctx.fillText('k = ' + s.k + ' N/m', 14, 25);
    ctx.fillText('m = ' + s.m.toFixed(1) + ' kg', 14, 42);
  };

  /* ===== VALUES ===== */

  var updateValues = function() {
    var s = sims[active];
    var pos, vel, accel;

    if (active === 'pendulum') {
      pos = s.theta.toFixed(3) + ' rad';
      vel = (s.L * s.omega).toFixed(3) + ' m/s';
      accel = (-(s.g) * Math.sin(s.theta)).toFixed(3) + ' m/s\\u00B2';
    } else if (active === 'projectile') {
      pos = '(' + s.x.toFixed(2) + ', ' + s.y.toFixed(2) + ') m';
      vel = '(' + s.vx.toFixed(2) + ', ' + s.vy.toFixed(2) + ') m/s';
      accel = '(0.00, -' + s.g.toFixed(2) + ') m/s\\u00B2';
    } else {
      pos = s.x.toFixed(3) + ' m';
      vel = s.v.toFixed(3) + ' m/s';
      accel = (-(s.k / s.m) * s.x).toFixed(3) + ' m/s\\u00B2';
    }

    $('#val-pos').textContent = pos;
    $('#val-vel').textContent = vel;
    $('#val-acc').textContent = accel;
  };

  /* ===== LOOP ===== */

  var physicsStep = function(dt) {
    if (active === 'pendulum') stepPendulum(sims.pendulum, dt);
    else if (active === 'projectile') stepProjectile(sims.projectile, dt);
    else stepSpring(sims.spring, dt);
  };

  var render = function() {
    if (active === 'pendulum') drawPendulum(sims.pendulum);
    else if (active === 'projectile') drawProjectile(sims.projectile);
    else drawSpring(sims.spring);
    updateValues();
  };

  var animate = function(ts) {
    if (!lastTs) lastTs = ts;
    var frame = Math.min((ts - lastTs) / 1000, 0.05);
    lastTs = ts;

    if (playing) {
      accumulator += frame * speed;
      var maxSteps = 20;
      var steps = 0;
      while (accumulator >= FIXED_DT && steps < maxSteps) {
        physicsStep(FIXED_DT);
        accumulator -= FIXED_DT;
        steps++;
      }
      if (steps >= maxSteps) accumulator = 0;
    }

    render();
    requestAnimationFrame(animate);
  };

  /* ===== RESET ===== */

  var resetSim = function(name) {
    if (name === 'pendulum') {
      var s = sims.pendulum;
      s.theta = Math.PI / 4;
      s.omega = 0;
      s.trail = [];
    } else if (name === 'projectile') {
      var s = sims.projectile;
      s.x = 0; s.y = 0;
      s.vx = 0; s.vy = 0;
      s.trail = [];
      s.launched = false;
      s.done = false;
    } else {
      var s = sims.spring;
      s.x = 1;
      s.v = 0;
      s.trail = [];
    }
  };

  /* ===== EVENTS ===== */

  $$('[data-tab]').forEach(function(btn) {
    btn.addEventListener('click', function() {
      $$('[data-tab]').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      active = btn.dataset.tab;
      $$('.params').forEach(function(p) { p.style.display = 'none'; });
      $('#params-' + active).style.display = 'flex';
      accumulator = 0;
      render();
    });
  });

  $('#btn-play').addEventListener('click', function() {
    if (active === 'projectile' && !sims.projectile.launched) {
      var s = sims.projectile;
      var rad = s.angle * Math.PI / 180;
      s.vx = s.v0 * Math.cos(rad);
      s.vy = s.v0 * Math.sin(rad);
      s.launched = true;
      s.done = false;
    }
    playing = true;
    $('#btn-play').classList.add('on');
    $('#btn-pause').classList.remove('on');
  });

  $('#btn-pause').addEventListener('click', function() {
    playing = false;
    $('#btn-play').classList.remove('on');
    $('#btn-pause').classList.add('on');
  });

  $('#btn-reset').addEventListener('click', function() {
    playing = false;
    $('#btn-play').classList.remove('on');
    $('#btn-pause').classList.remove('on');
    resetSim(active);
    accumulator = 0;
    lastTs = 0;
    render();
  });

  $('#speed-slider').addEventListener('input', function(e) {
    speed = parseFloat(e.target.value);
    $('#speed-val').textContent = speed.toFixed(1) + 'x';
  });

  $('#pendulum-length').addEventListener('input', function(e) {
    sims.pendulum.L = parseFloat(e.target.value);
    $('#pendulum-length-val').textContent = sims.pendulum.L.toFixed(1) + ' m';
  });
  $('#pendulum-gravity').addEventListener('input', function(e) {
    sims.pendulum.g = parseFloat(e.target.value);
    $('#pendulum-gravity-val').textContent = sims.pendulum.g.toFixed(1) + ' m/s\\u00B2';
  });

  $('#projectile-angle').addEventListener('input', function(e) {
    sims.projectile.angle = parseInt(e.target.value);
    $('#projectile-angle-val').textContent = sims.projectile.angle + '\\u00B0';
    resetSim('projectile');
    render();
  });
  $('#projectile-velocity').addEventListener('input', function(e) {
    sims.projectile.v0 = parseInt(e.target.value);
    $('#projectile-velocity-val').textContent = sims.projectile.v0 + ' m/s';
    resetSim('projectile');
    render();
  });

  $('#spring-k').addEventListener('input', function(e) {
    sims.spring.k = parseFloat(e.target.value);
    $('#spring-k-val').textContent = sims.spring.k + ' N/m';
  });
  $('#spring-mass').addEventListener('input', function(e) {
    sims.spring.m = parseFloat(e.target.value);
    $('#spring-mass-val').textContent = sims.spring.m.toFixed(1) + ' kg';
  });

  /* ===== INIT ===== */

  render();
  requestAnimationFrame(animate);
})();
`;

