const clientScript = `
  const elementsData = JSON.parse(document.getElementById('elements-data').textContent);
  const overlay = document.getElementById('detail-overlay');
  const panel = document.getElementById('detail-panel');
  const searchInput = document.getElementById('search-input');
  const categorySelect = document.getElementById('category-filter');
  const cells = document.querySelectorAll('.element-cell');

  const categoryLabels = {
    'alkali-metal': 'Alkali Metal',
    'alkaline-earth-metal': 'Alkaline Earth Metal',
    'transition-metal': 'Transition Metal',
    'post-transition-metal': 'Post-transition Metal',
    'metalloid': 'Metalloid',
    'nonmetal': 'Nonmetal',
    'noble-gas': 'Noble Gas',
    'lanthanide': 'Lanthanide',
    'actinide': 'Actinide',
    'unknown': 'Unknown'
  };

  const showDetail = (el) => {
    const catColors = JSON.parse(document.getElementById('category-colors').textContent);
    const color = catColors[el.category]?.color || '#e8e8e8';
    panel.innerHTML = \`
      <button class="close-btn" onclick="closeDetail()">&times;</button>
      <div class="el-header">
        <div class="el-symbol-box" style="background:\${color}">\${el.symbol}</div>
        <div class="el-title">
          <div class="el-name">\${el.name}</div>
          <div class="el-number">Atomic Number \${el.atomicNumber} &middot; \${el.atomicMass} u</div>
          <div class="el-category">\${categoryLabels[el.category] || el.category}</div>
        </div>
      </div>
      <div class="props">
        <div class="prop full-width">
          <div class="prop-label">Electron Configuration</div>
          <div class="prop-value">\${el.electronConfiguration}</div>
        </div>
        <div class="prop">
          <div class="prop-label">Oxidation States</div>
          <div class="prop-value">\${el.oxidationStates}</div>
        </div>
        <div class="prop">
          <div class="prop-label">Discovery Year</div>
          <div class="prop-value">\${el.discoveryYear != null ? el.discoveryYear : 'Ancient'}</div>
        </div>
        <div class="prop">
          <div class="prop-label">Melting Point</div>
          <div class="prop-value">\${el.meltingPoint != null ? el.meltingPoint + ' °C' : 'N/A'}</div>
        </div>
        <div class="prop">
          <div class="prop-label">Boiling Point</div>
          <div class="prop-value">\${el.boilingPoint != null ? el.boilingPoint + ' °C' : 'N/A'}</div>
        </div>
      </div>
      <div class="el-description">\${el.description}</div>
    \`;
    overlay.classList.add('open');
  };

  const closeDetail = () => {
    overlay.classList.remove('open');
  };
  window.closeDetail = closeDetail;

  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) closeDetail();
  });

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeDetail();
  });

  cells.forEach((cell) => {
    cell.addEventListener('click', () => {
      const num = parseInt(cell.dataset.number, 10);
      const el = elementsData.find((e) => e.atomicNumber === num);
      if (el) showDetail(el);
    });
  });

  const applyFilters = () => {
    const query = searchInput.value.toLowerCase().trim();
    const cat = categorySelect.value;

    cells.forEach((cell) => {
      const name = cell.dataset.name.toLowerCase();
      const symbol = cell.dataset.symbol.toLowerCase();
      const cellCat = cell.dataset.category;

      const matchesSearch = !query || name.includes(query) || symbol.includes(query);
      const matchesCategory = cat === 'all' || cellCat === cat;

      cell.classList.toggle('hidden', !matchesSearch);
      cell.classList.toggle('dimmed', matchesSearch && !matchesCategory);
    });
  };

  searchInput.addEventListener('input', applyFilters);
  categorySelect.addEventListener('change', applyFilters);
`

const renderElementCell = (el: Element): string => {
