const loadElements = async (): Promise<Element[]> => {
  const data = await Bun.file('data/elements.json').json()
  return data as Element[]
}

const serve = async () => {
  const elements = await loadElements()
  const html = renderPage(elements)

  Bun.serve({
    port: 3000,
    fetch: (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/index.html') {
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/elements') {
        return new Response(JSON.stringify(elements), {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      if (url.pathname.startsWith('/api/elements/')) {
        const num = parseInt(url.pathname.split('/').pop() ?? '', 10)
        const el = elements.find((e) => e.atomicNumber === num)
        if (el) {
          return new Response(JSON.stringify(el), {
            headers: { 'Content-Type': 'application/json' },
          })
        }
        return new Response('Not found', { status: 404 })
      }

      return new Response('Not found', { status: 404 })
    },
  })

  console.log('Periodic Table Explorer running at http://localhost:3000')
}

