export type DatasetStats = {
  name: string
  data: number[]
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
  count: number
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const computeMean = (data: number[]): number =>
  data.reduce((sum, v) => sum + v, 0) / data.length

const computeMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const computeMode = (data: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of data) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const computeVariance = (data: number[], mean: number): number =>
  data.reduce((sum, v) => sum + (v - mean) ** 2, 0) / data.length

const computeQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !isNaN(n))
  }
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !isNaN(n))
}

export const computeStats = (name: string, data: number[]): DatasetStats => {
  if (data.length === 0) {
    return {
      name,
      data: [],
      mean: 0,
      median: 0,
      mode: [],
      stdDev: 0,
      variance: 0,
      min: 0,
      max: 0,
      range: 0,
      q1: 0,
      q3: 0,
      iqr: 0,
      count: 0,
    }
  }

  const sorted = sortAsc(data)
  const mean = computeMean(data)
  const variance = computeVariance(data, mean)
  const q1 = computeQuartile(sorted, 0.25)
  const q3 = computeQuartile(sorted, 0.75)

  return {
    name,
    data: sorted,
    mean,
    median: computeMedian(sorted),
    mode: computeMode(data),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
    count: data.length,
  }
}

const fmt = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  return n.toFixed(4).replace(/0+$/, '').replace(/\.$/, '')
}

export const formatStat = (value: number | number[]): string => {
  if (Array.isArray(value)) {
    return value.length === 0 ? 'None' : value.map(fmt).join(', ')
  }
  return fmt(value)
}

