const SVG_W = 600
const SVG_H = 200
const PAD = 40
const PLOT_W = SVG_W - PAD * 2
const PLOT_H = SVG_H - PAD * 2

const renderBoxPlot = (datasets: DatasetStats[]): string => {
  const allVals = datasets.flatMap((d) => d.data)
  if (allVals.length === 0) return ''

  const globalMin = Math.min(...allVals)
  const globalMax = Math.max(...allVals)
  const span = globalMax - globalMin || 1

  const scale = (v: number): number => PAD + ((v - globalMin) / span) * PLOT_W

  const boxH = Math.min(30, PLOT_H / datasets.length - 4)
  const totalBoxesH = datasets.length * (boxH + 4) - 4
  const startY = PAD + (PLOT_H - totalBoxesH) / 2

  const ticks = 5
  const tickEls: string[] = []
  for (let i = 0; i <= ticks; i++) {
    const val = globalMin + (span * i) / ticks
    const x = scale(val)
    tickEls.push(
      `<line x1="${x}" y1="${PAD}" x2="${x}" y2="${SVG_H - PAD + 5}" stroke="#ccc" stroke-width="1"/>`,
      `<text x="${x}" y="${SVG_H - PAD + 18}" text-anchor="middle" font-size="10" fill="#666">${val.toFixed(1)}</text>`
    )
  }

  const boxes = datasets.map((ds, i) => {
    if (ds.data.length === 0) return ''
    const y = startY + i * (boxH + 4)
    const cy = y + boxH / 2
    const color = colorFor(i)

    const x1 = scale(ds.min)
    const xQ1 = scale(ds.q1)
    const xMed = scale(ds.median)
    const xQ3 = scale(ds.q3)
    const x2 = scale(ds.max)

    return [
      // whisker line
      `<line x1="${x1}" y1="${cy}" x2="${x2}" y2="${cy}" stroke="${color}" stroke-width="1.5"/>`,
      // whisker caps
      `<line x1="${x1}" y1="${y + 4}" x2="${x1}" y2="${y + boxH - 4}" stroke="${color}" stroke-width="1.5"/>`,
      `<line x1="${x2}" y1="${y + 4}" x2="${x2}" y2="${y + boxH - 4}" stroke="${color}" stroke-width="1.5"/>`,
      // box
      `<rect x="${xQ1}" y="${y}" width="${xQ3 - xQ1}" height="${boxH}" fill="${color}" fill-opacity="0.25" stroke="${color}" stroke-width="1.5" rx="2"/>`,
      // median
      `<line x1="${xMed}" y1="${y}" x2="${xMed}" y2="${y + boxH}" stroke="${color}" stroke-width="2.5"/>`,
      // label
      `<text x="${PAD - 6}" y="${cy + 4}" text-anchor="end" font-size="11" font-weight="600" fill="${color}">${ds.name}</text>`,
    ].join('\n')
  })

  return `<svg viewBox="0 0 ${SVG_W} ${SVG_H}" width="${SVG_W}" style="max-width:100%;height:auto;background:#fafafa;border-radius:8px;margin:8px 0">
    <text x="${SVG_W / 2}" y="16" text-anchor="middle" font-size="13" font-weight="700" fill="#333">Box Plot</text>
    ${tickEls.join('\n')}
    ${boxes.join('\n')}
  </svg>`
}

const renderHistogram = (ds: DatasetStats, idx: number): string => {
  if (ds.data.length === 0) return ''

  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(ds.data.length))))
  const span = ds.max - ds.min || 1
  const binWidth = span / binCount
  const bins: number[] = new Array(binCount).fill(0)

  for (const v of ds.data) {
    let b = Math.floor((v - ds.min) / binWidth)
    if (b >= binCount) b = binCount - 1
    bins[b]++
  }

  const maxBin = Math.max(...bins)
  const color = colorFor(idx)
  const barW = PLOT_W / binCount

  const bars = bins.map((count, i) => {
    const barH = maxBin > 0 ? (count / maxBin) * PLOT_H : 0
    const x = PAD + i * barW
    const y = PAD + PLOT_H - barH
    return `<rect x="${x}" y="${y}" width="${barW - 1}" height="${barH}" fill="${color}" fill-opacity="0.6" stroke="${color}" stroke-width="0.5" rx="1"/>
    <text x="${x + barW / 2}" y="${y - 3}" text-anchor="middle" font-size="9" fill="#555">${count > 0 ? count : ''}</text>`
  })

  const xTicks: string[] = []
  const tickStep = Math.max(1, Math.floor(binCount / 6))
  for (let i = 0; i <= binCount; i += tickStep) {
    const val = ds.min + i * binWidth
    const x = PAD + i * barW
    xTicks.push(
      `<text x="${x}" y="${SVG_H - PAD + 15}" text-anchor="middle" font-size="9" fill="#666">${val.toFixed(1)}</text>`
    )
  }

  return `<svg viewBox="0 0 ${SVG_W} ${SVG_H}" width="${SVG_W}" style="max-width:100%;height:auto;background:#fafafa;border-radius:8px;margin:8px 0">
    <text x="${SVG_W / 2}" y="16" text-anchor="middle" font-size="13" font-weight="700" fill="#333">Histogram — ${ds.name}</text>
    <line x1="${PAD}" y1="${PAD + PLOT_H}" x2="${PAD + PLOT_W}" y2="${PAD + PLOT_H}" stroke="#999" stroke-width="1"/>
    <line x1="${PAD}" y1="${PAD}" x2="${PAD}" y2="${PAD + PLOT_H}" stroke="#999" stroke-width="1"/>
    ${bars.join('\n')}
    ${xTicks.join('\n')}
  </svg>`
}

