import { parseInput, computeStats, type DatasetStats } from './stats.ts'
import { renderPage } from './render.ts'

const DATA_PATH = 'data/datasets.json'

type StoredDataset = {
  name: string
  data: number[]
}

const loadDatasets = async (): Promise<DatasetStats[]> => {
  try {
    const file = Bun.file(DATA_PATH)
    if (await file.exists()) {
      const stored = (await file.json()) as StoredDataset[]
      return stored.map((s) => computeStats(s.name, s.data))
    }
  } catch {
    // ignore corrupt file
  }
  return []
}

const saveDatasets = async (datasets: DatasetStats[]): Promise<void> => {
  const stored: StoredDataset[] = datasets.map((d) => ({ name: d.name, data: d.data }))
  await Bun.write(DATA_PATH, JSON.stringify(stored, null, 2))
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/clear') {
      await saveDatasets([])
      return new Response(null, { status: 303, headers: { Location: '/' } })
    }

    if (req.method === 'POST' && url.pathname === '/add') {
      const form = await req.formData()
      const name = (form.get('name') as string)?.trim()
      const raw = (form.get('data') as string)?.trim()

      if (!name || !raw) {
        const datasets = await loadDatasets()
        return new Response(renderPage(datasets, 'Please provide both a name and data.'), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      let parsed: number[]
      try {
        parsed = parseInput(raw)
      } catch {
        const datasets = await loadDatasets()
        return new Response(renderPage(datasets, 'Could not parse data. Use comma-separated numbers or a JSON array.'), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (parsed.length === 0) {
        const datasets = await loadDatasets()
        return new Response(renderPage(datasets, 'No valid numbers found in input.'), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      const datasets = await loadDatasets()
      const existing = datasets.findIndex((d) => d.name === name)
      const newStats = computeStats(name, parsed)

      if (existing >= 0) {
        datasets[existing] = newStats
      } else {
        datasets.push(newStats)
      }

      await saveDatasets(datasets)
      return new Response(null, { status: 303, headers: { Location: '/' } })
    }

    // GET /
    const datasets = await loadDatasets()
    return new Response(renderPage(datasets), {
      headers: { 'Content-Type': 'text/html' },
    })
  },
})

console.log(`Statistics Calculator running at http://localhost:${server.port}`)

