export type Ingredient = {
  amount: number;
  unit: string;
  name: string;
};

export type Recipe = {
  id: string;
  title: string;
  ingredients: Ingredient[];
  steps: string[];
  tags: string[];
  prepTime: number;
  cookTime: number;
  createdAt: string;
  updatedAt: string;
};

export type RecipeInput = {
  title: string;
  ingredients: Ingredient[];
  steps: string[];
  tags: string[];
  prepTime: number;
  cookTime: number;
};

export type RecipeFilter = {
  search?: string;
  tag?: string;
};

import type { Recipe, RecipeInput, RecipeFilter } from './types';

const DATA_PATH = 'data/recipes.json';

const generateId = (): string => crypto.randomUUID();

const readRecipes = async (): Promise<Recipe[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const writeRecipes = async (recipes: Recipe[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(recipes, null, 2));
};

export const getAllRecipes = async (filter?: RecipeFilter): Promise<Recipe[]> => {
  let recipes = await readRecipes();

  if (filter?.search) {
    const term = filter.search.toLowerCase();
    recipes = recipes.filter(
      (r) =>
        r.title.toLowerCase().includes(term) ||
        r.ingredients.some((i) => i.name.toLowerCase().includes(term))
    );
  }

  if (filter?.tag) {
    const tag = filter.tag.toLowerCase();
    recipes = recipes.filter((r) =>
      r.tags.some((t) => t.toLowerCase() === tag)
    );
  }

  return recipes.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  );
};

export const getRecipeById = async (id: string): Promise<Recipe | undefined> => {
  const recipes = await readRecipes();
  return recipes.find((r) => r.id === id);
};

export const createRecipe = async (input: RecipeInput): Promise<Recipe> => {
  const recipes = await readRecipes();
  const now = new Date().toISOString();
  const recipe: Recipe = {
    id: generateId(),
    ...input,
    createdAt: now,
    updatedAt: now,
  };
  recipes.push(recipe);
  await writeRecipes(recipes);
  return recipe;
};

export const updateRecipe = async (
  id: string,
  input: Partial<RecipeInput>
): Promise<Recipe | undefined> => {
  const recipes = await readRecipes();
  const index = recipes.findIndex((r) => r.id === id);
  if (index === -1) return undefined;

  recipes[index] = {
    ...recipes[index],
    ...input,
    updatedAt: new Date().toISOString(),
  };
  await writeRecipes(recipes);
  return recipes[index];
};

export const deleteRecipe = async (id: string): Promise<boolean> => {
  const recipes = await readRecipes();
  const index = recipes.findIndex((r) => r.id === id);
  if (index === -1) return false;

  recipes.splice(index, 1);
  await writeRecipes(recipes);
  return true;
};

export const getAllTags = async (): Promise<string[]> => {
  const recipes = await readRecipes();
  const tagSet = new Set<string>();
  recipes.forEach((r) => r.tags.forEach((t) => tagSet.add(t)));
  return [...tagSet].sort();
};

