import { getAllRecipes, getRecipeById, createRecipe, updateRecipe, deleteRecipe, getAllTags } from './store';
import { renderRecipeList, renderRecipeDetail, renderRecipeForm } from './render';
import type { RecipeInput, Ingredient } from './types';

const parseIngredients = (raw: string): Ingredient[] =>
  raw
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      const parts = line.split(/\s+/);
      const amount = parseFloat(parts[0]) || 0;
      const unit = parts[1] ?? '';
      const name = parts.slice(2).join(' ') || parts.slice(1).join(' ');
      return { amount, unit, name };
    });

const parseSteps = (raw: string): string[] =>
  raw
    .split('\n')
    .map((s) => s.trim())
    .filter(Boolean);

const parseTags = (form: FormData): string[] => {
  const tags = form.getAll('tags');
  return tags.map(String).filter(Boolean);
};

const parseRecipeForm = async (req: Request): Promise<RecipeInput> => {
  const form = await req.formData();
  return {
    title: String(form.get('title') ?? '').trim(),
    ingredients: parseIngredients(String(form.get('ingredients') ?? '')),
    steps: parseSteps(String(form.get('steps') ?? '')),
    tags: parseTags(form),
    prepTime: parseInt(String(form.get('prepTime') ?? '0'), 10) || 0,
    cookTime: parseInt(String(form.get('cookTime') ?? '0'), 10) || 0,
  };
};

const html = (body: string) =>
  new Response(body, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });

const redirect = (path: string) =>
  new Response(null, { status: 302, headers: { Location: path } });

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;
    const accept = req.headers.get('accept') ?? '';
    const isJSON = accept.includes('application/json') || req.headers.get('content-type')?.includes('application/json');

    // API: JSON endpoints
    if (isJSON && method === 'GET' && path === '/') {
      const search = url.searchParams.get('search') ?? undefined;
      const tag = url.searchParams.get('tag') ?? undefined;
      const recipes = await getAllRecipes({ search, tag });
      return json(recipes);
    }

    if (isJSON && method === 'POST' && path === '/') {
      const input: RecipeInput = await req.json();
      const recipe = await createRecipe(input);
      return json(recipe, 201);
    }

    if (isJSON && method === 'PUT' && path.match(/^\/[a-f0-9-]+$/)) {
      const id = path.slice(1);
      const input: Partial<RecipeInput> = await req.json();
      const recipe = await updateRecipe(id, input);
      return recipe ? json(recipe) : json({ error: 'Not found' }, 404);
    }

    if (isJSON && method === 'DELETE' && path.match(/^\/[a-f0-9-]+$/)) {
      const id = path.slice(1);
      const deleted = await deleteRecipe(id);
      return deleted ? json({ ok: true }) : json({ error: 'Not found' }, 404);
    }

    if (isJSON && method === 'GET' && path.match(/^\/[a-f0-9-]+$/)) {
      const id = path.slice(1);
      const recipe = await getRecipeById(id);
      return recipe ? json(recipe) : json({ error: 'Not found' }, 404);
    }

    // HTML: List page
    if (method === 'GET' && path === '/') {
      const search = url.searchParams.get('search') ?? undefined;
      const tag = url.searchParams.get('tag') ?? undefined;
      const [recipes, tags] = await Promise.all([
        getAllRecipes({ search, tag }),
        getAllTags(),
      ]);
      return html(renderRecipeList(recipes, tags, search, tag));
    }

    // HTML: New recipe form
    if (method === 'GET' && path === '/new') {
      return html(renderRecipeForm());
    }

    // HTML: Create recipe
    if (method === 'POST' && path === '/create') {
      const input = await parseRecipeForm(req);
      const recipe = await createRecipe(input);
      return redirect(`/${recipe.id}`);
    }

    // HTML: Edit recipe form
    if (method === 'GET' && path.startsWith('/edit/')) {
      const id = path.slice(6);
      const recipe = await getRecipeById(id);
      if (!recipe) return html('<h1>Recipe not found</h1>');
      return html(renderRecipeForm(recipe));
    }

    // HTML: Update recipe
    if (method === 'POST' && path.startsWith('/update/')) {
      const id = path.slice(8);
      const input = await parseRecipeForm(req);
      await updateRecipe(id, input);
      return redirect(`/${id}`);
    }

    // HTML: Delete recipe
    if (method === 'POST' && path.startsWith('/delete/')) {
      const id = path.slice(8);
      await deleteRecipe(id);
      return redirect('/');
    }

    // HTML: View recipe
    if (method === 'GET' && path.match(/^\/[a-f0-9-]+$/)) {
      const id = path.slice(1);
      const recipe = await getRecipeById(id);
      if (!recipe) return html('<h1>Recipe not found</h1>');
      return html(renderRecipeDetail(recipe));
    }

    return new Response('Not Found', { status: 404 });
  },
});

console.log(`Recipe Manager running at http://localhost:${server.port}`);

