import type { Habit, Completion } from './types'

const HABITS_PATH = 'data/habits.json'
const COMPLETIONS_PATH = 'data/completions.json'

export const loadHabits = async (): Promise<Habit[]> => {
  const file = Bun.file(HABITS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveHabits = async (habits: Habit[]): Promise<void> => {
  await Bun.write(HABITS_PATH, JSON.stringify(habits, null, 2))
}

export const loadCompletions = async (): Promise<Completion[]> => {
  const file = Bun.file(COMPLETIONS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveCompletions = async (completions: Completion[]): Promise<void> => {
  await Bun.write(COMPLETIONS_PATH, JSON.stringify(completions, null, 2))
}

export const addHabit = async (name: string, frequency: 'daily' | 'weekly'): Promise<Habit> => {
  const habits = await loadHabits()
  const habit: Habit = {
    id: crypto.randomUUID(),
    name,
    frequency,
    createdAt: new Date().toISOString(),
  }
  habits.push(habit)
  await saveHabits(habits)
  return habit
}

export const deleteHabit = async (id: string): Promise<void> => {
  const habits = await loadHabits()
  const filtered = habits.filter((h) => h.id !== id)
  await saveHabits(filtered)

  const completions = await loadCompletions()
  const filteredCompletions = completions.filter((c) => c.habitId !== id)
  await saveCompletions(filteredCompletions)
}

export const toggleCompletion = async (habitId: string, date: string): Promise<boolean> => {
  const completions = await loadCompletions()
  const idx = completions.findIndex((c) => c.habitId === habitId && c.date === date)

  if (idx >= 0) {
    completions.splice(idx, 1)
    await saveCompletions(completions)
    return false
  }

  completions.push({ habitId, date })
  await saveCompletions(completions)
  return true
}

export const isCompleted = (completions: Completion[], habitId: string, date: string): boolean =>
  completions.some((c) => c.habitId === habitId && c.date === date)

export const toDateString = (d: Date): string => {
  const year = d.getFullYear()
  const month = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
}

export const getToday = (): string => toDateString(new Date())

const DAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'] as const

export const getDayLabel = (d: Date): string => DAY_LABELS[d.getDay()]

export const getWeekDates = (): { date: string; dayLabel: string }[] => {
  const today = new Date()
  const dayOfWeek = today.getDay()
  // Start week on Monday: Monday=0 offset, Sunday=6 offset
  const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1
  const monday = new Date(today)
  monday.setDate(today.getDate() - mondayOffset)

  const days: { date: string; dayLabel: string }[] = []
  for (let i = 0; i < 7; i++) {
    const d = new Date(monday)
    d.setDate(monday.getDate() + i)
    days.push({
      date: toDateString(d),
      dayLabel: getDayLabel(d),
    })
  }
  return days
}

