const styleToString = (style: Record<string, string>): string =>
  Object.entries(style)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

export const renderPage = (habits: Habit[], completions: Completion[]): string => {
  const today = getToday()
  const weekDates = getWeekDates()
  const todayIdx = weekDates.findIndex((d) => d.date === today)

  const weekViews: HabitWeekView[] = habits.map((habit) => {
    const days = weekDates.map((wd, i) => ({
      date: wd.date,
      dayLabel: wd.dayLabel,
      completed: isCompleted(completions, habit.id, wd.date),
    }))

    const expectedDays = habit.frequency === 'daily'
      ? weekDates.filter((_, i) => i <= todayIdx || todayIdx === -1).length
      : 1

    const completedCount = days.filter((d) => d.completed).length

    return { habit, days, completedCount, totalExpected: expectedDays }
  })

  // Overall completion rate
  const totalCompleted = weekViews.reduce((sum, wv) => sum + wv.completedCount, 0)
  const totalExpected = weekViews.reduce((sum, wv) => sum + wv.totalExpected, 0)
  const completionRate = totalExpected > 0 ? Math.round((totalCompleted / totalExpected) * 100) : 0

  const addForm = h('form', {
    style: styleToString(styles.form),
    'p-trigger': 'addHabit:submit',
  },
    h('input', {
      type: 'text',
      name: 'habitName',
      placeholder: 'New habit name...',
      required: 'true',
      style: styleToString(styles.input),
    }),
    h('select', {
      name: 'frequency',
      style: styleToString(styles.select),
    },
      h('option', { value: 'daily' }, 'Daily'),
      h('option', { value: 'weekly' }, 'Weekly'),
    ),
    h('button', { type: 'submit', style: styleToString(styles.button) }, 'Add Habit'),
  )

  const checklist = habits.length === 0
    ? h('div', { style: styleToString(styles.emptyState) }, 'No habits yet. Add one above to get started!')
    : h('div', {},
      ...habits.map((habit) => {
        const done = isCompleted(completions, habit.id, today)
        return h('div', { style: styleToString(styles.checklistItem) },
          h('input', {
            type: 'checkbox',
            ...(done ? { checked: 'true' } : {}),
            style: styleToString(styles.checkbox),
            'p-trigger': `toggle:click`,
            'data-habit-id': habit.id,
            'data-date': today,
          }),
          h('span', { style: styleToString(done ? styles.completedName : styles.habitName) }, habit.name),
          h('span', { style: styleToString(styles.badge) }, habit.frequency),
          h('button', {
            style: styleToString(styles.deleteButton),
            'p-trigger': 'deleteHabit:click',
            'data-habit-id': habit.id,
          }, 'Delete'),
        )
      }),
    )

  const weekGridContent = habits.length === 0
    ? h('div', { style: styleToString(styles.emptyState) }, 'Add habits to see your weekly streaks.')
    : h(Fragment, {},
      // Week grid
      h('div', { style: styleToString(styles.weekGrid) },
        // Header row
        h('div', {}, ''),
        ...weekDates.map((wd) =>
          h('div', {
            style: styleToString({
              ...styles.dayHeader,
              ...(wd.date === today ? { color: '#4f46e5', fontWeight: '700' } : {}),
            }),
          }, wd.dayLabel),
        ),
        h('div', { style: styleToString(styles.dayHeader) }, ''),
        // Habit rows
        ...weekViews.flatMap((wv) => [
          h('div', {
            style: styleToString({
              fontSize: '13px',
              fontWeight: '500',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
            }),
          }, wv.habit.name),
          ...wv.days.map((day, i) => {
            const isFuture = todayIdx >= 0 && i > todayIdx
            const cellStyle = isFuture
              ? { ...styles.dayCell, ...styles.dayCellFuture }
              : day.completed
                ? { ...styles.dayCell, ...styles.dayCellCompleted }
                : { ...styles.dayCell, ...styles.dayCellMissed }

            return h('div', { style: styleToString(cellStyle) },
              day.completed ? '\u2713' : isFuture ? '\u00B7' : '\u2013',
            )
          }),
          h('div', {
            style: styleToString({
              fontSize: '12px',
              color: '#6b7280',
              paddingLeft: '8px',
            }),
          }, `${wv.completedCount}/${wv.totalExpected}`),
        ]),
      ),
      // Completion rate
      h('div', { style: styleToString(styles.percentBar) },
        h('div', { style: styleToString(styles.percentValue) }, `${completionRate}%`),
        h('div', { style: styleToString(styles.percentLabel) }, 'Weekly completion rate'),
      ),
    )

  const page = h('div', { style: styleToString(styles.container) },
    h('div', { style: styleToString(styles.header) }, 'Habit Tracker'),
    h('div', { style: styleToString(styles.subheader) }, `Today: ${formatDate(today)}`),

    addForm,

    h('div', { style: styleToString(styles.section) },
      h('div', { style: styleToString(styles.sectionTitle) }, "Today's Checklist"),
      checklist,
    ),

    h('div', { style: styleToString(styles.section) },
      h('div', { style: styleToString(styles.sectionTitle) }, 'Weekly Streaks'),
      weekGridContent,
    ),
  )

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Habit Tracker</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #fff; }
  </style>
</head>
<body>
  ${page}
</body>
</html>`
}

const formatDate = (dateStr: string): string => {
  const [year, month, day] = dateStr.split('-').map(Number)
  const d = new Date(year, month - 1, day)
  return d.toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })
}

import { loadHabits, loadCompletions, addHabit, deleteHabit, toggleCompletion } from './store'
import { renderPage } from './ui'

const parseFormData = async (req: Request): Promise<URLSearchParams> => {
  const text = await req.text()
  return new URLSearchParams(text)
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    // Serve the main page
    if (url.pathname === '/' && method === 'GET') {
      const [habits, completions] = await Promise.all([loadHabits(), loadCompletions()])
      const html = renderPage(habits, completions)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // Add a new habit
    if (url.pathname === '/habits' && method === 'POST') {
      const form = await parseFormData(req)
      const name = form.get('habitName')?.trim()
      const frequency = form.get('frequency') as 'daily' | 'weekly' | null

      if (!name) {
        return Response.redirect('/', 303)
      }

      await addHabit(name, frequency === 'weekly' ? 'weekly' : 'daily')
      return Response.redirect('/', 303)
    }

    // Toggle habit completion
    if (url.pathname === '/toggle' && method === 'POST') {
      const form = await parseFormData(req)
      const habitId = form.get('habitId')
      const date = form.get('date')

      if (habitId && date) {
        await toggleCompletion(habitId, date)
      }
      return Response.redirect('/', 303)
    }

    // Delete a habit
    if (url.pathname === '/delete' && method === 'POST') {
      const form = await parseFormData(req)
      const habitId = form.get('habitId')

      if (habitId) {
        await deleteHabit(habitId)
      }
      return Response.redirect('/', 303)
    }

    // API: list habits
    if (url.pathname === '/api/habits' && method === 'GET') {
      const habits = await loadHabits()
      return Response.json(habits)
    }

    // API: list completions
    if (url.pathname === '/api/completions' && method === 'GET') {
      const completions = await loadCompletions()
      return Response.json(completions)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Habit Tracker running at http://localhost:${server.port}`)

