const formatUsd = (n: number): string =>
  n.toLocaleString('en-US', { style: 'currency', currency: 'USD' })

const formatPercent = (n: number): string =>
  `${n >= 0 ? '+' : ''}${n.toFixed(2)}%`

const gainLossColor = (n: number): string =>
  n >= 0 ? '#16a34a' : '#dc2626'

const buildPieSlices = (entries: PortfolioEntry[]): string => {
  if (entries.length === 0) return ''

  const size = 200
  const cx = size / 2
  const cy = size / 2
  const r = 80

  // Aggregate by symbol for the pie chart
  const bySymbol = new Map<string, number>()
  for (const e of entries) {
    bySymbol.set(
      e.holding.symbol,
      (bySymbol.get(e.holding.symbol) ?? 0) + e.currentValue
    )
  }
  const totalValue = entries.reduce((s, e) => s + e.currentValue, 0)
  if (totalValue === 0) return ''

  const slices = Array.from(bySymbol.entries()).map(([symbol, value]) => ({
    symbol,
    value,
    fraction: value / totalValue,
  }))

  let currentAngle = -Math.PI / 2
  const paths: string[] = []

  slices.forEach((slice, i) => {
    const angle = slice.fraction * 2 * Math.PI
    const endAngle = currentAngle + angle
    const largeArc = angle > Math.PI ? 1 : 0
    const color = CHART_COLORS[i % CHART_COLORS.length]

    if (slices.length === 1) {
      // Full circle
      paths.push(
        `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${color}" />`
      )
    } else {
      const x1 = cx + r * Math.cos(currentAngle)
      const y1 = cy + r * Math.sin(currentAngle)
      const x2 = cx + r * Math.cos(endAngle)
      const y2 = cy + r * Math.sin(endAngle)

      paths.push(
        `<path d="M ${cx} ${cy} L ${x1.toFixed(2)} ${y1.toFixed(2)} A ${r} ${r} 0 ${largeArc} 1 ${x2.toFixed(2)} ${y2.toFixed(2)} Z" fill="${color}" stroke="#fff" stroke-width="1" />`
      )
    }

    currentAngle = endAngle
  })

  // Legend
  const legendItems = slices
    .map((slice, i) => {
      const color = CHART_COLORS[i % CHART_COLORS.length]
      const pct = (slice.fraction * 100).toFixed(1)
      return `<div style="display:flex;align-items:center;gap:6px;margin:2px 0"><div style="width:12px;height:12px;border-radius:2px;background:${color};flex-shrink:0"></div><span style="font-size:13px;color:#e2e8f0">${slice.symbol} ${pct}%</span></div>`
    })
    .join('')

  return `<div style="display:flex;align-items:center;gap:24px;flex-wrap:wrap">
    <svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">${paths.join('')}</svg>
    <div>${legendItems}</div>
  </div>`
}

