import { addHolding, removeHolding, getHoldings } from './holdings'
import { updatePrice, getPrices } from './prices'
import { getPortfolioSummary } from './portfolio'
import { renderPortfolio, renderAddForm, renderPriceUpdateForm } from './ui'

type Route =
  | { action: 'view' }
  | { action: 'add-form' }
  | { action: 'add'; symbol: string; amount: number; purchasePrice: number }
  | { action: 'remove'; id: string }
  | { action: 'update-price-form' }
  | { action: 'update-price'; symbol: string; price: number }

const handleRequest = async (route: Route): Promise<string> => {
  switch (route.action) {
    case 'view': {
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'add-form': {
      return renderAddForm()
    }

    case 'add': {
      await addHolding(route.symbol, route.amount, route.purchasePrice)
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'remove': {
      await removeHolding(route.id)
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'update-price-form': {
      const prices = await getPrices()
      return renderPriceUpdateForm(prices)
    }

    case 'update-price': {
      await updatePrice(route.symbol, route.price)
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }
  }
}

const parseArgs = (): Route => {
  const args = process.argv.slice(2)
  const action = args[0] ?? 'view'

  switch (action) {
    case 'add':
      return {
        action: 'add',
        symbol: args[1] ?? '',
        amount: parseFloat(args[2] ?? '0'),
        purchasePrice: parseFloat(args[3] ?? '0'),
      }

    case 'remove':
      return { action: 'remove', id: args[1] ?? '' }

    case 'add-form':
      return { action: 'add-form' }

    case 'update-price-form':
      return { action: 'update-price-form' }

    case 'update-price':
      return {
        action: 'update-price',
        symbol: args[1] ?? '',
        price: parseFloat(args[2] ?? '0'),
      }

    default:
      return { action: 'view' }
  }
}

const main = async () => {
  const route = parseArgs()
  const html = await handleRequest(route)
  console.log(html)
}

main()

