import type { Snippet } from './types'

const DATA_PATH = 'data/snippets.json'

export const loadSnippets = async (): Promise<Snippet[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveSnippets = async (snippets: Snippet[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(snippets, null, 2))
}

export const addSnippet = async (input: {
  title: string
  language: string
  tags: string[]
  code: string
}): Promise<Snippet> => {
  const snippets = await loadSnippets()
  const now = new Date().toISOString()
  const snippet: Snippet = {
    id: crypto.randomUUID(),
    title: input.title,
    language: input.language.toLowerCase(),
    tags: input.tags.map((t) => t.toLowerCase().trim()),
    code: input.code,
    createdAt: now,
    updatedAt: now,
  }
  snippets.unshift(snippet)
  await saveSnippets(snippets)
  return snippet
}

export const deleteSnippet = async (id: string): Promise<boolean> => {
  const snippets = await loadSnippets()
  const idx = snippets.findIndex((s) => s.id === id)
  if (idx === -1) return false
  snippets.splice(idx, 1)
  await saveSnippets(snippets)
  return true
}

export const filterSnippets = (
  snippets: Snippet[],
  language?: string,
  tag?: string,
): Snippet[] => {
  let result = snippets
  if (language) {
    const lang = language.toLowerCase()
    result = result.filter((s) => s.language === lang)
  }
  if (tag) {
    const t = tag.toLowerCase()
    result = result.filter((s) => s.tags.includes(t))
  }
  return result
}

export const getLanguages = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.map((s) => s.language))].sort()

export const getTags = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.flatMap((s) => s.tags))].sort()

import { loadSnippets, addSnippet, deleteSnippet, filterSnippets, getLanguages, getTags } from './store'
import { renderPage } from './ui'

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // GET / — render the snippet list page
    if (req.method === 'GET' && pathname === '/') {
      const all = await loadSnippets()
      const language = url.searchParams.get('language') || undefined
      const tag = url.searchParams.get('tag') || undefined
      const filtered = filterSnippets(all, language, tag)
      const languages = getLanguages(all)
      const tags = getTags(all)
      const html = renderPage(filtered, languages, tags, language, tag)
      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // POST /snippets — create a snippet (JSON or form)
    if (req.method === 'POST' && pathname === '/snippets') {
      const contentType = req.headers.get('content-type') || ''

      let title: string
      let language: string
      let tags: string[]
      let code: string

      if (contentType.includes('application/json')) {
        const body = await req.json()
        title = body.title
        language = body.language
        tags = Array.isArray(body.tags) ? body.tags : (body.tags || '').split(',').map((t: string) => t.trim()).filter(Boolean)
        code = body.code
      } else {
        const form = await req.formData()
        title = form.get('title') as string
        language = form.get('language') as string
        const rawTags = form.get('tags') as string || ''
        tags = rawTags.split(',').map((t) => t.trim()).filter(Boolean)
        code = form.get('code') as string
      }

      if (!title || !language || !code) {
        return new Response('Missing required fields: title, language, code', { status: 400 })
      }

      const snippet = await addSnippet({ title, language, tags, code })

      if (contentType.includes('application/json')) {
        return Response.json(snippet, { status: 201 })
      }
      return Response.redirect('/', 303)
    }

    // DELETE /snippets/:id — delete a snippet
    if (req.method === 'DELETE' && pathname.startsWith('/snippets/')) {
      const id = pathname.slice('/snippets/'.length)
      const deleted = await deleteSnippet(id)
      if (!deleted) return new Response('Not found', { status: 404 })
      return new Response(null, { status: 204 })
    }

    // GET /snippets — JSON API
    if (req.method === 'GET' && pathname === '/snippets') {
      const all = await loadSnippets()
      const language = url.searchParams.get('language') || undefined
      const tag = url.searchParams.get('tag') || undefined
      return Response.json(filterSnippets(all, language, tag))
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Code Snippets server running at http://localhost:${server.port}`)

