  const q = attempt.questions[attempt.currentQuestion];
  const progress = attempt.currentQuestion / attempt.questions.length;
  const isLast = attempt.currentQuestion === attempt.questions.length - 1;

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, attempt.quizTitle),
    h('p', { style: styles.muted },
      `Question ${attempt.currentQuestion + 1} of ${attempt.questions.length}`,
