export const renderScore = (attempt: QuizAttempt) => {
  const total = attempt.questions.length;
  const correct = attempt.questions.filter(
    (q, i) => attempt.answers[i] === q.correctIndex,
  ).length;
  const pct = Math.round((correct / total) * 100);

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Quiz Results'),
    h('h2', { style: { ...styles.subheading, textAlign: 'center' } }, attempt.quizTitle),
    h('div', { style: styles.scoreCircle }, `${correct}/${total}`),
    h('p', {
      style: { textAlign: 'center', fontSize: '18px', marginBottom: '24px', color: '#555' },
    }, `You scored ${pct}%`),
    h('h3', { style: styles.subheading }, 'Question Breakdown'),
    ...attempt.questions.map((q, i) => {
      const userAnswer = attempt.answers[i];
      const isCorrect = userAnswer === q.correctIndex;
      return h('div', {
        style: {
          ...styles.card,
          borderLeft: `4px solid ${isCorrect ? '#27ae60' : '#c0392b'}`,
        },
      },
        h('p', { style: { fontWeight: '600', margin: '0 0 8px' } },
          `${i + 1}. ${q.text}`,
        ),
