        !isCorrect
          ? h('p', { style: { ...styles.correct, fontSize: '14px', margin: '4px 0' } },
              `Correct answer: ${q.options[q.correctIndex]}`,
            )
          : null,
      );
    }),
    h('div', { style: { marginTop: '20px' } },
      h('a', { href: `/take/${attempt.quizId}`, style: styles.button }, 'Retake Quiz'),
      h('a', { href: '/', style: styles.buttonSecondary }, 'Back to Quizzes'),
