};

import { createSSR } from 'plaited';
import type { Quiz, Question, QuizAttempt } from './types';
import { loadQuizzes, addQuiz, getQuiz, deleteQuiz } from './store';
import {
  renderQuizList,
  renderCreateQuiz,
  renderQuestionFields,
  renderTakeQuestion,
  renderScore,
} from './render';

const ssr = createSSR();

const activeAttempts = new Map<string, QuizAttempt>();

const generateId = (): string =>
  crypto.randomUUID();

const htmlPage = (body: ReturnType<typeof renderQuizList>): string => {
  const content = ssr(body);
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Quiz Builder</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; background: #f5f5f5; }
    a { text-decoration: none; }
  </style>
</head>
<body>${content}</body>
</html>`;
};

const parseFormData = async (req: Request): Promise<Map<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const map = new Map<string, string>();
  for (const [key, value] of params) {
    map.set(key, value);
  }
  return map;
};

const parseQuestions = (form: Map<string, string>): Question[] => {
  const questions: Question[] = [];
  let idx = 0;
  while (form.has(`q_${idx}_text`)) {
    const text = form.get(`q_${idx}_text`) ?? '';
    const options: [string, string, string, string] = [
      form.get(`q_${idx}_opt_0`) ?? '',
      form.get(`q_${idx}_opt_1`) ?? '',
      form.get(`q_${idx}_opt_2`) ?? '',
      form.get(`q_${idx}_opt_3`) ?? '',
    ];
    const correctIndex = parseInt(form.get(`q_${idx}_correct`) ?? '0', 10);
    questions.push({
      id: generateId(),
      text,
      options,
      correctIndex,
    });
    idx++;
  }
  return questions;
};

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;
  const method = req.method;

  // Home — list quizzes
  if (path === '/' && method === 'GET') {
    const quizzes = await loadQuizzes();
    return new Response(htmlPage(renderQuizList(quizzes)), {
      headers: { 'Content-Type': 'text/html' },
    });
  }

  // Create quiz form
  if (path === '/create' && method === 'GET') {
    return new Response(htmlPage(renderCreateQuiz()), {
      headers: { 'Content-Type': 'text/html' },
    });
  }

  // Create quiz submit
  if (path === '/create' && method === 'POST') {
    const form = await parseFormData(req);
    const title = form.get('title')?.trim() ?? '';
    const questions = parseQuestions(form);

    if (!title) {
      return new Response(htmlPage(renderCreateQuiz('Please enter a quiz title.')), {
        headers: { 'Content-Type': 'text/html' },
      });
    }

    if (questions.length === 0) {
      return new Response(htmlPage(renderCreateQuiz('Please add at least one question.')), {
        headers: { 'Content-Type': 'text/html' },
      });
    }

    const quiz: Quiz = {
      id: generateId(),
      title,
      questions,
      createdAt: new Date().toISOString(),
    };

    await addQuiz(quiz);
    return Response.redirect('/', 303);
  }

  // Delete quiz
  const deleteMatch = path.match(/^\/delete\/([a-f0-9-]+)$/);
  if (deleteMatch && method === 'GET') {
    await deleteQuiz(deleteMatch[1]);
    return Response.redirect('/', 303);
  }

  // Start taking a quiz
  const takeMatch = path.match(/^\/take\/([a-f0-9-]+)$/);
  if (takeMatch && method === 'GET') {
    const quiz = await getQuiz(takeMatch[1]);
    if (!quiz) {
      return Response.redirect('/', 303);
    }

    const sessionId = generateId();
    const attempt: QuizAttempt = {
      quizId: quiz.id,
      quizTitle: quiz.title,
      questions: quiz.questions,
      answers: [],
      currentQuestion: 0,
      completed: false,
    };
    activeAttempts.set(sessionId, attempt);

    return new Response(htmlPage(renderTakeQuestion(attempt)), {
      headers: {
        'Content-Type': 'text/html',
        'Set-Cookie': `session=${sessionId}; Path=/; HttpOnly; SameSite=Strict`,
      },
    });
  }

  // Answer a question
  const answerMatch = path.match(/^\/take\/([a-f0-9-]+)\/answer$/);
  if (answerMatch && method === 'POST') {
    const cookies = req.headers.get('Cookie') ?? '';
    const sessionMatch = cookies.match(/session=([a-f0-9-]+)/);
    const sessionId = sessionMatch?.[1] ?? '';
    const attempt = activeAttempts.get(sessionId);

    if (!attempt) {
      return Response.redirect(`/take/${answerMatch[1]}`, 303);
    }

    const form = await parseFormData(req);
    const answer = parseInt(form.get('answer') ?? '-1', 10);

    attempt.answers[attempt.currentQuestion] = answer;

    if (attempt.currentQuestion < attempt.questions.length - 1) {
      attempt.currentQuestion++;
      return new Response(htmlPage(renderTakeQuestion(attempt)), {
        headers: { 'Content-Type': 'text/html' },
      });
    }

    // Quiz complete
    attempt.completed = true;
    const scoreHtml = htmlPage(renderScore(attempt));
    activeAttempts.delete(sessionId);

    return new Response(scoreHtml, {
      headers: { 'Content-Type': 'text/html' },
    });
  }

  // Add question field (for dynamic form — returns HTML fragment)
  if (path === '/add-question' && method === 'GET') {
    const index = parseInt(url.searchParams.get('index') ?? '1', 10);
    const fragment = ssr(renderQuestionFields(index));
    return new Response(fragment, {
      headers: { 'Content-Type': 'text/html' },
    });
  }

  return new Response('Not found', { status: 404 });
};

const server = Bun.serve({
  port: 3000,
  fetch: router,
});

console.log(`Quiz Builder running at http://localhost:${server.port}`);

